REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1, 'El hombre que ha cometido un error y no lo corrige, comete otro error mayor.', 'Confucio (551-479 a. C.); filósofo chino');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (2, 'La contemplación es un lujo, mientras que la acción es una necesidad.', 'Henri Bergson (1859-1941); filósofo francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (3, 'No hay más realidad que la imagen, ni más vida que la conciencia.', 'Azorín (seudónimo de José Martínez Ruiz) (1874-1967); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (4, 'Nadie se ha perdido aún en un camino recto.', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (5, 'La característica de la verdad es que no necesita otra prueba que la verdad.', 'Jeremy Bentham (1748-1832); jurisconsulto y filósofo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (6, 'Poner el remiendo junto al agujero no es buena solución, porque suele ocurrir que\nsi no se había visto el agujero, se ve el remiendo y,a menudo, es el mismo remiendo\nel que hace ver el agujero.', 'Jules Amédé Barbey d\'Aurevilly (1808-1889); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (7, 'Los errores que hay que evitar son aquellos que eliminan la posibilidad de volverlo a intentar.', 'Anónimo');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (8, 'Quizá todo granuja no sea un ladrón, pero desde luego todo ladrón es un granuja.', 'Aristóteles (384-322 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (9, 'Ten compasión del ladrón: quizá el bien que te quita sólo lo use en su daño.', 'José María Vigil (1829-1900); escritor, historiador y político mexicano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (10, 'La libertad y la salud se asemejan: su verdadero valor se conoce cuando nos faltan.', 'Henri Becque (1837-1899); dramaturgo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (11, 'Por la debilidad de la naturaleza humana, los remedios son siempre más lentos que los males.', 'Tácito, Publius Cornelius Tacitus (c.55-115 d. C.);historiador romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (12, 'Los acontecimientos, cuando no se escriben, no se cuentan o no se recuerdan,\nes como si no hubiesen ocurrido.', 'Anónimo');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (13, 'El presente sólo se forma del pasado, y lo que se encuentra en el efecto estaba ya en la causa.', 'Henri Bergson (1859-1941); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (14, 'Quien todo lo ve, todo lo observa.', 'Barón de Montesquieu, (1689-1755); escritor y filósofo francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (15, 'El ver mucho y el leer mucho aviva los ingenios de los hombres.', 'Miguel de Cervantes Saavedra (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (16, 'Nada nos engaña tanto como nuestro propio juicio.', 'Leonardo da Vinci (1452-1519); pintor, escultor e inventor italiano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (17, 'Toda dilación es odiosa, pero suele engendrar prudencia.', 'Siro, Publius (siglo I a. C.); poeta romano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (18, 'Todo mal viene con alas y huye cojeando.', 'Voltaire (nacido François-Marie Arouet) (1694-1778); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (19, 'No anheles impaciente el bien futuro:mira que ni el presente está seguro.', 'Félix María de Samaniego (1745-1801); escritor neoclásico español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (20, 'La ciencia es el misticismo de los hechos;la verdad es que nadie sabe nada.', 'Leonid Nikoláievich Andréiev (1873-1932);escritor ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (21, 'La concisión es el alma del ingenio.', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (22, 'Los que no pueden recordar el pasado están condenados a repetirlo.', 'George Santayana (1863-1952); filósofo estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (23, 'En la prosperidad modérate; en la adversidad resígnate y sé siempre prudente.', 'Periandro de Corinto (siglo VII-VI a.C.);uno de los Siete Sabios de Grecia');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (24, 'La reflexión es el ojo del alma.', 'Jacques Bénigne Bossuet (1627-1704); orador y escritor francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (25, 'Llevadera es la labor cuando muchos comparten la fatiga.', 'Homero (siglo IX a. C.); poeta griego');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (26, 'En los campos de la observación, el azar no favorece sino a los espíritus preparados.', 'Louis Pasteur (1822-1895); químico, biólogo y bacteriólogo francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (27, 'La huella de un sueño no es menos real que la de una pisada.', 'Georges Duby (1914); historiador francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (28, 'La duda es el principio de la sabiduría.\"\nAristóteles (384-322 a. C.); filósofo griego.\n\"La verdad se asienta en un limitado ámbito; el error, empero, es inmenso.', 'Vizconde Bolinebroke, (1678-1751); estadista y escritor inglés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (29, 'Más fácilmente se añade lo que falta que se quita lo que sobra.', 'Francisco de Quevedo y Villegas (1580-1645); escritor español');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (30, 'En el molde de nuestras acciones es donde se ha forjado la inteligencia.', 'Henri Bergson (1859-1941); filósofo francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (31, 'Lo esencial es invisible a los ojos.', 'Antoine de Saint-Éxupery (1900-1944); escritor y aviador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (32, 'Los peligros visibles nos atemorizan menos que los horrores imaginarios.', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (33, 'La verdad que daña es mejor que la mentira que alegra.', 'Máxima árabe');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (34, 'La fortuna vende muy caro lo que parece regalar.', 'Vincent Voiture (1597-1648); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (35, 'Con audacia se puede intentar todo, más no conseguirlo todo.', 'Napoleón I Bonaparte (1769-1821); emperador de Francia.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (36, 'Nada perece en el universo; cuanto en él acontece no pasa de meras transformaciones.', 'Pitágoras (570-500 a. C.); filósofo y matemático griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (37, 'Lo esperado no sucede, es lo inesperado lo que acontece.', 'Eurípides (480-406 a. C.); poeta trágico griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (38, 'La totalidad de la vida es simbólica porque todo en ella tiene significado.', 'Boris Pasternak (1890-1960); escritor ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (39, 'Los conflictos existen siempre; no tratéis de evitarlos sino de entenderlos.', 'Lin Yutang (1895-1976); escritora estadounidense, de origen chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (40, 'Toda dilación es odiosa, pero suele engendrar prudencia.', 'Siro, Publius (siglo I a. C.); poeta romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (41, 'Creer posible algo es hacerlo cierto.', 'Christian Friedrich Hebbel (1813-1863); poeta y autor dramático alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (42, 'Si la prudencia te acompaña, ningún poder celestial te desamparará.', 'Juvenal, Decimus Junius Juvenalis (c.60-130 d. C.); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (43, 'Toda la armonía total de este mundo está formada por discordancias.', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo hispanolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (44, 'Si te sientas en el camino, ponte de frente a lo que aún has de andar y de espaldas a lo ya andado.', 'Proverbio chino');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (45, 'El motivo no existe siempre para ser alcanzado, sino para servir de punto de mira.', 'Joseph Joubert (1754-1824); moralista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (46, 'Las preguntas descubren la amplitud del ingenio, y las respuestas su agudeza.', 'Joseph Joubert (1754-1824); moralista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (47, 'Los esfuerzos individuales nos traerán el progreso general.', 'Cesare Cantú (1804-1895); historiador y político italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (48, 'El que lee mucho y anda mucho, va mucho y sabe mucho.', 'Miguel de Cervantes Saavedra (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (49, 'Si me engañas una vez, tuya es la culpa. Si me engañas dos, la culpa es mía.', 'Anaxágoras (500-428 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (50, 'La evidencia es la más decisiva demostración.', 'Cicerón, (106-43 a. C.); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (51, 'Lo verdadero puede no ser a veces inverosímil.', 'Nicolas Boileau (1636-1711); poeta y crítico francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (52, 'El talento sin ingenio es bien poco. El ingenio sin talento no es nada.', 'Paul Valéry (1871-1945); poeta y escritor francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (53, 'Divide las dificultades que examinas en tantas partes como sea posible para su mejor solución.', 'René Descartes (1596-1650); filósofo y científico francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (54, 'Dichoso aquel que puede conocer la causa de las cosas.', 'Virgilio, Publius Virgilius Maro (70-19 a. C.); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (55, 'El nombre propio es el que marca la individualidad; el apellido, las relaciones sociales.', 'Ángel Ganivet (1865-1898); escritor y diplomático español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (56, 'Hay dos maneras de llegar al desastre: una, pedir lo imposible; otra, retrasar lo inevitable.', 'Francisco Cambó (1876-1947); político español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (57, 'Hay una puerta por la que pueden entrar la buena o la mala fortuna, pero tú tienes la llave.', 'Proverbio japonés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (58, 'Aun cuando todos los expertos coincidan, pueden muy bien estar equivocados.', 'Bertrand Russell (1872-1970); filósofo y matemático inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (59, 'Sabemos lo que somos, pero ignoramos lo que podríamos ser.', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (60, 'Que siempre por señales o razones suelen descubrirse las intenciones.', 'Alonso de Ercilla y Zúñiga (1533-1594); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (61, 'El mejor modo de resolver una dificultad es no tratar de soslayarla.', 'Noel Clarasó (1905-1985); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (62, 'Naces solo y mueres solo, y en el paréntesis la soledad es tan grande que necesitas\ncompartir la vida para olvidarlo.', 'Erich Fromm (1900-1980); sociólogo y psicoanalista estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (63, 'En circunstancias especiales, el hecho debe ser más rápido que el pensamiento.', 'Hernán Cortés (1485-1547); conquistador español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (64, 'Hay gentes que padecen tres clases de tribulación:\nla que tuvieron, la que tienen y la que esperan tener.', 'Orison Swett Marden (1853-1924); escritor y moralista estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (65, 'Lo que importa verdaderamente en la vida no son los objetivos que nos marcamos,\nsino los caminos que seguimos para lograrlos.', 'Peter Bamm (nacido Kurt Emmerich) (1897-1975); novelista alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (66, 'Sírvete de lo aparente como indicio de lo inaparente.', 'Solón (640-558 a. C.); legislador griego');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (67, 'Puedo creer lo imposible, pero no lo improbable.', 'Gilbert Keith Chesterton (1874-1936); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (68, 'Nada existe en el mundo que sea insignificante.', 'Friedrich von Schiller (1759-1805); poeta alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (69, '“Es preciso considerar el pasado con respeto y el presente\ncon desconfianza si se pretende asegurar el porvenir.\"', 'Joseph Joubert (1754-1824); moralista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (70, 'Un hombre aislado se siente débil, y lo es.', 'Concepción Arenal (1820-1893); escritora y socióloga española.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (71, 'El que puede cambiar sus pensamientos puede cambiar su destino.', 'Stephen Crane (1871-1900); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (72, 'Lo que vemos todos los días no nos admira, aunque sepamos por qué sucede.', 'Cicerón, (106-43 a. C.); político y escritor latino');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (73, 'Sed espectadores atentos allí donde no podáis ser actores.', 'José Enrique Rodó (1871-1917); escritor uruguayo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (74, 'Más vale un abrojo de experiencia que toda una selva de advertencias.', 'James Russell Lowell (1819-1891); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (75, 'Los límites de mi lenguaje son los límites de mi mundo.', 'L. Wittgenstein (1889-1951); filósofo británico de origen austríaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (76, 'La ciencia siempre está en falta. Nunca soluciona un problema sin crear otros diez.', 'George Bernard Shaw (1856-1950); dramaturgo irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (77, 'Cualquier cosa debe tomarse seriamente, nada trágicamente.', 'Luis Adolfo Thiers (1797-1877); estadista e historiador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (78, 'Lo que sucede hoy acaeció otras veces; lo que se dice, sigue diciéndose\ny se dirá más adelante; lo que ha de ser, ya fue un día.', 'Antonio Francesco Doni (1513-1574); escritor italiano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (79, 'El mundo ha sido creado para ser recreado.', 'Georges Duhamel (1884-1966); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (80, 'La serena razón huye de todo extremismo y anhela la prudencia moderada.', 'Molière (1622-1673); comediógrafo y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (81, 'El conocer lo que tenemos delante de nosotros,\nen nuestra vida ordinaria, esa es la principal sabiduría.', 'John Milton (1608-1674); poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (82, 'Hay dos clases de debilidad: la que se quiebra y la que se pliega.', 'James Russell Lowell (1819-1891); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (83, 'Sed espectadores atentos allí donde no podáis ser actores.', 'José Enrique Rodó (1871-1917); escritor uruguayo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (84, 'No hay nacimiento ni muerte; no hay sino transformación bajo la ley del progreso.\"\nGottfried Wilhelm Leibniz (1646-1716); filósofo y matemático alemán.\n\"Un sueño sin estrellas es un sueño olvidado.', 'Paul Éluard (nacido Eugène Grindel) (1895-1952); poeta francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (85, 'Lo que ocurre realmente es trivial al lado de lo que pudiera ocurrir.', 'Robert von Musil (1880-1942); escritor austríaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (86, 'El hombre cauto jamás deplora el mal presente;\nemplea el presente en prevenir las aflicciones futuras.', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (87, 'El juicio nos es impuesto por la experiencia.', 'Samuel Johnson (1709-1784); ensayista y lexicógrafo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (88, 'Cuando el peligro parece ligero, deja de ser ligero.', 'Francis Bacon (1561-1626); filósofo y político inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (89, 'Las verdades que revela la ciencia superan siempre a los sueños que destruye.', 'Joseph Ernest Renan (1823-1892); historiador y filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (90, 'Más vale un toma que dos te daré.', 'Miguel de Cervantes Saavedra (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (91, 'Si deseas que tus sueños se hagan realidad, ¡despierta!', 'Ambrose Bierce (1842-1914); escritor y periodista estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (92, 'Vivimos bajo el mismo cielo, pero ninguno tenemos el mismo horizonte.', 'Konrad Adenauer (1876-1967); político alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (93, 'En la vida no hay soluciones, sino fuerzas en marcha.\nEs preciso crearlas, y las soluciones vienen.', 'Antoine de Saint-Éxupery (1900-1944); escritor y aviador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (94, 'La evidencia es la más decisiva demostración.', 'Cicerón, (106-43 a. C.); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (95, 'La ficción es lo característico de la actividad humana. Somos animales\nsimbólicos que hemos inventado un mundo de símbolos.', 'Enrique Anderson Imbert (1910); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (96, 'Toda dificultad eludida se convertirá más tarde en un fantasma que perturbará nuestro reposo.', 'Frédéric Chopin (1810-1849); pianista y compositor polaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (97, 'Entrar en el mundo de la acción es entrar en el mundo de los límites.', 'Gilbert Keith Chesterton (1874-1936); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (98, 'La duda lleva al examen, y el examen a la verdad.', 'Pedro Abelardo (1079-1142); filósofo y teólogo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (99, 'Con suavidad en la forma pero con fortaleza en el fondo.', 'Claudio Acquaviva (1543-1615); jesuita italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (100, 'El comportamiento es un espejo en el que cada uno muestra su imagen.', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (101, 'El precio se olvida, la calidad permanece.', 'Proverbio francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (102, 'Confiamos porque somos precavidos.', 'Epícteto (c.50-c.125 d. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (103, 'No hay mentira más perjudicial que la verdad disfrazada.', 'Manuel Tamayo y Baus (1829-1898); dramaturgo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (104, 'No podemos luchar contra el futuro. El tiempo constituye nuestro límite.', 'William Ewart Gladstone (1809-1898); político inglés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (105, 'La razón es un sol severo: ilumina pero ciega.', 'Romain Rolland (1866-1944); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (106, 'Que no hay tan diestra mentira que no se venga a saber.', 'Félix Lope de Vega Carpio (1562-1635); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (107, 'Sed lentos en resolver y prontos en ejecutar.', 'Isócrates (436-338 a. C.); orador griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (108, 'Más vale un consejo que diez avisos, pero más vale una ayuda que diez consejos.', 'Louis Bottach (siglo XIX); novelista y ensayista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (109, '“El ser se ha hecho hoy menos importante que el parecer.\"', 'Georges Duhamel (1884-1966); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (110, 'Quien tiene la voluntad tiene la fuerza.', 'Menandro (c.340-292 a. C.); comediógrafo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (111, 'No podemos matar el tiempo sin herir la eternidad.', 'Henry D. Thoreau (1817-1862); escritor y pensador estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (112, 'Muchas cosas se reputan imposibles antes de haberse realizado.', 'Plinio el Viejo, (c.23-79 d. C.); escritor latino');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (113, 'Estableced el orden: el hábito se encargará de mantenerlo.', 'Duque de Levis (1755-1830); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (114, 'El hombre bien preparado para la lucha ya ha conseguido medio triunfo.', 'Miguel de Cervantes Saavedra (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (115, 'El principio de un gran árbol es una semilla.', 'Abul Fadl Ahmed Ibn Mohamed al-Meidani (?-1124); historiador árabe');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (116, 'La resignación es un suicidio cotidiano.', 'Honoré de Balzac (1799-1850); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (117, 'El éxito tiene muchos padres, pero el fracaso es huérfano.', 'John Fitzgerald Kennedy (1917-1963); político estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (118, 'Se ha sembrado la palabra mañana, pero no ha brotado todavía.', 'Anónimo');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (119, 'La vida es una serie de sorpresas.', 'Ralph Waldo Emerson (1803-1882); poeta y ensayista estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (120, 'No hay un solo error que no haya tenido sus seguidores.', 'John Locke (1632-1704); filósofo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (121, '“Porque tienen de su parte mucho poder las mentiras cuando parecen verdades.\"', 'Pedro Calderón de la Barca (1600-1681); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (122, 'El arte de escribir consiste en el arte de interesar.', 'Jacques Delille (1738-1813); poeta francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (123, 'Lo inevitable rara vez sucede, es lo inesperado lo que suele ocurrir.', 'John Maynard Keynes (1883-1946); economista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (124, '¿Qué puede haber imprevisto para el que nada ha previsto?', 'Paul Valéry (1871-1945); poeta y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (125, 'Los recuerdos son cuernos de caza cuyo sonido muere en el viento.', 'Guillaume Apollinaire (1880-1918); poeta y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (126, 'O sabes que nada sabes, o lo ignoras. Si lo ignoras, no puedes afirmarlo. Si lo sabes, algo sabes.', 'Cicerón, (106-43 a. C.); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (127, 'No es cierto que todo sea incierto.', 'Blas Pascal (1623-1662); científico, filósofo y escritor francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (128, 'Los vientos y las olas están siempre a favor del navegante más capacitado.', 'Edward Gibbon (1737-1794); historiador inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (129, 'Primero observa, argumenta después.', 'Jean Henri Casimir Fabre (1823-1915); entomólogo francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (130, 'Muchos hay que no conocen su debilidad, pero otros tantos hay que no conocen su fuerza.', 'Jonathan Swift (1667-1745); escritor irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (131, 'Mira dos veces para ver lo exacto; mira una sola vez para ver lo hermoso.', 'Henri Frédéric Amiel (1821-1881); escritor y profesor suizo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (132, 'El árbol no niega su sombra ni al leñador.', 'Proverbio hindú');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (133, 'No pasa de ser un pobre ratón el que solamente conoce un agujero para escapar.', 'Georg Rollenhagen (1542-1609); escritor alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (134, 'No basta con adquirir sabiduría, además es preciso saber usarla.', 'Cicerón (106-43 a. C.); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (135, 'La ciencia es como la tierra: sólo puede poseerse una pequeña parte.', 'Isaac Newton (1642-1727); matemático, físico y filósofo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (136, 'Para el hombre prudente es más fácil prevenir que remediar.', 'Baltasar Gracián (1601-1658); jesuita y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (137, 'El hombre cauto jamás deplora el mal presente;\nemplea el presente en prevenir las aflicciones futuras.', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (138, 'La maldad no necesita razones, le basta con un pretexto.', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (139, 'El rostro es el espejo del alma, y los ojos, sus delatores.', 'Cicerón; político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (140, 'El ingenio quizás es al talento lo que el instinto a la razón.', 'Jules Renard (1864-1910); escritor y dramaturgo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (141, 'La ciencia que se aparta de la justicia, más que ciencia debe llamarse astucia.', 'Cicerón,(106-43 a. C.); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (142, 'El escritor original no es aquel que no imita a nadie, sino aquel a quien nadie puede imitar.', 'Vizconde de Chateaubriand, (1768-1848); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (143, 'La verdad se robustece con la investigación y la dilación;\nla falsedad, con el apresuramiento y la incertidumbre.', 'Tácito,(c.55-115 d. C.); historiador romano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (144, 'El saber es la parte principal de la felicidad.', 'Sócrates (470-399 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (145, '\"Ninguna cuestión queda nunca concluida', 'hasta que se concluye bien.\"');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (146, 'El exceso es el veneno de la razón.', 'Francisco de Quevedo y Villegas (1580-1645); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (147, 'La memoria parece grande por lo que muestra en recuerdos;\nlo es mucho más por lo que ciertamente esconde.', 'Niceto Alcalá Zamora (1877-1949); abogado y político español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (148, 'Todo mal viene con alas y huye cojeando.', 'Voltaire (1694-1778); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (149, 'De pequeños principios resultan grandes fines.', 'Alejandro Magno (356-326 a. C.); rey de Macedonia');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (150, 'El motivo no existe siempre para ser alcanzado, sino para servir de punto de mira.', 'Joseph Joubert (1754-1824); moralista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (151, 'Si bien buscas, encontrarás.', 'Platón (c.428-c.347 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (152, 'No basta con adquirir sabiduría, además es preciso saber usarla.', 'Cicerón, (106-43 a. C.); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (153, 'Son los ojos testigos mucho más exactos que los oídos.', 'Heráclito (c.544-480 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (154, 'No hay sabiduría sin prudencia.', 'Jaime Balmes (1810-1848); sacerdote y filósofo español');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (155, 'Sólo aquellos que nada esperan del azar son dueños del destino.', 'Matthew Arnold (1822-1888); escritor y poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (156, 'Lo que ocurre realmente es trivial al lado de lo que pudiera ocurrir.', 'Robert von Musil (1880-1942); escritor austríaco');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (157, 'El carácter es la mitad del destino.', 'R. Guerin de la Grasserie (1839-1915);filósofo y jurisconsulto francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (158, 'Nuestra prudencia está sujeta a la fortuna, como nuestros bienes.', 'Duque de la Rochefoucauld, (1613-1680); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (159, 'La evolución no es una fuerza, sino un progreso;  no una causa sino una ley.', 'Vizconde de Blackburn, John Morley (1838-1923); estadista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (160, 'Lo importante se halla en la mirada, no en la cosa mirada.', 'André Gide (1869-1951); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (161, 'Cada vida ha de tener sus espacios huecos que el ideal ha de rellenar.', 'Julia Ward Howe (1819-1910); escritora estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (162, 'Con el cebo de una mentira se pesca una carpa de verdad.', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (163, 'La incomprensión, más que la imposibilidad de comprender, es la imposibilidad de sentir.', 'José Narosky (siglo XX); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (164, 'Una gran parte de los hombres obra sin pensar. La otra piensa sin obrar.', 'Ugo Foscolo (1778-1827); escritor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (165, 'Todas las cosas son imposibles, mientras lo parecen.', 'Concepción Arenal (1820-1893); escritora y socióloga española.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (166, 'Saber para prever, a fin de poder.', 'Auguste Comte (1798-1857); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (167, 'Plantearse los menos problemas posibles es la única manera de resolverlos.', 'Jean Cocteau (1889-1963); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (168, 'El asunto es el problema; la forma, la solución.', 'Christian F. Hebbel (1813-1863); poeta y autor dramático alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (169, 'En la circunferencia, el comienzo y el fin coinciden.', 'Heráclito (c.544-480 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (170, 'Siempre y nunca, es tan largo el uno como el otro.', 'Elsa Triolet (1896-1970); escritora francesa, de origen ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (171, 'Todo fluye, nada permanece.', 'Heráclito (c.544-480 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (172, 'Fray ejemplo es el mejor predicador.', 'Francisco Jiménez Cisneros (1436-1517); prelado y político español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (173, 'El requisito del éxito es la prontitud en las decisiones.', 'Francis Bacon (1561-1626); filósofo y político inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (174, 'El conocimiento es sólo una de las representaciones de la existencia.', 'José Vasconcelos (1882-1959); político y filósofo mexicano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (175, 'El verdadero progreso consiste en renovarse.', 'Alejandro Vinet (1797-1847); literato y teólogo protestante suizo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (176, 'Una acción es la perfección y la publicación del pensamiento.', 'Ralph Waldo Emerson (1803-1882); poeta y ensayista estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (177, 'La grandeza de un hombre consiste en saber reconocer su propia pequeñez.', 'Blas Pascal (1623-1662); científico, filósofo y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (178, 'El espíritu humano avanza de continuo, pero siempre en espiral.', 'Johann W. von Goethe (1749-1832); poeta, dramaturgo y polígrafo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (179, 'No se graban tanto mil palabras como un solo hecho.', 'Henrik Ibsen (1828-1906); dramaturgo noruego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (180, '¡Estudia! No para saber una cosa más, sino para saberla mejor.', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo hispanolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (181, '\"La historia es el progreso de la conciencia de la libertad\".', 'Georg Wilhelm Friedrich Hegel (1770-1831); filósofo alemán');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (182, '\"Mira dos veces para ver lo exacto; mira una sola vez para ver lo hermoso\".', 'Henri Frédéric Amiel (1821-1881); escritor y profesor suizo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (183, '\"Se debe hacer todo tan sencillo como sea posible, pero no más sencillo\".', 'Albert Einstein (1879-1955); físico y matemático.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (184, '\"Muchos hay que no conocen su debilidad, pero otros tantos hay que no conocen su fuerza\".', 'Jonathan Swift (1667-1745); escritor irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (185, '\"Quien pretenda una felicidad y sabiduría constantes, deberá acomodarse a frecuentes cambios\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (186, '\"Por los defectos de los demás, el sabio corrige los propios\".', 'Publius Siro (siglo I a. C.); poeta romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (187, '\"Lo más seguro es no ponerse en peligro\".', 'Francisco de Quevedo y Villegas (1580-1645); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (188, '\"Jamás se desvía uno tan lejos como cuando cree conocer el camino\".', 'Proverbio chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (189, '\"Un experto es un hombre que ha dejado de pensar: sabe\".', 'Frank Lloyd Wright (1867-1959); arquitecto estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (190, '\"El valor hace vencedores; la concordia hace invencibles\".', 'Casimir Jean François Delavigne (1793-1843); poeta francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (191, '\"El que duda, piensa\".', 'Carlo Dossi (1849-1910); novelista italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (192, '\"Donde esté el riesgo, allí también se ponga el lucro\".', 'Justiniano I (482-565); emperador bizantino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (193, '\"Todos los problemas tienen solución; el problema está en dar con ella\".', 'Noel Clarasó (1905-1985); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (194, '\"El verdadero progreso consiste en renovarse\".', 'Alejandro Vinet (1797-1847); literato suizo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (195, '\"En las adversidades sale a la luz la virtud\".', 'Aristóteles (384-322 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (196, '\"No me digas que el problema es difícil. Si no lo fuera, no sería un problema\".', 'Ferdinand Foch (1851-1929); mariscal francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (197, '\"La habilidad y la constancia son las armas de la debilidad\".', 'Nicolás Maquiavelo (1469-1527); político italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (198, '\"En los ojos está el espíritu, el alma y el cuerpo\".', 'George Herbert (1593-1633); poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (199, '\"Gracias al ingenio nos divertimos, mas sólo gracias al corazón no nos aburrimos\".', 'Madame de Swetchine (1782-1857); escritora francesa de origen ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (200, '\"La gran meta de la educación no es el conocimiento, sino la acción\".', 'Herbert Spencer (1820-1903); filósofo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (201, '\"Perdemos lo seguro por buscar lo incierto\".', 'Plauto, Maccius Plautus (c.254-184 a. C.); comediógrafo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (202, '\"El libro de la naturaleza alcanza cada año una nueva tirada\".', 'Hans Christian Andersen (1805-1875); escritor danés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (203, '¿Qué puede haber imprevisto para el que nada ha previsto?', 'Paul Valéry (1871-1945); poeta y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (204, '\"El hacer una cosa por otra es lo mismo que mentir\".', 'Miguel de Cervantes Saavedra (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (205, '\"Los ejemplos corrigen mejor que las reprimendas\".', 'Voltaire (1694-1778); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (206, '\"No son los ojos los que ven, sino que nosotros vemos por medio de los ojos\".', 'Platón (c.428-c.347 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (207, '\"Quien se contenta con nada lo posee todo\".', 'Nicolás Boileau (1636-1711); poeta y crítico francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (208, '\"El único hombre que puede cambiar de opinión es aquel que tiene una\".', 'Harún al-Rashid (766-809); califa abasí.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (209, '\"La peor decisión es la indecisión\".', 'Benjamin Franklin (1706-1790); físico y político estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (210, '\"Prueba es de mejoramiento conocer los defectos que antes no conocíamos\".', 'Séneca (c.5 a. C.-65 d. C.); filósofo hispanolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (211, '\"Los votos deberían pesarse, no contarse\".', 'Friedrich von Schiller (1759-1805); poeta alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (212, '\"La barca pasa, pero el río queda\".', 'Proverbio malayo');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (213, '\"La fe no es creer lo que no vimos, sino creer lo que no vemos\".', 'Miguel de Unamuno (1864-1936); escritor y filósofo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (214, '\"Hay cosas que no tienen remedio, y son las menos\".', 'Mariano José de Larra (1809-1837); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (215, '\"La unidad es la variedad, y la variedad en la unidad es la ley suprema del universo\".', 'Isaac Newton (1642-1727); matemático, físico y astrónomo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (216, '\"La leyenda corrige la historia\".\nTeixeira de Pascoaes (1879-1952); poeta portugués.\n\"El pensamiento es valioso en la medida de su fecundidad\".', 'Edward George Bulwer-Lytton (1803-1873); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (217, '\"Si al pleno acierto aspiras, une la utilidad con el deleite\".', 'Tomás de Iriarte (1750-1791); escritor neoclásico español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (218, '\"Sólo hay una avaricia honrosa: la de las palabras\".', 'Constancio Vigil (1876-1954); escritor y periodista venezolano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (219, '\"La sabiduría consiste no sólo en ver lo que tienes ante ti, sino en prever lo que va a venir\".', 'Terencio (195-159 a. C.); comediógrafo latino, de origen africano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (220, '\"Una cosa sobre todo hace sugestivo el pensamiento humano: la inquietud\".', 'Anatole France (1844-1924); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (221, '\"La audacia sin juicio es peligrosa, y el juicio sin audacia, inútil\".', 'Gustave Le Bon (1841-1931); etnólogo, sociólogo y psicólogo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (222, '\"Nadie guarda mejor un secreto que el que lo ignora\".', 'George Farquhar (1678-1707); dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (223, '\"La preocupación germina en la cuna de la ignorante pereza\".', 'Pitágoras (570-500 a. C.); filósofo y matemático griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (224, '\"Nunca es poco lo que es bastante; nunca es bastante lo que es mucho\".', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo hispanolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (225, '\"El que se aprovecha de un delito es culpable de él\".', 'Proverbio francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (226, '\"Que un perro muerda a un hombre no es noticia; que un hombre muerda a un perro sí lo es\".', 'Charles Dana (1819-1897); periodista estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (227, '\"Oír o leer sin reflexionar es una ocupación inútil\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (228, '\"El accidente es sólo orden imprevisto\".', 'Novalis (1772-1801), poeta y novelista alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (229, '\"La vida es una especie de juego de azar donde todo el mundo piensa\nque el de al lado sabe qué está pasando\".', 'Solomon, Barbara P. (n. 1929); escritora estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (230, '\"Ninguna nación fue nunca arruinada jamás por el comercio\".', 'Franklin, Benjamin (1706-1790); estadista y científico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (231, '\"La evidencia es la más decisiva demostración\".', 'Cicerón, (106-43 a.C.); político y filósofo romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (232, '\"En la tardanza está el peligro\".', 'Livio, Tito (59 a.c.-17 d.c.); historiador romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (233, '\"El que habla siembra; el que escucha recoge\".', 'Anónimo');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (234, '\"A grandes males, grandes remedios\".', 'Hipócrates (c.460-377 a. C.); médico griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (235, '\"Los enemigos declarados no son los más peligrosos\".', 'Duchesne, Louis (1843-1922); sacerdote francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (236, '\"El que tiene paciencia tendrá lo que quiera\".', 'Franklin, Benjamin (1706-1790); científico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (237, '\"Es más difícil hacer durar la admiración que provocarla\".', 'Dubay, Sanial (1754-1817); escritor francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (238, '\"Mejor es prevenir que curar\".', 'Erasmo de Rotterdam, Desiderio (1466-1536); humanista holandés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (239, '\"La ciencia es la clasificación sistemática de la experiencia\".', 'Lewes, George H. (1817-1878); filósofo y actor inglés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (240, '\"El destino tiene dos maneras de herirnos: negándose a cumplir nuestros deseos y cumpliéndolos\".', 'Amiel, Henri-Frédéric (1821-1881); filósofo suizo');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (241, '\"Cuando se puede evitar un mal es necedad aceptarlo\".', 'Terencio Afer, Publio (195-159 a. C.); autor cómico latino');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (242, '\"Ciencia sin conciencia no es más que ruina del alma\".', 'Rabelais, François (1945 -1553); escritor francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (243, '\"La muerte es el comienzo de la inmortalidad\".', 'Robespierre, Maximilien (1758-1794); revolucionario francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (244, '\"Los hombres sabios discuten los problemas, y los necios los deciden\".', 'Anacarsis (s. VI-V a. C); filósofo escita');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (245, '\"Sólo sé que no sé nada\".', 'Sócrates (470 - 400 a. C.); filósofo griego');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (246, '\"El saber es la única propiedad que no puede perderse\".', 'Bías de Pirene (s. VI a. C,); uno de los Siete Sabios de Grecia');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (247, '\"El silencio es el único amigo que jamás traiciona\".', 'Confucio (551 - 479 a. C.); estadista y filósofo chino');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (248, '\"Fiarse de todo el mundo y no fiarse de nadie son dos vicios:\npero en el uno se encuentra más virtud, y en el otro más seguridad\".', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo hispanolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (249, '\"Quien piensa poco, yerra mucho\".', 'Leonardo da Vinci (1452-1519); pintor, escultor e inventor italiano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (250, '\"La razón no es otra cosa que el análisis de lo que se cree\".', 'Franz Schubert (1797-1828); compositor austríaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (251, '\"El tiempo es la materia de la que he sido creado\".', 'Borges, Jorge Luis (1899-1987); poeta, ensayista y narrador argentino');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (252, '\"La ciencia es orgullosa por lo mucho que ha aprendido;\nla sabiduría es humilde porque no sabe más\".', 'Cowper, William (1731-1800); poeta inglés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (253, '\"Añorar el pasado es correr tras el viento\".', 'Proverbio ruso');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (254, '\"Desear lo mejor, recelar lo peor y tomar lo que viniere\".', 'Delacroix, Eugenè (1798-1863); pintor y grabador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (255, '\"Nunca me enfado por lo que la gente me pide, sino por lo que me niega\".', 'Cánovas del Castillo, Antonio (1828-1897); político y escritor español');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (256, '\"El comercio es casi un arte; es la forma inferior, el primer grado del arte\".', 'Brunetière, Ferdinand V.(1849-1906); crítico francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (257, '\"En la práctica, sólo es problema lo que la inteligencia puede resolver\".', 'Keyerling, Hermann (1880-1946); filósofo alemán');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (258, '\"La ciencia avanza a pasos, no a saltos\".', 'Thomas Macaulay (1800-1859); historiador y político británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (259, '\"El Arte es una mentira que nos acerca a la verdad\".', 'Pablo Picasso (1881-1973); pintor, grabador, escultor y muralista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (260, '\"La lectura no da sabiduría al hombre; le da únicamente conocimiento\".', 'William Somerset Maugham (1874-1965); escritor inglés, nacido en Francia.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (261, '\"La insignificancia es siempre una garantía de seguridad\".', 'Esopo (siglo VI a. C.); fabulista griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (262, '\"La confidencia corrompe la amistad; el mucho contacto la consume; el respeto la conserva\".', 'Cicerón, (106-43 a.C.); político y filósofo romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (263, '\"Donde una puerta se cierra, otra se abre\".', 'Miguel de Cervantes Saavedra (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (264, '\"La ventaja se la lleva aquel que aprovecha el momento oportuno\".', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (265, '\"La originalidad es la vuelta a los orígenes\".', 'Gaudí i Cornet, Antonio (1852-1926), arquitecto español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (266, '\"El destino se ríe de las probabilidades\".', 'Bulwer-Lytton, Edw. George (1803-1873); escritor inglés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (267, '\"El mundo ha sido creado para ser recreado\".', 'Georges Duhamel (1884-1966); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (268, '\"Nuestro conocimiento es necesariamente finito,\nmientras que nuestra ignorancia es necesariamente infinita\".', 'Sir Karl Raimund Popper (1902-1994); filósofo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (269, '\"Lo que está fuera de tu vista pronto estará fuera de tu memoria\".', 'Kempen, Tomás de (1397-1471); monje agustino alemán');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (270, '\"La memoria es el deseo satisfecho\".', 'Fuentes, Carlos (n. 1929); periodista y escritor mexicano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (271, '\"Nada resiste tanto como lo provisional\".', 'Maurois, André (1885.1967); escritor francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (272, '\"La ignorancia es madre del miedo\".', 'Kames, Henry Home (1696-1782); juez y escritor francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (273, '\"Los grandes conocimientos engendran las grandes dudas\".', 'Aristóteles (384-322 a.c.); filósofo griego');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (274, '\"Es menos malo agitarse en la duda que reposar en el error\".', 'Manzoni, Alessandro (1785-1873); escritor italiano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (275, '\"Del escuchar procede la sabiduría, y del hablar el arrepentimiento\".', 'Proverbio italiano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (276, '\"La vida es como un arca inmensa llena de posibilidades\".', 'Nervo, Amado (1870-1919); poeta y diplomático mexicano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (277, '\"La historia es un incesante volver a empezar\".', 'Tucídides (460-396 a. C.), historiador ateniense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (278, '\"El sigilo frente a la luz nació con los hombres\".', 'Santonja, Gonzalo (1955), poeta español');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (279, '\"La diplomacia te saca de un problema  en el que el tacto te hubiera evitado meterte\".', 'Bowling, Brian; humanista estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (280, '\"Una vida entera no es lo bastante larga para explicarnos qué ocurre en nuestro entorno\".', 'Larson, Dong; periodista estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (281, '\"El cambio es la única cosa en el universo que no cambia\".', 'Wilhem, Helmuth; científico alemán');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (282, '\"Si no te ha sorprendido nada extraño durante el día, es que no ha habido día\".', 'Archibald, John; físico estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (283, '\"La vida es un arco iris que incluye el negro\".', 'Yevtushenko, Yevgeny; poeta ruso');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (284, '\"Lo que se considera ceguera del destino es en realidad propia miopía\".', 'Faulkner, William (1897-1962), escritor estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (285, '\"En el estudio no existe la saciedad\".', 'Erasmo de Rotterdam (1466-1536); humanista holandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (286, '\"Saber mucho da ocasión de dudar más\".', 'Michel Eyquem de Montaigne (1533-1592); pensador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (287, '\"El dinero es la tarjeta de crédito de los pobres\".', 'Herbert Marshall McLuhan (1911-1980); sociólogo canadiense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (288, '\"No existe una mejor prueba del progreso de una civilización\nque la del progreso de la cooperación\".', 'John Stuart Mill (1806-1873); filósofo y economista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (289, '\"No veo lógico rechazar datos porque parezcan increíbles\".', 'Fred Hoyle (1915); astrónomo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (290, '\"El genio convierte la excepción en regla\".', 'Eugeni Trias (1942); filósofo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (291, '\"Los hechos no dejan de existir porque se los ignore\".', 'Aldous Huxley (1894-1963); escritor y ensayista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (292, '\"Ninguna prueba, ninguna rectificación ni desmentido\npuede anular el efecto de una publicidad bien hecha\".', 'H. Alexander von Keyserling (1880-1946); filósofo y científico alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (293, '\"El poder conseguido por medios culpables', 'nunca se ejercitó en buenos propósitos\".');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (294, '\"La medida más segura de toda fuerza es la resistencia que vence\".', 'Stefan Zweig (1881-1942); escritor austríaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (295, '\"Una cosa sobre todo hace sugestivo el pensamiento humano: es la inquietud\".', 'Anatole France (1844-1924); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (296, '\"A gran necesidad, gran diligencia\".', 'Ramón Llull o Raimundo Lulio (1235-1315); filósofo y teólogo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (297, '\"Si me mezclo en la vida, exagero su importancia;\ny si me alejo de ella, exagero su insignificancia\".', 'Jean Lucien Arréat (1841-1922); escritor y filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (298, '\"Cree a aquellos que buscan la verdad; duda de los que la han encontrado\".', 'André Gide (1869-1951); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (299, '\"La sabiduría es un adorno en la prosperidad y un refugio en la adversidad\".', 'Aristóteles (384-322 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (300, '\"El hombre se descubre cuando se mide con un obstáculo\".', 'Antoine de Saint-Éxupery (1900-1944); escritor y aviador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (301, '\"Humano es errar; pero sólo los estúpidos perseveran en el error\".', 'Cicerón, (106-43 a. C.); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (302, '\"El que no sabe por qué camino llegará al mar, debe buscar el río por compañero\".', 'John Ray (1627-1705); naturalista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (303, '\"El único deber que tenemos con la historia es reescribirla\".', 'Óscar Fingal O\'Flahertie Wills Wilde (1854-1900); escritor irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (304, '\"El carácter es la mitad del destino\".', 'Raoult Guerin de la Grasserie (1839-1915); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (305, '\"El sigilo frente a la luz nació con los hombres\".', 'Gonzalo Santonja (1955); poeta español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (306, '\"Para prevenidos no hay acasos\".', 'Baltasar Gracián (1601-1658); jesuita y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (307, '\"Los mundos nuevos deben ser vividos antes de ser explicados\".', 'Alejo Carpentier (1904-1980); escritor cubano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (308, '\"El mundo no ha cambiado por la política, sino por la técnica\".', 'Friedrich Dürrenmatt (1921); escritor y dramaturgo suizo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (309, '\"¿No es extraño? Los mismos que se ríen de los adivinos se toman en serio a los economistas\".', 'Anónimo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (310, '\"La nostalgia ya no es lo que era\".', 'Peter De Vries, escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (311, '\"Los problemas son oportunidades para demostrar lo que se sabe\".', 'Duke Ellington (1899-1974); compositor y músico de jazz estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (312, '\"Una cabeza sin memoria es como una fortaleza sin guarnición\".', 'Napoleón I Bonaparte (1769-1821); emperador de Francia.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (313, '\"La memoria es el único paraíso del que no podemos ser expulsados\".', 'Jean-Paul Richter (nacido Johann Paul Richter) (1763-1825); poeta alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (314, '\"El futuro está oculto detrás de los hombres que lo hacen\".', 'Anatole France (1844-1924); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (315, '\"La capacidad de atención del hombre es limitada\ny debe ser constantemente espoleada por la provocación\".', 'Albert Camus (1913-1960); escritor francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (316, '\"Lo más incomprensible del mundo es que sea comprensible\".', 'Albert Einstein (1879-1955); físico y matemático.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (317, '\"La independencia siempre fue mi deseo;\nla dependencia siempre fue mi destino\".', 'Paul Verlaine (1844-1895); poeta francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (318, '\"Cuatro cosas no pueden ser escondidas durante largo tiempo:\nla ciencia, la estupidez, la riqueza y la pobreza\".', 'Averroes (1126-1198); filósofo y médico hispanoárabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (319, '\"La novedad es madre de la temeridad, hermana de la superstición e hija de la ligereza\".', 'S. Bernardo de Claraval (1091-1153);primer abad del monasterio de Claraval');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (320, '\"Lo oscuro acabamos viéndolo; lo completamente claro lleva más tiempo\".', 'Edward Roscoe Murrow (1908-1965); comentarista y reportero estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (321, '\"Las cosas no valen sino lo que se las hace valer\".', 'Molière (1622-1673); comediógrafo y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (322, '\"Absurdo sería pedir al cálculo lo que puede dar la abnegación\".', 'Concepción Arenal (1820-1893); escritora y socióloga española.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (323, '\"No sabe más el que más cosas sabe, sino el que sabe las que más importan\".', 'Bernardino Rebolledo (1597-1676); militar, poeta y diplomático español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (324, '\"Probamos por medio de la lógica, pero descubrimos por medio de la intuición\".', 'Henri Poincaré (1854-1912); matemático francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (325, '\"Del origen primero del mundo derívase una cadena de causas\".', 'André Maurois (nacido Émile Herzog) (1885-1967); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (326, '\"La reflexión calmada y tranquila desenreda todos los nudos\".', 'Harold MacMillan (1894-1986); político inglés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (327, '\"La razón es un sol severo: ilumina pero ciega\".', 'Romain Rolland (1866-1944); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (328, '\"Que siempre por señales o razones se suelen descubrir las intenciones\".', 'Alonso de Ercilla y Zúñiga (1533-1594); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (329, '\"Quien volviendo a hacer el camino viejo aprende el nuevo,\npuede considerarse un maestro\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (330, '\"El tiempo de la reflexión es una economía de tiempo\".', 'Siro, Publius (siglo I a. C.); poeta romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (331, '\"Nada es real hasta que se experimenta;\naun un proverbio no lo es hasta que la vida no lo haya ilustrado\".', 'John Keats (1795-1821); poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (332, '\"La claridad es el barniz de los maestros\".', 'Luc de Clapiers (1715-1747); moralista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (333, '\"Debe desear todo hombre vivir para saber, y saber para bien vivir\".', 'Mateo Alemán (1547-c.1614); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (334, '\"Una vez descartado lo imposible, lo que queda,\npor improbable que parezca, debe ser la verdad\".', 'Sir Arthur Conan Doyle (1859-1930); novelista escocés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (335, '\"El mundo es una comedia para los que piensan y una tragedia para los que sienten\".', 'Sir Hugh Seymour Walpole (1884-1941); novelista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (336, '\"La juventud es el momento de estudiar la sabiduría; la vejez, el de practicarla\".', 'Jean Jacques Rousseau (1712-1778); escritor y filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (337, '\"Repetir es persuadir con más detalle\".', 'Duque de Levis (1755-1830); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (338, '\"La imprudencia suele preceder a la calamidad\".', 'Apiano (siglo II d. C.); historiador griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (339, '\"El pasado me ha revelado la estructura del futuro\".', 'Pierre Teilhard de Chardin (1881-1955); filósofo y teólogo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (340, '\"Lo que no se parece a nada no existe\".', 'Paul Valéry (1871-1945); poeta y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (341, '\"Ni aún permaneciendo sentado junto al fuego de su hogar\npuede el hombre escapar a la sentencia de su destino\".', 'Esquilo (c.525-456 a. C.); poeta trágico griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (342, '\"Lo esperado no sucede, es lo inesperado lo que acontece\".', 'Eurípides (480-406 a. C.); poeta trágico griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (343, '\"El primer favor denegado anula todos los anteriores\".', 'Plinio el Viejo, Caius Plinius Secundus (c.23-79 d. C.); escritor latino');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (344, '\"Es preciso considerar el pasado con respeto\ny el presente con desconfianza si se pretende asegurar el porvenir\".', 'Joseph Joubert (1754-1824); moralista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (345, '\"El hombre tiene mil planes para sí mismo.\nEl azar, sólo uno para cada uno\".', 'Mencio o Meng Zi (372-289 a. C.); filósofo chino confuciano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (346, '\"Sólo hay una máxima absoluta y es que no hay nada absoluto\".', 'Auguste Comte (1798-1857); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (347, '\"El corazón tiene razones que la razón ignora\".', 'Blas Pascal (1623-1662); científico, filósofo y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (348, '\"El movimiento veloz que agita el mundo no se oye sino andando\".', 'Félicité de Lamennais (1782-1854); escritor religioso francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (349, '\"El mundo es la suma total de nuestras posibilidades vitales\".', 'José Ortega y Gasset (1883-1955); filósofo y ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (350, '\"En un minuto hay muchos días\".', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (351, '\"Mi memoria es magnífica para olvidar\".', 'Robert Louis Stevenson (1850-1894); novelista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (352, '\"Volver la vista atrás es una cosa y marchar atrás, otra\".', 'Charles Caleb Colton (1780-1832); poeta y ensayista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (353, '\"La historia es la novela de los hechos,\ny la novela es la historia de los sentimientos\".', 'Claude Adrien Helvétius (1715-1771); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (354, '\"Nada parece tan verdadero que no pueda parecer falso\".', 'Michel Eyquem de Montaigne (1533-1592); pensador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (355, '\"Repara tu trineo en el verano, y tu carreta en el invierno\".', 'Proverbio armenio');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (356, '\"El azar sólo favorece a quien sabe cortejarlo\".', 'Charles Nicolle (1866-1936); médico y bacteriólogo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (357, '\"Los que saben mucho se admiran de pocas cosas,\ny los que no saben nada se admiran de todo\".', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo hispanolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (358, '\"Las ideas se encienden unas con otras como las chispas eléctricas\".', 'Johann Jakob Engel (1741-1802); escritor alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (359, '\"Lo importante no es escuchar lo que se dice,\nsino averiguar lo que se piensa\".', 'Juan Donoso Cortés (1809-1853); ensayista y diplomático español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (360, '\"La concordia hace crecer las pequeñas cosas,\nla discordia arruina las grandes\".', 'Salustio, Caius Sallustius Crispus (85-35 a. C.); historiador latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (361, '\"No menos que el saber me place el dudar\".', 'Dante Alighieri (1265-1321); poeta italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (362, '\"La ciencia es orgullosa por lo mucho que ha aprendido;\nla sabiduría es humilde porque no sabe más\".', 'William Cowper (1731-1800); poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (363, '\"Nada es más nocivo para la creatividad que el furor de la inspiración\".', 'Umberto Eco (1932); escritor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (364, '\"En dos palabras puedo resumir cuanto he aprendido\nacerca de la vida: Sigue adelante\".', 'Robert Lee Frost (1875-1963); poeta estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (365, '\"Es tan difícil verse a uno mismo como mirar para atrás sin volverse\".', 'Henry David Thoreau (1817-1862); escritor y pensador estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (366, '\"Recuerdo incluso lo que no quiero. Olvidar no puedo lo que quiero\".', 'Cicerón, (106-43 a. C.); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (367, '\"Presta solamente aquello cuya pérdida puedas soportar\".', 'George Herbert (1593-1633); poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (368, '\"Aprender sin reflexionar es malgastar la energía\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (369, '\"El ignorante afirma, el sabio duda y reflexiona\".', 'Aristóteles (384-322 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (370, '\"De todas las formas de engañar a los demás,\nla pose de seriedad es la que hace más estragos\".', 'Santiago Rusiñol (1861-1931); pintor y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (371, '\"Oír es precioso para el que escucha\".', 'Proverbio egipcio');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (372, '\"La astucia puede tener vestidos, pero a la verdad le gusta ir desnuda\".', 'Thomas Fuller (1609-1661); clérigo y escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (373, '\"Hay palabras que suben como el humo, y otras que caen como la lluvia\".', 'Marquesa de Sévigné,(1626-1696); escritora francesa.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (374, '\"El saber es la única propiedad que no puede perderse\".', 'Bías de Priene (siglo VI a. C.); uno de los siete sabios de Grecia.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (375, '\"La meditación fortifica a los fuertes y debilita a los débiles\".', 'Benjamin-H. Constant de Rebecque (1767-1830); escritor y político francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (376, '\"Al bien hacer jamás le falta premio\".', 'Miguel de Cervantes Saavedra (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (377, '\"El pasado siempre está presente\".', 'Maurice Maeterlinck (1862-1949); escritor belga.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (378, '\"La naturaleza ha puesto en nuestras mentes\nun insaciable deseo de ver la verdad\".', 'Cicerón, (106-43 a. C.); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (379, '\"El verdadero misterio del mundo es lo visible, no lo invisible\".', 'Óscar Fingal O\'Flahertie Wills Wilde (1854-1900); escritor irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (380, '\"La fuerza de la necesidad es irresistible\".', 'Esquilo (c.525-456 a. C.); poeta trágico griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (381, '\"Los ríos más profundos son siempre los más silenciosos\".', 'Curcio, Quintus Curtius Rufus (siglo I o II d. C.); historiador latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (382, '\"El tiempo no es sino el espacio entre nuestros recuerdos\".', 'Henri Frédéric Amiel (1821-1881); escritor y profesor suizo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (383, '\"Todo es muy difícil antes de ser sencillo\".', 'Thomas Fuller (1609-1661); clérigo y escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (384, '\"El tiempo es un gran maestro que arregla muchas cosas\".', 'Pierre Corneille (1606-1684); dramaturgo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (385, '\"La confianza es madre del descuido\".', 'Baltasar Gracián (1601-1658); jesuita y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (386, '\"Lo que de raíz se aprende nunca del todo se olvida\".', 'Séneca (c.5 a. C.-65 d. C.); filósofo hispanolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (387, '\"La intención hace el agravio\".', 'Pedro Calderón de la Barca (1600-1681); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (388, '\"La verdad levanta tormentas contra sí que  desparraman su semilla a los cuatro vientos\".', 'Rabindranath Tagore (1861-1914); poeta hindú.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (389, '\"El idealismo aumenta en proporción directa  de la distancia que nos separa del problema\".', 'John Galsworthy (1867-1933); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (390, '\"Todos los asuntos tienen dos asas: por una son manejables, por la otra no\".', 'Epícteto (c.50-c.125 d. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (391, '\"En todas las cosas parece existir como ley un círculo\".', 'Tácito, Publius Cornelius Tacitus (c.55-115 d. C.); historiador romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (392, '\"Nada vale la pena de ser  encontrado sino lo que jamás ha existido aún\".', 'Pierre Teilhard de Chardin (1881-1955); filósofo y teólogo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (393, '\"Comprender es el principio de aprobar\".', 'Baruch Spinoza (1632-1677); filósofo holandés, de origen judeoespañol.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (394, '\"El mundo está lleno de pequeñas alegrías; el arte consiste en saber distinguirlas\".', 'Li Po (o Li Taibo) (700-762); poeta chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (395, '\"El trabajo del pensamiento se parece a la perforación de un pozo:\nel agua es turbia al principio, más luego se clarifica\".', 'Proverbio chino');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (396, '\"Si quieres que tu secreto sea guardado, guárdalo tú mismo\".', 'Séneca el Filósofo, (c.5 a. C.-65 d. C.); filósofo hispanolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (397, '\"Es intentando lo imposible como se realiza lo posible\".', 'Henri Barbusse (1873-1935); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (398, '\"Sólo comprendemos aquellas preguntas que podemos responder\".', 'Friedrich Nietzsche (1844-1900); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (399, '\"Un camino de mil millas comienza con un paso\".', 'Benjamin Franklin (1706-1790); físico y político estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (400, '\"Cuanto más se dividen los obstáculos son más fáciles de vencer\".', 'Concepción Arenal (1820-1893); escritora y socióloga española.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (401, '\"Lo mejor de la vida es el pasado, el presente y el futuro\".', 'Pier Paolo Pasolini (1922-1975); escritor y director de cine italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (402, '\"Haríamos muchas más cosas si creyéramos que son muchas menos las imposibles\".', 'C. Guillaume de Lamoignan de Malesherbes (1721-1794); político francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (403, '\"Una llave de oro abre todas las cerraduras\".', 'Christoph Wieland (1733-1813); escritor alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (404, '\"La habilidad es a la astucia lo que la destreza a la estafa\".', 'Nicolas-Sébastien Roch Chamfort (1741-1794); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (405, '\"Se aprende más por lo que la gente habla entre sí\no por lo que se sobrentiende, que planteándose preguntas\".', 'Rudyard Kipling (1865-1936); escritor inglés, de origen indio.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (406, '\"La acción es el fruto propio del conocimiento\".', 'Thomas Fuller (1609-1661); clérigo y escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (407, '\"El sentido común no es nada común\".', 'Voltaire (1694-1778); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (408, '\"El que se pierde es el que encuentra las nuevas sendas\".', 'Nils Kjaer (1870-1924); escritor noruego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (409, '\"Encuentro tanta diferencia entre yo y yo mismo como entre yo y los demás\".', 'Michel Eyquem de Montaigne (1533-1592); pensador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (410, '\"La ignorancia es la noche de la mente: pero una noche sin luna y sin estrellas\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (411, '\"Construye tu cabaña en el valle, pero nunca lo hagas en la cima\".', 'Heinrich Heine (1797-1856); poeta romántico alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (412, '\"La prudencia es el más excelso de todos los bienes\".', 'Epicuro (341-271 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (413, '\"Una experiencia nunca es un fracaso, pues siempre viene a demostrar algo\".', 'Thomas Alva Edison (1847-1931); físico e inventor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (414, '\"El destino es el que baraja las cartas, pero nosotros somos los que jugamos\".', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (415, '\"Si tuviese mi mano cerrada llena de verdades, me guardaría muy bien de abrirla\".', 'Bernard Le Bovier de Fontenelle (1657-1757); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (416, '\"Uno a uno, todos somos mortales. Juntos, somos eternos\".', 'Apuleyo, Lucius Apuleius (c.124-180 d. C.); escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (417, '\"El que ha comenzado bien, está a la mitad de la obra\".', 'Horacio, Quintus Horatius Flaccus (65-8 a. C.); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (418, 'Las paredes que nosotros construimos a nuestro\nalrededor, alejan la tristeza, pero también alejan las alegrías', 'Jim Rohn');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (419, 'Cada gran salto que logra, viene después de que\nhaya tomado una decisión clara y firme, de algún tipo', 'Brian Tracy');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (420, 'Cuando usted toma una decisión, el universo conspira para que se realice', 'Ralph Waldo Emerson');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (421, 'Las personas empiezan a tener  éxito, en el momento en que lo deciden', 'Harvey Mackay');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (422, 'Mantengase firme en sus decisiones, pero sea flexible en su metodología', 'Anthony Robbins');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (423, 'Sin el sentido de urgencia, el deseo pierde su valor', 'Jim Rohn');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (424, 'Cuando usted desea algo desesperadamente demasiado, desarrollará la confianza y la\nhabilidad de superar cualquier obstáculo en su camino', 'Brian Tracy');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (425, 'La diferencia entre una persona exitosa y los demás, no está en la falta de fuerza,\no en la falta de conocimiento, sino más bien está en la falta de voluntad', 'Vincent T. Lombardi');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (426, 'Cada acto de autodisciplina aumenta su confianza en sí mismo y en sus habilidades', 'Brian Tracy');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (427, '\"Mil rutas se apartan del fin elegido, pero hay una que llega a él\".', 'Michel Eyquem de Montaigne (1533-1592); pensador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (428, '\"La música es la aritmética de los sonidos, como la óptica es la geometría de la luz\".', 'Claude Debussy (1862-1918); compositor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (429, '\"Una cosa es continuar la historia y otra repetirla\".', 'Jacinto Benavente (1866-1953); dramaturgo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (430, '\"Excava el pozo antes de que tengas sed\".', 'Proverbio chino');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (431, '\"Cada día es una pequeña vida\".', 'Horacio, Quintus Horatius Flaccus (65-8 a. C.); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (432, '\"Lo que los hombres realmente quieren no es el conocimiento sino la certidumbre\".', 'Bertrand Russell (1872-1970); filósofo y matemático inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (433, '\"La belleza es el acuerdo entre el contenido y la forma\".', 'Henrik Ibsen (1828-1906); dramaturgo noruego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (434, '\"Creer posible algo es hacerlo cierto\".', 'Christian Friedrich Hebbel (1813-1863); poeta y autor dramático alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (435, '\"El niño reconoce a la madre por la sonrisa\".', 'León Tolstoi (1828-1910); escritor ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (436, '\"Hablar es el arte de sofocar e interrumpir el pensamiento\".', 'Thomas Carlyle (1795-1881); historiador y ensayista escocés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (437, '\"Lo que no ha pasado a mediodía puede pasar por la noche\".', 'César Borgia (c.1475-1507); príncipe, guerrero y político italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (438, '\"El tiempo es una cierta parte de la eternidad\".', 'Cicerón, Marcus Tullius Cicero (106-43 a. C.); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (439, '\"Sírvete de lo aparente como indicio de lo inaparente\".', 'Solón (640-558 a. C.); legislador griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (440, '\"Los límites de mi lenguaje son los límites de mi mente\".', 'Ludwig Wittgenstein (1889-1951); filósofo británico, de origen austríaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (441, '\"El artista ve lo que ya no existe o lo que todavía no ha existido en la realidad\".', 'Ilya Grigorievich Ehrenburg (1891-1967); escritor soviético.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (442, '\"Mediante la lectura nos hacemos contemporáneos de todos los hombres\ny ciudadanos de todos los países\".', 'Antoine Houdar de la Motte (1672-1731); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (443, '\"Divide las dificultades que examinas en tantas partes\ncomo sea posible para su mejor solución\".', 'René Descartes (1596-1650); filósofo y científico francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (444, '\"Saber para prever, a fin de poder\".', 'Auguste Comte (1798-1857); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (445, '\"La suerte es la sonrisa de lo desconocido\".', 'Etienne Rey (finales siglo XIX); dramaturgo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (446, '\"Yo no procuro conocer las preguntas; procuro conocer las respuestas\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (447, 'El hombre supera al nimal con la palabra; pero con el silencio se supera a sí mismo', 'O. Manson');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (448, 'El mercado es tan buen lugar para el silencio como el monasterio,\npues el silencio es la ausencia de ego', 'Antony de Mello');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (449, 'El único rival que usted puede llegar a tener, es la competencia\nentre su disciplinada e indisciplinada mente', 'James A. Ray');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (450, 'Actitud, humor y acción (presistencia) serán los azotes del miedo y el rechazo.\nMiedo y fracaso no existen si usted cree que no existen', 'Jeffrey Gitomer');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (451, 'Hay dos formas de encontrar dificultades.\nUsted cambia las dificultades, o ellas lo cambian a usted', 'Phyllis Bottome');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (452, 'El carácter es la habilidad de llevar a cabo una idea o\nproyecto siempre con la misma emoción con que se planeó', 'Brian Tracy');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (453, '\"La memoria es el centinela del cerebro\".', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (454, '\"Sorprendernos por algo es el primer paso de la mente hacia el descubrimiento\".', 'Louis Pasteur (1822-1895); químico y microbiólogo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (455, '\"El mal de la calumnia es semejante a la mancha de aceite: deja siempre huellas\".', 'Napoleón Bonaparte (1769-1821); emperador de Francia.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (456, '\"La madre de la invención es la necesidad\".', 'Susannah Centlivre (c.1667-1723); escritora inglesa.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (457, '\"Todo lo racional es real; y todo lo real es racional\".', 'Georg Wilhelm Friedrich Hegel (1770-1831); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (458, '\"El tiempo no es sino la corriente en la que estoy pescando\".', 'Henry David Thoreau (1817-1862); escritor y pensador estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (459, '\"Nunca se mezclan el agua y el fuego\".', 'Teognis (siglo VI a. C.); poeta griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (460, '\"La oportunidad es un pájaro que jamás se posa\".', 'Anónimo');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (461, '\"La lectura es a la mente lo que el ejercicio al cuerpo\".', 'Joseph Addison (1672-1719); ensayista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (462, '\"Nunca sopla viento favorable para el marino que no sabe en qué puerto fondear\".', 'Proverbio americano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (463, '\"Libros, caminos y días dan al hombre sabiduría\".', 'Proverbio árabe');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (464, '\"En el idioma está el árbol genealógico de una nación\".', 'Samuel Johnson (1709-1784); ensayista y lexicógrafo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (465, '\"El mundo real es mucho más pequeño que el mundo de la imaginación\".', 'Friedrich Nietzsche (1844-1900); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (466, '\"La verdad anda sobre la mentira como el aceite sobre el agua\".', 'Miguel de Cervantes Saavedra (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (467, '\"Una palabra bien elegida puede economizar no sólo cien palabras\nsino cien pensamientos\".', 'Henri Poincaré (1854-1912); matemático francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (468, '\"No saber lo que ha ocurrido antes de nosotros es como seguir siendo niños\".', 'Cicerón, (106-43 a. C.); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (469, '\"Tú no ves lo que eres, sino su sombra\".', 'Rabindranath Tagore (1861-1914); poeta hindú.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (470, '\"El presente es la viviente suma total del pasado\".', 'Thomas Carlyle (1795-1881); historiador y ensayista escocés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (471, '\"Los acontecimientos, cuando no se escriben,\nno se cuentan o no se recuerdan, es como si no hubiesen ocurrido\".', 'Anónimo');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (472, '\"La música es un eco del mundo invisible\".', 'Giuseppe Mazzini (1805-1872); político revolucionario italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (473, '¿Qué puede haber imprevisto para el que nada ha previsto?', 'Paul Valéry (1871-1945); poeta y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (474, '\"La unidad es la variedad, y la variedad en la unidad es la ley suprema del universo\".', 'Isaac Newton (1642-1727); matemático, físico y astrónomo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (475, '\"Tributa tu admiración a las montañas, pero quédate en el llano;\npondera el mar, pero mantente en la ribera\".', 'John Florio (c.1553-1625); escritor y filólogo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (476, '\"Como la vista es al cuerpo, la razón es al espíritu\".', 'Aristóteles (384-322 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (477, '\"Tres clases hay de ignorancia: no saber lo que debiera saberse,\nsaber mal lo que se sabe, y saber lo que no debiera saberse\".', 'Duque de la Rochefoucauld, F. Rochefoucauld (1613-1680); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (478, '\"Hay mucho que saber, es poco el vivir, y no se vive si no se sabe.\nHombre sin noticias, mundo a oscuras\".', 'Baltasar Gracián (1601-1658); jesuita y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (479, '\"Mientras se gana algo no se pierde nada\".', 'Miguel de Cervantes Saavedra (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (480, '\"Hallaré un camino o me lo abriré\".', 'Aníbal (247-183 a. C.); general cartaginés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (481, '\"Si quieres que tu secreto sea guardado, guárdalo tú mismo\".', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo hispanolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (482, '\"La habilidad y la constancia son las armas de la debilidad\".', 'Nicolás Maquiavelo (1469-1527); político e historiador italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (483, '\"La sabiduría es un tesoro que nunca causa entorpecimientos\".', 'Jean de La Fontaine (1621-1695); novelista y fabulista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (484, '\"Si lloras de alegría, no seques tus lágrimas: las robas al dolor\".', 'Paul Jean Toulet (1867-1920); escritor y crítico francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (485, '\"Las ideas no duran mucho. Hay que hacer algo con ellas\".', 'Santiago Ramón y Cajal (1854-1934); médico español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (486, '\"El trabajo es todo lo que se está obligado a hacer;\nel juego es lo que se hace sin estar obligado a ello\".', 'Mark Twain (1835-1910); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (487, '\"El que no aplique nuevos remedios debe esperar nuevos males,\nporque el tiempo es el máximo innovador\".', 'Barón de Verulam, Francis Bacon (1561-1626); filósofo y político inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (488, '\"La verdad se asienta en un limitado ámbito; el error, empero, es inmenso\".', 'Henry Saint-John (1678-1751); estadista y escritor inglés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (489, '\"Los dos mayores tiranos del mundo: la casualidad y el tiempo\".', 'Johann Herder (1744-1803); escritor y filósofo prusiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (490, '\"Hay pasiones que la prudencia enciende y que no existirían sin el riesgo que provocan\".', 'Jules Amédé Barbey d\'Aurevilly (1808-1889); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (491, '\"Las viejas ideas son prejuicios; las nuevas, caprichos\".', 'Ximenes Doudan (1800-1872); literato francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (492, '\"Ni la contradicción es indicio de falsedad,\nni la falta de contradicción es indicio de verdad\".', 'Blaise Pascal (1623-1662); científico, filósofo y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (493, '\"La casualidad no es, ni puede ser,\nmás que una causa ignorada de un efecto desconocido\".', 'Voltaire (nacido François-Marie Arouet) (1694-1778); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (494, '\"Una acción es la perfección y la publicación del pensamiento\".', 'Ralph Waldo Emerson (1803-1882); poeta y ensayista estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (495, '\"Lo que sucede hoy acaeció otras veces; lo que se dice, sigue diciéndose\ny se dirá más adelante; lo que ha de ser, ya fue un día\".', 'Antonio Francesco Doni (1513-1574); escritor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (496, '\"La mucha luz es como la mucha sombra: no deja ver\".', 'Octavio Paz (1914); escritor mexicano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (497, '\"Los cautos rara vez se equivocan\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (498, '\"Ver es creer, pero sentir es estar seguro\".', 'John Ray (1627-1705); naturalista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (499, '\"El presente sólo se forma del pasado,\ny lo que se encuentra en el efecto estaba ya en la causa\".', 'Henri Bergson (1859-1941); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (500, '\"A siete años de un suceso, el suceso ya es otro\".', 'Camilo José Cela (1916-2002); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (501, '\"Una memoria ejercitada es guía más valiosa que el genio y la sensibilidad\".', 'Friedrich von Schiller (1759-1805); poeta alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (502, '\"De todas las formas de engañar a los demás,\nla pose de seriedad es la que hace más estragos\".', 'Santiago Rusiñol (1861-1931); pintor y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (503, '\"Cualquier cosa debe tomarse seriamente, nada trágicamente\".', 'Luis Adolfo Thiers (1797-1877); estadista e historiador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (504, '\"La práctica debería ser producto de la reflexión, no al contrario\".', 'Hermann Hesse (1877-1962); escritor suizo, de origen alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (505, '\"Nada vale la ciencia si no se convierte en conciencia\".', 'Carlo Dossi (nacido Alberto Pisani Dossi) (1849-1910); novelista italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (506, '\"Nada perece en el universo; cuanto en él acontece no pasa de meras transformaciones\".', 'Pitágoras (570-500 a. C.); filósofo y matemático griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (507, '\"Donde truena un hecho, ten la certeza de que ha relampagueado una idea\".', 'Ippolito Nievo (1831-1861); escritor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (508, '\"El lenguaje es el vestido del pensamiento\".', 'Samuel Johnson (1709-1784); ensayista y lexicógrafo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (509, '\"El cambio es la única cosa inmutable\".', 'Arthur Schopenhauer (1788-1860); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (510, '\"Todo número es cero ante el infinito\".', 'Víctor Hugo (1802-1885); poeta y novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (511, '\"Las buenas noticias siempre llegan tarde; las malas, demasiado pronto\".', 'Friedrich Martin von Bodenstedt (1819-1892); escritor y traductor alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (512, '\"Una síntesis vale por diez análisis\".', 'Eugenio d\'Ors (1882-1954); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (513, '\"El placer supremo es obtener lo que se anhela\".', 'Tales de Mileto (c.624-c.546 a. C.); filósofo y geómetra griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (514, '\"La razón puede advertirnos sobre lo que conviene evitar;\nsolamente el corazón nos dice lo que es preciso hacer\".', 'Joseph Joubert (1754-1824); moralista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (515, '\"Todo lo que ocurre, desde lo más grande a lo más chico, ocurre necesariamente\".', 'Arthur Schopenhauer (1788-1860); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (516, '\"Todo es posible para aquel que lo considera tal\".', 'William Ellery Channing (1780-1842); teólogo estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (517, '\"El mejor profeta del futuro es el pasado\".', 'Lord Byron, George Gordon (1788-1824); poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (518, '\"No encuentres la falta; encuentra el remedio\".', 'Henry Ford (1863-1947); industrial estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (519, '\"Vigilando, laborando y meditando todas las cosas prosperan\".', 'Salustio, Caius Sallustius Crispus (85-35 a. C.); historiador latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (520, '\"La evidencia es la más decisiva demostración\".', 'Cicerón (106-43 a. C.); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (521, '\"El exceso es el veneno de la razón\".', 'Francisco de Quevedo y Villegas (1580-1645); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (522, '\"El éxito no viene a ti. Tú vas a él\".', 'M.Collins.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (523, '- \"No hay un gran paso que represente un logro. Hay un montón de pequeños pasos\".', 'P.Cohen.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (524, '\"La paciencia tiene más poder que la fuerza\".', 'Plutarco (46-125 d. C.); escritor griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (525, '\"Quien no ha afrontado la adversidad no conoce su propia fuerza\".', 'Benjamin Jonson (1572-1637); dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (526, '\"El asunto es el problema; la forma, la solución\".', 'Christian Friedrich Hebbel (1813-1863); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (527, '\"La ilusión vale cuando la realidad la toma de la mano\".', 'Anónimo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (528, '\"Nada es constante en este mundo sino la inconstancia\".', 'Jonathan Swift (1667-1745); escritor irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (529, '\"No perdamos nada del pasado. Sólo con el pasado se forma el porvenir\".', 'Anatole France (1844-1924); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (530, '\"Una sola piedra puede desmoronar un edificio\".', 'Francisco de Quevedo y Villegas (1580-1645); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (531, '\"Vivimos bajo el mismo cielo, pero ninguno tenemos el mismo horizonte\".', 'Konrad Adenauer (1876-1967); político alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (532, '\"Las verdades que revela la ciencia superan siempre a los sueños que destruye\".', 'Joseph Ernest Renan (1823-1892); historiador y filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (533, '\"Si bien buscas, encontrarás\".', 'Platón (c.428-c.347 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (534, '\"Hay un libro abierto siempre para todos los ojos: la naturaleza\".', 'Jean Jacques Rousseau (1712-1778); escritor y filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (535, '\"La experiencia no consiste en lo que se ha vivido, sino en lo que se ha reflexionado\".', 'José María de Pereda (1833-1906); novelista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (536, '\"Sólo la inteligencia se examina a sí misma\".', 'Jaime Balmes (1810-1848); sacerdote y filósofo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (537, '\"El mundo ha sido creado para ser recreado\".', 'Georges Duhamel (1884-1966); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (538, 'Las palabras pueden ser como rayos X si se usan apropiadamente: lo atraviesan todo\".\nAldous Huxley\n\"El pecado que no tiene perdón es el que mata la vida del amor en un ser', 'Henrik Ibsen');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (539, '\"No son las locomotoras, sino las ideas, las que llevan y arrastran el mundo\".', 'Victor Hugo (1802-1885); poeta y novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (540, '\"Vale más sembrar una cosecha nueva que llorar por la que se perdió\".', 'Alejandro Casona (1903-1965); dramaturgo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (541, '\"No conozco ningún otro signo de superioridad que la bondad\".', 'Ludwig van Beethoven (1770-1827); compositor alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (542, '\"Es bueno seguir la pendiente con tal que sea subiendo\".', 'André Gide (1869-1951); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (543, '\"Toda dificultad eludida se convertirá más tarde\nen un fantasma que perturbará nuestro reposo\".', 'Frédéric Chopin (1810-1849); pianista y compositor polaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (544, '\"Manejar el silencio es más difícil que manejar la palabra\".', 'Georges Clemenceau (1841-1929); político francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (545, '\"El conocimiento es sólo una de las representaciones de la existencia\".', 'José Vasconcelos (1882-1959); político, escritor y filósofo mexicano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (546, '\"Si añades un poco a lo poco y lo haces así con frecuencia,\npronto llegará a ser mucho\".', 'Hesíodo (siglo VIII a. C.); poeta griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (547, '\"Las obras no se acaban, se abandonan\".', 'Paul Valéry (1871-1945); poeta y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (548, '\"Sólo en la actividad desearás vivir cien años\".', 'Proverbio japonés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (549, '\"En lo pasado está la historia del futuro\".', 'Juan Donoso Cortés (1809-1853); ensayista y diplomático español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (550, '\"La verdad si no es entera, se convierte en aliada de lo falso\".', 'Javier Sádaba (1940); filósofo y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (551, '\"La existencia dividida por la razón deja siempre un resto\".', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (552, '\"El tiempo físico nos es extraño, mientras el tiempo interior es nosotros mismos\".', 'Alexis Carrel (1873-1944); biólogo y médico francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (553, '\"Un hecho vale más que todo un mundo de promesas\".', 'Jacob Howell (c.1594-1666); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (554, '\"Entre hombre y hombre no hay gran diferencia.\nLa superioridad consiste en aprovechar las lecciones de la experiencia\".', 'Tucídides (c.471-395 a. C.); historiador griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (555, '\"Muchas cosas se reputan imposibles antes de haberse realizado\".', 'Plinio el Viejo, Caius Plinius Secundus(c.23-79 d. C.); escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (556, '\"El hombre se descubre cuando se mide con un obstáculo\".', 'Antoine de Saint-Éxupery (1900-1944); escritor y aviador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (557, '\"El arte es la perfección de la naturaleza. La naturaleza hizo un mundo y el arte otro\".', 'Sir Thomas Browne (1605-1682); escritor y médico inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (558, '\"No puede impedirse el viento. Pero pueden construirse molinos\".', 'Proverbio holandés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (559, '\"No es posible meter el pie dos veces en el mismo río\".', 'Heráclito (c.544-480 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (560, '\"La claridad es el barniz de los maestros\".', 'Marqués de Vauvenargues, Luc de Clapiers (1715-1747); moralista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (561, '\"La ciencia es la estética de la inteligencia\".', 'Gaston Bachelard (1884-1962); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (562, '\"Dicen los libros indios que dondequiera pone el hombre la planta\npisa siempre cien senderos\".', 'José Ortega y Gasset (1883-1955); filósofo y ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (563, '\"Ni la utilidad del mentir es sólida, ni el mal de la verdad perjudica mucho tiempo\".', 'Juan Luis Vives (1492-1540); humanista y filósofo español');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (564, '\"En la vida, el primero y el último maestro es el vivir mismo,\ncon riesgos y sin reservas\".', 'Franz Werfel (1890-1945); escritor austríaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (565, '\"Apresúrate lentamente\".', 'Suetonio (75-150 d. C.); historiador latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (566, '\"La duda: la escuela de la verdad\".', 'Barón de Verulam, Francis Bacon (1561-1626); filósofo y político inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (567, '\"Se ha sembrado la palabra mañana, pero no ha brotado todavía\".', 'Anónimo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (568, '\"La gota horada la piedra, no por su fuerza, sino por su constancia\".', 'Ovidio, Publius Ovidius Naso (43 a. C.-17 d. C.); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (569, '\"El ingenio quizás es al talento lo que el instinto a la razón\".', 'Jules Renard (1864-1910); escritor y dramaturgo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (570, '\"A menudo encontramos nuestro destino\npor los caminos que tomamos para evitarlo\".', 'Jean de La Fontaine (1621-1695); novelista y fabulista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (571, '\"El principio es la mitad del todo\".', 'Pitágoras (570-500 a. C.); filósofo y matemático griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (572, '\"El mejor modo de resolver una dificultad es no tratar de soslayarla\".', 'Noel Clarasó (1905-1985); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (573, '\"El que nada duda, nada sabe\".', 'Proverbio griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (574, '\"Todo aquello que se exagera, por lo mismo se empequeñece\".', 'Jean Françoise de la Harpe (1739-1803); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (575, '\"El sentido común es el instinto de la verdad\".', 'Max Jacobs (1876-1944); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (576, '\"No darás tropezón ni desatino que no te haga adelantar camino\".', 'Bernardo de Balbuena (1568-1627); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (577, '\"En todas las tierras el sol sale al amanecer\".', 'George Herbert (1593-1633); poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (578, '\"El hombre no se da cuenta de cuánto puede hacer,\nmás que cuando realiza intentos, medita y desea\".', 'Ugo Foscolo (1778-1827); escritor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (579, '\"La verdad es una antorcha que luce en medio de la niebla sin disiparla\".', 'Claude Adrien Helvétius (1715-1771); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (580, '\"La peor decisión es la indecisión\".', 'Benjamin Franklin (1706-1790); filósofo, físico y político estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (581, '\"Lo que ocurre realmente es trivial al lado de lo que pudiera ocurrir\".', 'Robert von Musil (1880-1942); escritor austríaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (582, '\"El arte de vencer se aprende en las derrotas\".', 'Simón Bolívar (1783-1830); militar, político y ensayista venezolano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (583, '\"Ante el inminente peligro, la fortaleza es lo que cuenta\".', 'Lucano, Marcus Annaeus Lucanus (39-65 d. C.); poeta hispanolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (584, '\"La fantasía no es otra cosa que un modo de memoria emancipado del orden del tiempo\".', 'Samuel Taylor Coleridge (1772-1834); poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (585, '\"Repetir es persuadir con más detalle\".', 'Duque de Levis (nacido Pierre Marc-Gaston) (1755-1830); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (586, 'Digamos que existen dos tipos de mentes poéticas: una apta para inventar fábulas\ny otra dispuesta a creerlas.\"', 'Galileo Galilei (1564-1642), matemático, astrónomo y físico italiano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (587, '\"Después de saber cuándo debemos aprovechar una oportunidad,\nlo más importante es saber cuándo debemos renunciar a una ventaja\".', 'Benjamin Disraeli (1804-1881); político inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (588, '\"Lo que se considera ceguera del destino es en realidad propia miopía\".', 'William Faulkner (1897-1962); novelista estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (589, '\"Frío e insípido es el consuelo cuando no va envuelto en algún remedio\".', 'Platón (c.428-c.347 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (590, 'Un pequeño gusano roe el corazón a un cedro y lo derriba', 'Diego de Saavedra (1584-1648); diplomático y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (591, '\"El día precedente enseña el día que sigue\".', 'Píndaro (521-441 a. C.); poeta griego');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (592, '\"Lo verdadero puede no ser a veces inverosímil\".', 'Nicolás Boileau (1636-1711); poeta y crítico francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (593, '\"El más largo aprendizaje de todas las artes es aprender a ver\".', 'Jules de Goncourt (1830-1896); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (594, '\"Sólo la renovación puede mantener, el que se queda parado, se retrasa\".', 'Everhardus Johannes Potgieter (1808-1875); escritor holandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (595, '\"El modo de dar una vez en el clavo es dar cien veces en la herradura\".', 'Miguel de Unamuno (1864-1936); escritor y filósofo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (596, '\"Toda la tierra está al alcance del sabio, ya que la patria de un alma elevada es el universo\".', 'Demócrito (c.460-370 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (597, '\"Quien se empeña en pegarle una pedrada a la luna no lo conseguirá,\npero terminará sabiendo manejar la honda\".', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (598, '\"Los oídos no sirven de nada a un cerebro ciego\".', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (599, '\"La uniformidad es la muerte; la diversidad es la vida\".', 'Mijail Aleksandrovich Bakunin (1814-1876); revolucionario ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (600, '\"Nada tarda tanto como aquello que no se empieza\".', 'Alain (nacido Émile Chartier) (1868-1951); ensayista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (601, '\"Sólo se inventa mediante el recuerdo\".', 'Jean Baptiste Alphonse Karr (1808-1890); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (602, '\"No es tan dañoso oír lo superficial como dejar de oír lo necesario\".', 'Quintiliano, Marcus Fabius (35-96 d. C.); escritor hispanolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (603, '\"La experiencia es el bastón de los ciegos\".', 'Jacques Roumain (1907-1944); poeta francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (604, '\"Los ríos más profundos son siempre los más silenciosos\".', 'Curcio, Quintus Curtius Rufus (siglo I o II d. C.); historiador latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (605, '\"La imaginación es más importante que la sabiduría\".', 'Albert Einstein (1879-1955); físico y matemático.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (606, '\"La forma última, la forma santa de la teoría, es la acción\".', 'Nikos Kazantzakis (1855-1957); escritor griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (607, '\"Una de las grandes desventajas de la prisa es que lleva demasiado tiempo\".', 'Gilbert Keith Chesterton (1874-1936); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (608, '\"La tinta más pobre de color vale más que la mejor memoria\".', 'Proverbio chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (609, '\"Sólo hay un bien: el conocimiento. Sólo hay un mal: la ignorancia\".', 'Sócrates (470-399 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (610, '\"La vida sería imposible si todo se recordase.\nEl secreto está en saber elegir lo que debe olvidarse\".', 'Roger Martin du Gard (1881-1958); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (611, '\"En la circunferencia, el comienzo y el fin coinciden\".', 'Heráclito (c.544-480 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (612, '\"Una familia feliz no es sino un paraíso anticipado\".', 'Sir John Bowring (1792-1872); filósofo y político inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (613, '\"En principio, la investigación necesita más cabezas que medios\".', 'Severo Ochoa (1905-1993); bioquímico español y Premio Nobel de Medicina.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (614, '\"No existen más que dos reglas para escribir: tener algo que decir y decirlo\".', 'Óscar Wilde (1854-1900); escritor irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (615, '\"Si de algo soy rico es de perplejidades y no de certezas\".', 'Borges, Jorge Luis (1899-1987); poeta, ensayista y narrador argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (616, '\"Oír o leer sin reflexionar es una ocupación inútil\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (617, '\"Saber es acordarse\".', 'Aristóteles (384 AC-322 AC.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (618, '\"Nunca consideres el estudio como una obligación, sino como una oportunidad\npara penetrar en el bello y maravilloso mundo del saber\".', 'Albert Einstein (1879-1955); físico y matemático.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (619, '\"La historia cuenta lo que sucedió; la poesía lo que debía suceder\".', 'Aristóteles (384 AC-322 AC.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (620, '\"Hay una manera de contribuir a la protección de la humanidad, y es no resignarse\".', 'Sábato, Ernesto (1911); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (621, '\"Trabaja en impedir delitos para no necesitar castigos\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (622, '\"La confianza es madre del descuido\".', 'Baltasar Gracián (1601-1658); jesuita y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (623, '\"A cada día le bastan sus temores, y no hay por qué anticipar los de mañana\".', 'Charles Péguy (1873-1914); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (624, '\"Lo pasado ha huido, lo que esperas está ausente, pero el presente es tuyo\".', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (625, '\"Nada tan estúpido como vencer; la verdadera gloria está en convencer\".', 'Victor Hugo (1802-1885); poeta y novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (626, '\"La soledad se admira y desea cuando no se sufre,\npero la necesidad humana de compartir cosas es evidente\".', 'Martín Gaite, Carmen (1925 - 2000); novelista española.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (627, '\"La respuesta más rápida es la acción\".', 'Proverbio americano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (628, '\"La medida más segura de toda fuerza es la resistencia que vence\".', 'Zweig, Stefan (1881-1942); escritor austríaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (629, '\"El que un perro haya mordido a un hombre, no es ninguna noticia;\nuna noticia es el que un hombre haya mordido a un perro\".', 'Dana, Charles A. (1819 - 1899); escritor y editor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (630, '\"Debe haber algo extrañamente sagrado en la sal:\nestá en nuestras lágrimas y en el mar\".', 'Gibran, Khalil  (1883-1931); ensayista, novelista y poeta libanés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (631, '\"El hombre cauto jamás deplora el mal presente; emplea el presente\nen prevenir las aflicciones futuras\".', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (632, '\"Cuando los elefantes luchan, la hierba es la que sufre\".', 'Proverbio africano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (633, '\"Cuanto más alto coloque el hombre su meta, tanto más crecerá\".', 'Friedrich von Schiller (1759-1805); poeta alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (634, 'Toda verdad pasa por tres etapas.\nPrimero, es ridiculizada. Segundo, es violentamente rechazada.\nTercero, es aceptada como evidente.', 'Arthur Schopenhauer –');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (635, '\"No hay árbol que el viento no haya sacudido\".', 'Proverbio hindú.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (636, '\"Dadme un punto de apoyo y moveré la tierra\".', 'Arquímedes (¿285-212 a. C.); matemático, físico e inventor griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (637, '\"El presente no existe, es un punto entre la ilusión y la añoranza\".', 'Villalonga, Llorenç (1897-1980); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (638, '\"Los ojos no sirven de nada a un cerebro ciego\".', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (639, '\"El tiempo saca a luz todo lo que está oculto y encubre\ny esconde lo que ahora brilla con el más grande esplendor\".', 'Horacio Flaco, Quinto (65 a. C. -8 a. C.); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (640, '\"El pensamiento es la única cosa del Universo\nde la que no se puede negar su existencia: negar es pensar\".', 'Ortega y Gasset, José (1883-1955); filósofo y ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (641, '\"Ver es creer, pero sentir es estar seguro\".', 'Ray, John (1627-1705); naturalista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (642, '\"La mucha luz es como la mucha sombra: no deja ver\".', 'Octavio Paz (1914); escritor mexicano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (643, '\"La prudencia suele faltar cuando más se la necesita\".', 'Siro, Publius (siglo I a. C.); poeta romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (644, '\"La inspiración es la ocasión del genio\".', 'Honoré de Balzac (1799-1850); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (645, '\"El saber es la parte principal de la felicidad\".', 'Sócrates (470-399 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (646, '\"La ciencia y la sabiduría, lejos de ser una misma cosa,\nno tienen entre sí a menudo conexión alguna\".', 'Cowper, William (1731-1800); poeta británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (647, '\"Nada en el mundo es más peligroso que la ignorancia sincera\ny la estupidez concienzuda\".', 'Luther King, M. (1929-1968); líder norteamericano de los derechos civiles.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (648, '\"El corazón es un niño: espera lo que desea\".', 'Proverbio ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (649, '\"Lo último que uno sabe es por donde empezar\".', 'Pascal, Blaise (1623-1662); científico, filósofo y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (650, '\"Aprender sin pensar es inútil. Pensar sin aprender, peligroso\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (651, '\"Quien da primero, da dos veces\".', 'Refrán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (652, '\"El momento elegido por el azar vale siempre más\nque el momento elegido por nosotros mismos\".', 'Proverbio chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (653, '\"La única función del tiempo es consumirse: arde sin dejar cenizas\".', 'Triolet, Elsa (1896-1970); novelista francesa.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (654, '\"No hay árbol que el viento no haya sacudido\".', 'Proverbio hindú.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (655, '\"El misterio es la cosa más bonita que podemos experimentar.\nEs la fuente de todo arte y ciencia verdaderos\".', 'Einstein, Albert (1879-1955); físico y matemático.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (656, '\"La brevedad es el alma del ingenio\".', 'Shakespeare, William (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (657, '\"Mejor es prevenir que curar\".', 'Erasmo de Rotterdam (1466-1536); humanista holandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (658, '\"Experiencia es el nombre que damos a nuestras equivocaciones\".', 'Wilde, Óscar (1854-1900); escritor irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (659, '\"Estudia el pasado si quieres pronosticar el futuro\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (660, '\"Enfrentarse, siempre enfrentarse,\nes el modo de resolver el problema. ¡Enfrentarse a él!\".', 'Conrad, Joseph (1857-1924); narrador británico de origen polaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (661, '\"La ciencia se compone de errores,\nque a su vez son los pasos hacia la verdad\".', 'Verne, Julio (1828-1905); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (662, '\"De virtud hay una especie, de maldad, muchas\".', 'Platón (427-347 a.C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (663, '\"El arte es un compendio de la naturaleza formado por la imaginación\".', 'José María E Ca de Queiroz (1845-1900); novelista portugués.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (664, '\"Es un hecho que el hombre tiene que controlar la ciencia\ny chequear ocasionalmente el avance de la tecnología\".', 'Huxley, Thomas Henry (1825-1895); zoólogo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (665, '\"La inteligencia consiste no sólo en el conocimiento, sino también\nen la destreza de aplicar los conocimientos en la práctica\".', 'Aristóteles (384 AC-322 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (666, '\"Cuando hayas de sentenciar procura olvidar a los litigantes y acordarte sólo de la causa\".', 'Epicteto de Frigia (50-135); filósofo grecolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (667, '\"La ignorancia afirma o niega rotundamente; la ciencia duda\".', 'Voltaire -nacido François-Marie Arouet- (1694-1778); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (668, '\"Uno no puede hablar acerca del misterio, uno debe ser cautivado por él\".', 'Magritte, René (1898 - 1967); pintor belga.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (669, '\"El tiempo no es sino el espacio entre nuestros recuerdos\".', 'Amiel, Henri Frédéric (1821-1881); escritor y profesor suizo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (670, '\"Saber mucho da ocasión de dudar más\".', 'Montaigne, Michel Eyquem de la (1533-1592); escritor y filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (671, '\"Con el conocimiento se acrecientan las dudas\".', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (672, '\"Terrible es el error cuando usurpa el nombre de la ciencia\".', 'Jaime Luciano Balmes (1810-1848); filósofo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (673, '\"Ni el pasado existe ni el futuro. Todo es presente\".', 'Gonzalo Torrente Ballester; (1910- 1999); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (674, '\"Cuando era más joven podía recordar todo, hubiera sucedido o no\".', 'Mark Twain (1835-1910); escritor y periodista estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (675, '\"El hombre nunca mira al cielo porque siempre lo tiene a la vista\".', 'Jean de Monet (1744-1829); biólogo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (676, '\"La llave del éxito es el conocimiento del valor de las cosas\".', 'John Boyle O\'Reilly (1844-1890); poeta y periodista irlandés-norteamericano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (677, '\"Una idea es verdad cuando aún no se ha impuesto\".', 'Eugene Ionesco (1912-1994); dramaturgo francés de origen rumano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (678, '\"El modo de dar una vez en el clavo es dar cien veces en la herradura\".', 'Miguel de Unamuno (1864-1936); filósofo y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (679, '\"De dos males, elige el menor\".', 'Erasmo de Rotterdam (1466-1536); humanista holandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (680, '\"A nadie le acontece cosa alguna que no sea, por naturaleza, capaz de soportar\".', 'Marco Aurelio (121-180 d. C.); emperador y filósofo romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (681, '\"Los mundos nuevos deben ser vividos antes de ser explicados\".', 'Alejo Carpentier (1904-1980); novelista, ensayista y musicólogo cubano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (682, '\"La suerte favorece sólo a la mente preparada\".', 'Isaac Asimov (1920-1992); escritor estadounidense de ciencia ficción.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (683, '\"Lo que sabemos es una gota de agua; lo que ignoramos es el océano\".', 'Isaac Newton (1643 - 1727); matemático inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (684, '\"En vano se echa la red ante los ojos de los que tienen alas\".', 'Gabriela Mistral (1889 - 1957); escritora chilena.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (685, '\"La fortuna juega en favor de una mente preparada\".', 'Louis Pasteur (1822-1895); químico y microbiólogo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (686, '\"Todas las cosas buenas que existen son el fruto de la originalidad\".', 'John Stuart Mill (1806 - 1873); filósofo y economista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (687, '\"La sabiduría no se traspasa, se aprende\".', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (688, 'Saber no es suficiente, debemos aplicar. Desear no es suficiente, debemos hacer.', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (689, '\"Cuando el carro se ha roto, muchos nos dirán por dónde no se debía pasar\".', 'Proverbio turco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (690, '\"Un error no se convierte en verdad por el hecho de que todo el mundo crea en él\".', 'Mahatma Gandhi (1869-1948); político y pensador indio.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (691, '\"Nunca pienso en el futuro. Llega enseguida\".', 'Einstein, Albert (1879-1955); físico y matemático.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (692, '\"Somos engañados por la apariencia de la verdad\".', 'Horacio, Quintus Horatius Flaccus (65-8 a. C.); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (693, '\"El tiempo es una imagen móvil de la eternidad\".', 'Platón (427-347 a.C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (694, '\"La suprema facultad del hombre no es la razón, sino la imaginación\".', 'Edmundo O\'Gorman (1906-1995); historiador mexicano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (695, '\"El nacimiento de la ciencia fue la muerte de la superstición\".', 'Thomas Henry Huxley (1825-1895); zoólogo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (696, '\"La ciencia avanza a pasos, no a saltos\".', 'Thomas Babington Macaulay (1800-1859); historiador y escritor británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (697, '\"Pocos ven lo que somos, pero todos ven lo que aparentamos\".', 'Nicolás Maquiavelo (1469-1527); político e historiador italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (698, '\"El pensamiento es el corcel; la razón el jinete\".', 'Sand, George (1804-1876); escritora francesa.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (699, '\"Todo lo que se ignora, se desprecia\".', 'Machado, Antonio (1875-1939); poeta y prosista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (700, '\"Cuando llega el tiempo en que se podría, ha pasado en el que se pudo\".', 'Marie von Ebner-Eschenbach (1830-1916); novelista austriaca.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (701, '\"En la naturaleza están todos los estilos futuros\".', 'Rodin, Auguste (1840-1917); escultor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (702, '\"Lo presente, producto de lo pasado, engendra a su vez lo futuro\".', 'G. Wilhelm Leibniz (1646-1716); filósofo, matemático y estadista alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (703, '\"La experiencia no es lo que te sucede, sino lo que haces con lo que te sucede\".', 'Aldous Huxley (1894-1963); novelista, ensayista, crítico y poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (704, '\"Los sabios son los que buscan la sabiduría, los necios piensan ya haberla encontrado\".', 'Napoleón Bonaparte (1769-1821); emperador de Francia.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (705, '\"Callando es como se aprende a oír; oyendo es como se aprende a hablar;\ny luego, hablando se aprende a callar\".', 'Diógenes de Sínope (412 a. C.-323 a. C); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (706, '\"Todo lo que puede suceder sucede, pero sólo puede suceder lo que sucede\".', 'Franz Kafka (1883-1924); escritor checo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (707, '\"Por la calle del ya voy, se va a la casa del nunca\".', 'Miguel de Cervantes Saavedra (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (708, '\"El hombre está dispuesto siempre a negar todo aquello que no comprende\".', 'Pascal, Blaise (1623-1662); científico, filósofo y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (709, '\"Actuar es fácil, pensar es difícil; actuar según se piensa es aún más difícil\".', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (710, '\"Lo mejor que podemos hacer por otro no es sólo compartir\ncon él nuestras riquezas, sino mostrarle las suyas\".', 'Disraeli, Benjamin (1804- 1881); estadista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (711, '\"El error es la disciplina a través de la que avanzamos\".', 'William Ellery Channing (1780-1842); teólogo estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (712, '\"Las acciones correctas para el futuro son la mejor disculpa\nde las equivocaciones del pasado\".', 'Tryon Edwards (1809-1895); escritor y lexicógrafo estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (713, '\"El problema de nuestros tiempos es que el futuro ya no es lo que era\".', 'Paul Valéry (1871-1945); poeta y ensayista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (714, '\"Las circunstancias cambian la lógica\".', 'Jaime Luciano Balmes (1810-1848); filósofo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (715, '\"Sólo es capaz de realizar los sueños el que, cuando llega la hora, sabe estar despierto\".', 'León Daudí (1905-1985); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (716, '\"Los espejos se emplean para verse la cara; el arte para verse el alma\".', 'George Bernard Shaw (1856-1950); escritor irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (717, '\"Es extraña la ligereza con que los malvados creen que todo les saldrá bien\".', 'Víctor Hugo (1802-1885); poeta y novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (718, '\"Ocurra lo que ocurra, aún en el día más borrascoso las horas y el tiempo pasan\".', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (719, '\"Lo verdadero es demasiado sencillo, pero siempre se llega a ello por lo más complicado\".', 'Sand, George (1804-1876); escritora francesa.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (720, '\"En la práctica, sólo es problema lo que la inteligencia puede resolver\".', 'Keyserling, Hermann (1880-1946); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (721, '\"La verdad es una antorcha que luce entre la niebla, sin disiparla\".', 'Claude Adrien Helvetius (1715-1771); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (722, '\"Cada dogma tiene su día, pero los ideales son eternos\".', 'Israel Zangwill (1864-1926); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (723, '\"El valor es hijo de la prudencia, no de la temeridad\".', 'Pedro Calderón de la Barca (1600-1681); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (724, '\"En el punto donde se detiene la ciencia, empieza la imaginación\".', 'Jules de Gaultier (1811-1872); poeta, crítico y novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (725, '\"La ciencia es para el mundo moderno lo que el arte fue para el antiguo\".', 'Benjamin Disraeli (1766-1848); estadista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (726, '\"En el estudio no existe la saciedad\".', 'Erasmo de Rotterdam (1466-1536); humanista holandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (727, '\"La totalidad esta presente incluso en las piezas rotas\".', 'Aldous Huxley (1894-1963); novelista, ensayista, crítico y poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (728, '\"No puede haber gracia donde no hay discreción\".', 'Miguel de Cervantes Saavedra (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (729, '\"Lleva tiempo llegar a ser joven\".', 'Pablo Picasso (1881-1973); pintor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (730, '\"El hombre nada puede aprender sino en virtud de lo que sabe\".', 'Aristóteles (384-322 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (731, '\"El ser capaz de llenar el ocio de una manera inteligente\nes el último resultado de la civilización\".', 'Bertrand Russell (1872-1970); filósofo y matemático inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (732, '\"No hay nada más espantoso que la ignorancia activa\".', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (733, '\"La imaginación hace cuerpo de lo que es visión\".', 'Refrán español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (734, '\"La vida es como un arca inmensa llena de posibilidades\".', 'Amado Nervo (1870-1919); poeta, novelista y ensayista mexicano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (735, '\"La diligencia en escuchar es el más breve camino hacia la ciencia\".', 'Juan Luis Vives (1492-1540); humanista y filósofo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (736, '\"Si el tiempo es lo más caro, la pérdida de tiempo es el mayor de los derroches\".', 'Benjamín Franklin (1706-1790); estadista y científico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (737, '\"El entendimiento es una tabla lisa en la cual nada hay escrito\".', 'Aristóteles (384-322 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (738, '\"La ciencia más útil es aquella cuyo fruto es el más comunicable\".', 'Leonardo da Vinci (1452-1519); artista e inventor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (739, '\"El sol es nuevo cada día\".', 'Heráclito de Efeso (540 AC-470 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (740, '\"Sólo aquello que se ha ido es lo que nos pertenece\".', 'Jorge Luis Borges (1899-1986); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (741, '\"No se puede imitar lo que se quiere crear\".', 'Georges Braque (1882-1963); pintor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (742, '\"La primera vez que me engañes, será culpa tuya;\nla segunda vez, la culpa será mía\".', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (743, '\"La perfección es muerte; la imperfección es el arte\".', 'Manuel Vicent (1936); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (744, '\"No hay auténtico genio sin paciencia\".', 'Louis Charles Alfred de Musset (1810-1857); poeta francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (745, '\"La verdad existe. Sólo se inventa la mentira\".', 'Georges Braque (1882-1963); pintor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (746, '\"El pasado es un prólogo\".', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (747, '\"La inteligencia busca, pero quien encuentra es el corazón\".', 'Sand, George (1804-1876); escritora francesa.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (748, '\"No basta con alcanzar la sabiduría, es necesario saber utilizarla\".', 'Cicerón, Marcus Tullius Cicero (106-43 a. C.); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (749, '\"La risa es el sol que ahuyenta el invierno del rostro humano\".', 'Víctor Hugo (1802-1885); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (750, '\"Aquella teoría que no encuentre aplicación práctica en la vida\nes una acrobacia del pensamiento\".', 'Swami Vivekananda (1863-1902); líder espiritual y reformador hindú.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (751, '\"Ciencia sin seso, locura doble\".', 'Baltasar Gracián (1601-1658); jesuita y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (752, 'Con audacia se puede intentar todo, mas no conseguirlo todo.', 'Napoleón Bonaparte (1769-1821); Emperador de Francia.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (753, 'La gota horada la roca, no por su fuerza sino por su constancia.', 'Publio Ovidio (43 a.C.-17 d.C.); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (754, '\"La música es la voluptuosidad de la imaginación\".', 'Eugène Delacroix (1798-1863); pintor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (755, '\"Cuanto más numerosas son las cosas que quedan para aprender,\nmenos tiempo queda para hacerlas\".', 'Marcel Prévost (1862-1941); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (756, '\"Si buscas resultados distintos, no hagas siempre lo mismo\".', 'Einstein, Albert (1879-1955); físico y matemático.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (757, '\"Nada resiste tanto como lo provisional\".', 'André Maurois -seudónimo de Émile Herzog- (1885-1967); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (758, '\"Todo nuestro conocimiento arranca del sentido,  pasa al entendimiento y termina en la razón\".', 'Inmanuel Kant (1724-1804); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (759, '\"Si de algo soy rico es de perplejidades y no de certezas\".', 'Jorge Luis Borges (1899-1986); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (760, '\"El progreso no es un accidente, es una necesidad, una parte de la naturaleza\".', 'Herbert Spencer (1820-1903); escritor británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (761, '\"A veces, cuesta mucho más eliminar un solo defecto que adquirir cien virtudes\".', 'Jean de la Bruyere (1645-1696); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (762, 'La tragedia de la vejez no es ser viejo, sino haber sido joven.', 'Oscar Wilde (1854-1900); dramaturgo y novelista irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (763, 'La vida es fascinante: sólo hay que mirarla a través de las gafas correctas.', 'Alejandro Dumas (1802-1870); Escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (764, '\"Después de la verdad nada hay tan bello como la ficción\".', 'Machado, Antonio (1875-1939); poeta y prosista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (765, '\"La fortuna llega en algunos barcos que no son guiados\".', 'William Shakespeare (1564-1616); escritor británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (766, '\"El hombre sensato cree en el destino; el voluble en el azar\".', 'Benjamín Disraeli (1766-1848); estadista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (767, '\"La ignorancia es la madre de todos los crímenes\".', 'Honoré de Balzac (1799-1850); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (768, 'Felicidad no es hacer lo que uno quiere sino querer lo que uno hace.', 'Jean Paul Sartre (1905-1980); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (769, 'Ocurra lo que ocurra, aún en el día más borrascoso las horas y el tiempo pasan.', 'William Shakespeare (1564-1616); dramaturgo británico');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (770, 'Cada cual es como Dios le ha hecho, pero llega a ser como él mismo se hace.', 'Miguel Servet (1511-1553); médico y reformista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (771, '\"Si la razón hace al hombre, el sentimiento lo conduce\".', 'Jean Jacques Rousseau (1712-1778); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (772, '\"Lo que sabemos es una gota de agua; lo que ignoramos es el océano\".', 'Isaac Newton (1642-1727); físico y matemático inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (773, '\"La belleza perece en la vida, pero es inmortal en el arte\".', 'Leonardo Da Vinci (1452-1519); pintor, escultor e inventor italiano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (774, '\"La palabra es el arma de los humanos para aproximarse unos a otros\".', 'Ana María Matute (1926); escritora española.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (775, '\"Tiempo es la medida del movimiento entre dos instantes\".', 'Aristóteles (384 AC-322 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (776, '\"La inteligencia busca, pero quien encuentra es el corazón\".', 'George Sand (1804-1876); esritora francesa.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (777, '\"La recompensa de una buena acción está en haberla hecho\".', 'Lucio Anneo Séneca (2 a.C.-65 d.C.); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (778, '\"Procuremos más ser padres de nuestro porvenir', 'que hijos de nuestro pasado\".');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (779, '\"Lo que hace falta es someter a las circunstancias, no someterse a ellas\".', 'Quinto Horacio Flaco (65 a.C.-8 a.C.); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (780, '\"El tiempo es el mejor antologista, o el único, tal vez\".', 'Jorge Luis Borges (1899-1986); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (781, '\"La sabiduría es un adorno en la prosperidad y un refugio en la adversidad\".', 'Aristóteles (384 a.C.-322 a.C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (782, '\"Las cualidades sublimes infunden respeto; las bellas amor\".', 'Inmanuel Kant (1724-1804); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (783, '\"En el arte como en el amor la ternura es lo que da la fuerza\".', 'Oscar Wilde (1854-1900); dramaturgo y novelista irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (784, '\"Estando siempre dispuestos a ser felices, es inevitable no serlo alguna vez\".', 'Blaise Pascal (1623-1662); matemático francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (785, '\"No podemos hacer la historia, sino sólo esperar a que se desarrolle\".', 'Otto von Bismark (1815-1898); político alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (786, '\"La felicidad es tanto mayor cuanto menos la advertimos\".', 'Alberto Moravia (1907-1990); escritor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (787, '\"La originalidad es la vuelta a los orígenes\".', 'Antonio Gaudí i Cornet (1852-1926); arquitecto español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (788, '\"La imaginación es el ojo del alma\".', 'Joseph Joubert (1754-1824); moralista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (789, '\"Sin arte la vida sería un error\".', 'Friedrich Nietzsche (1844-1900); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (790, '\"Mi conciencia tiene para mí más peso que la opinión de todo el mundo\".', 'Marcus Tullius Ciceron (106-43 a. C.); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (791, '\"La confianza es madre del descuido\".', 'Baltasar Gracián (1601-1658); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (792, '\"La vida es fascinante: sólo hay que mirarla a través de las gafas correctas\".', 'Alejandro Dumas (1803-1870); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (793, '\"El fuego prueba el oro; la miseria los hombres fuertes\".', 'Lucio Anneo Séneca (2 a.C.-65 d.C.); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (794, '\"La única manera de ser seguido es correr más deprisa que los demás\".', 'Francis Picabia (1879-1953); pintor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (795, '\"Pon un gramo de audacia en todo lo que hagas\".', 'Baltasar Gracián (1601-1658); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (796, '\"Los espejos se emplean para verse la cara; el arte para verse el alma\".', 'George Bernard Shaw (1856-1950); escritor Irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (797, '\"Más vale una palabra a tiempo que cien a destiempo\".', 'Miguel de Cervantes Saavedra (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (798, '¡Triste época la nuestra! Es más fácil desintegrar un átomo que un prejuicio.', 'Albert Einstein.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (799, '\"Sabio es aquel que constantemente se maravilla\".', 'André Gide (1859-1951); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (800, '\"No basta con alcanzar la sabiduría, es necesario saber utilizarla\".', 'Marco Tulio Cicerón (106 a.C.-43 a.C.); escritor y político romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (801, '\"El elector goza del sagrado privilegio de votar\npor un candidato que eligieron otros\".', 'Ambrose Bierce (1842-1914); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (802, '\"¡Estudia! No para saber una cosa más, sino para saberla mejor\".', 'Lucio Anneo Séneca (2 a.C.-65 d.C.); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (803, '\"Quien no comprende una mirada tampoco comprenderá una larga explicación\".', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (804, '\"Las cosas se llaman equívocas cuando tan sólo tienen de común el nombre\".', 'Aristóteles (384 AC-322 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (805, '\"La rapidez que es una virtud, engendra un vicio, que es la prisa\".', 'Gregorio Marañón (1887-1960); médico español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (806, '\"En la escala de lo cósmico sólo lo fantástico tiene posibilidades de ser verdadero\".', 'Pierre Teilhard de Chardin (1881-1955); filósofo y teólogo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (807, '\"La paciencia es un árbol de raíz amarga pero de frutos muy dulces\".', 'Proverbio persa.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (808, '\"Una mirada hacia atrás vale más que una mirada hacia adelante\".', 'Arquímedes (¿285-212 a. C.); matemático, físico e inventor griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (809, '\"No hay inversión más rentable que la del conocimiento\".', 'Benjamín Franklin (1706-1790); estadista y científico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (810, '\"Yo no procuro conocer las preguntas; procuro conocer las respuestas\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (811, '\"Lo que llamamos casualidad no es ni puede ser\nsino la causa ignorada de un efecto desconocido\".', 'Voltaire -nacido François-Marie Arouet- (1694-1778); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (812, '\"La verdad es más importante que los hechos\".', 'Frank Lloyd Wright (1867-1959); arquitecto estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (813, '\"Si quieres que tu secreto sea guardado, guárdalo tú mismo\".', 'Lucio Anneo Séneca (2 a.C.-65 d.C.); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (814, '\"Existe algo más importante que la lógica: la imaginación\".', 'Anónimo');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (815, '\"Los hechos no dejan de existir aunque se los ignore\".', 'Aldous Huxley (1894-1963); novelista, ensayista, crítico y poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (816, '\"Azar es una palabra vacía de sentido, nada puede existir sin causa\".', 'Voltaire -nacido François-Marie Arouet- (1694-1778); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (817, 'En lo tocante a ciencia, la autoridad de un millar no es superior\nal humilde razonamiento de un hombre.', 'Galileo Galilei (1564-1642); astrónomo y físico italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (818, '\"El sabio puede cambiar de opinión. El necio, nunca\".', 'Inmanuel Kant (1724-1804); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (819, '\"El mejor modo de resolver una dificultad es no tratar de soslayarla\".', 'Noel Clarasó (1905-1985); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (820, '\"Sólo se aguanta una civilización si muchos aportan su colaboración al esfuerzo\".', 'José Ortega y Gasset (1883-1955); filósofo y ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (821, '\"La acción es el fruto propio del conocimiento\".', 'Thomas Fuller  (1610-1661); clérigo y escritor británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (822, '\"Prefiero los errores del entusiasmo a la indiferencia de la sabiduría\".', 'Anatole France (1844-1924); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (823, '\"Divide las dificultades que examinas en tantas partes\ncomo sea posible para su mejor solución\".', 'René Descartes (1596-1650); filósofo y matemático francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (824, '\"En el proceso de la escritura la imaginación y la memoria se confunden\".', 'Adelaida García Morales (1945); escritora española.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (825, '\"La creencia no es el principio, sino el fin de todo conocimiento\".', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (826, '\"Puede adquirirse todo en la sociedad, excepto el carácter\".', 'Marie Henri Beyle Stendhal (1783-1842); novelista y ensayista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (827, '\"En dos palabras puedo resumir cuanto he aprendido acerca de la vida: Sigue adelante\".', 'Robert Frost (1874-1963); poeta estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (828, '\"Una cosa es continuar la historia y otra repetirla\".', 'Jacinto Benavente (1866-1954); dramaturgo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (829, '\"Lo que no es útil para la colmena no es útil para la abeja\".', 'Marco Aurelio (121-180 d. C.); emperador y filósofo romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (830, '\"Si no quieres repetir el pasado, estúdialo\".', 'Baruch Benedict Spinoza (1632-1677); filósofo holandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (831, '\"Si ya sabes lo que tienes que hacer y no lo haces entonces estás peor que antes\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (832, '\"El tiempo saca a luz todo lo que está oculto y encubre y esconde\nlo que ahora brilla con el más grande esplendor\".', 'Horacio, Quintus Horatius Flaccus (65-8 a. C.); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (833, '\"La naturaleza nos ha dado las semillas del conocimiento, no el conocimiento mismo\".', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (834, '\"Una vez terminado el juego, el rey y el peón vuelven a la misma caja\".', 'Proverbio italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (835, '\"El verdadero modo de no saber nada es aprenderlo todo a la vez\".', 'George Sand (1804-1876); esritora francesa.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (836, '\"Es tan difícil verse a uno mismo como mirar para atrás sin volverse\".', 'Henry David Thoreau (1817-1862); escritor, poeta y pensador.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (837, '\"Puedo creer lo imposible pero no lo improbable\".', 'Gilbert Keith Chesterton (1874-1936); escritor británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (838, '\"El destino mezcla las cartas, y nosotros jugamos\".', 'Arthur Schopenhauer (1788-1860); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (839, '\"Existen en nosotros varias memorias. El cuerpo y el espíritu tienen cada uno la suya\".', 'Honoré de Balzac (1799-1850); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (840, '\"Si revelas tus secretos al viento, no le culpes por revelarlos a los árboles\".', 'Khalil Gibran (1883-1931); ensayista, novelista y poeta libanés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (841, '\"La verdad no hace tanto bien en el mundo como el daño que hacen sus apariencias\".', 'François de la Rochefoucauld (1613-1680); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (842, '\"Gracias a la memoria se da en los hombres lo que se llama experiencia\".', 'Aristóteles (384 AC-322 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (843, '\"El único medio de vencer en una guerra es evitarla\".', 'George Catlett Marshall (1880-1959); militar y político estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (844, '\"El tiempo es la sustancia de la que estoy hecho\".', 'Jorge Luis Borges (1899-1986); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (845, '\"No basta con alcanzar la sabiduría, es necesario saber utilizarla\".', 'Marco Tulio Cicerón (106 AC-43 a.C.); escritor y político romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (846, '\"Poca cosa nos consuela porque poca cosa nos aflige\".', 'Blaise Pascal (1623-1662); matemático francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (847, '\"Los satisfechos, los felices, no aman; se duermen en la costumbre\".', 'Miguel de Unamuno (1864-1936); filósofo y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (848, '\"La vida es la constante sorpresa de saber que existo\".', 'Rabindranath Tagore (1861-1941); filósofo y escritor indio.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (849, '\"Un país, una civilización se puede juzgar por la forma en que trata a sus animales\".', 'Mahatma Gandhi (1869-1948); político y pensador indio.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (850, '\"En la práctica, sólo es problema lo que la inteligencia puede resolver\".', 'Hermann Keyserling;(1880-1946); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (851, '\"Todos deseamos llegar a viejos; y todos negamos que hemos llegado\".', 'Francisco de Quevedo (1580-1645); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (852, '\"Una experiencia nunca es un fracaso,pues siempre viene a demostrar algo\".', 'Thomas Alva Edison (1847-1931); físico e inventor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (853, '\"El mejor fuego no es el que se enciende rápidamente\".', 'George Eliot (1819-1880); novelista británica.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (854, 'Puedes llegar a cualquier parte, siempre que andes lo suficiente.', 'Lewis Carrol (1832-1898); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (855, '\"Haz lo necesario para lograr tu más ardiente deseo, y acabarás lográndolo\".', 'Ludwig van Beethoven (1770-1827); músico alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (856, '\"La justicia te proporcionará paz, y también trabajos\".', 'Ramón Llull (1235-1315); filósofo y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (857, '\"La ventaja se la lleva aquel que aprovecha el momento oportuno\".', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (858, '\"El hombre cauto jamás deplora el mal presente;\nemplea el presente en prevenir las aflicciones futuras\".', 'Shakespeare, William (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (859, '\"Todas las cosas son imposibles, mientras lo parecen\".', 'Concepción Arenal (1820-1893); escritora y socióloga española.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (860, '\"Buscad leyendo y halláreis meditando\".', 'San Juan de la Cruz (1542-1591); teólogo y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (861, '\"Nunca se va tan lejos, como cuando no se sabe dónde se va\".', 'Oliver Cromwell (1599-1658); político inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (862, '\"La brevedad es hermana del talento\".', 'Anton Chejov (1860-1904); dramaturgo y autor de relatos ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (863, '\"No pretendas apagar con fuego un incendio, ni remediar con agua una inundación\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (864, '\"La riqueza consiste mucho más en el disfrute que en la posesión\".', 'Aristóteles (384 a.C.-322 a.C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (865, '\"La ciencia es como la tierra; sólo se puede poseer un poco de ella\".', 'Voltaire -nacido François-Marie Arouet- (1694-1778); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (866, '\"La ciencia es el gran antídoto contra el veneno del entusiasmo y la superstición\".', 'Adam Smith (1723-1790); filósofo y economista escocés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (867, '\"Todo idealismo frente a la necesidad es un engaño\".', 'Friedrich Nietzsche (1844-1900); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (868, '\"El tiempo es una cierta parte de la eternidad\".', 'Marco T. Cicerón (106 a. C.-43 a.C); escritor, orador y político romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (869, '\"Yo sólo sé que no sé nada\".', 'Sócrates (470 - 399 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (870, '\"La ciencia es orgullosa por lo mucho que ha aprendido;\nla sabiduría es humilde porque no sabe más\".', 'William Cowper (1731-1800); poeta británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (871, '\"En la naturaleza nada hay superfluo\".', 'Averroes (1126-1198); filósofo y médico hispanoárabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (872, '\"Los ríos más profundos son siempre los más silenciosos\".', 'Quintus Curtius Rufus (s. I d.C); historiador latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (873, '\"Lo más incomprensible del Universo es que sea comprensible\".', 'Einstein, Albert (1879-1955); físico y matemático.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (874, '\"Lo que está hecho no se puede deshacer\".', 'Shakespeare, William (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (875, '\"Seguir un sólo camino es retroceder\".', 'Igor Feodorovich Stravinsky (1882-1971); compositor ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (876, '\"Sólo le falta el tiempo a quien no sabe aprovecharlo\".', 'G. M. de Jovellanos (1744-1811); literato, economista y político español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (877, '\"En principio la investigación necesita más cabezas que medios\".', 'Severo Ochoa (1905-1993); bioquímico español, premio Nobel de Medicina.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (878, '\"Nada se sabe bien sino por medio de la experiencia\".', 'Sir Francis Bacon (1561-1626); filósofo y estadista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (879, '\"Todos los ríos van al mar, pero el mar no se desborda\".', 'Proverbio chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (880, '\"Después de la tempestad viene la calma\".', 'Refrán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (881, '\"Todas las cosas fingidas caen como flores marchitas,\nporque ninguna simulación puede durar largo tiempo\".', 'Marco T. Cicerón (106 a. C.-43 a.C); escritor, orador y político romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (882, '\"El que nunca cambia de opinión, nunca corrige sus errores,\nnunca será más sabio mañana de lo que lo es hoy\".', 'Tryon Edwards (1809-1895); escritor y lexicógrafo estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (883, '\"En tanto que haya alguien que crea en una idea, la idea vive\".', 'José Ortega y Gasset (1883-1955); filósofo y ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (884, '\"Confía en el tiempo, que suele dar dulces salidas a muchas amargas dificultades\".', 'Miguel de Cervantes (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (885, '\"Cuando hables, procura que tus palabras sean mejores que el silencio\".', 'Proverbio hindú.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (886, '\"La experiencia es un sabio hecho a trompicones\".', 'Ramón Campoamor (1817-1901); poeta español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (887, '\"Dadme un punto de apoyo y moveré el mundo\".', 'Arquímedes (¿285-212 a. C.); matemático, físico e inventor griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (888, 'A los hombres les encanta maravillarse. Esto es la semilla de la ciencia.', 'Ralph Waldo Emerson (1803-1882); filósofo y escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (889, '\"La verdad es hija del tiempo, no de la autoridad\".', 'Sir Francis Bacon (1561-1626); filósofo y estadista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (890, '\"La ciencia puede descubrir lo que es cierto, pero no lo que es bueno, justo y humano\".', 'Marcus Jacobson (1930-2001); neurocientífico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (891, '\"Si te caes siete veces, levántate ocho\".', 'Proverbio.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (892, '\"Quien volviendo a hacer el camino viejo aprende el nuevo, puede considerarse un maestro\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (893, '\"Cuanto más alto coloque el hombre su meta, tanto más crecerá\".', 'J. Christoph Friedrich von Schiller (1759-1805); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (894, '\"La ciencia se puede aprender de memoria, pero la sabiduría no\".', 'Lawrence Sterne (1713-1768); novelista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (895, '\"Si no chocamos contra la razón nunca llegaremos a nada\".', 'Albert Einstein (1879-1955); físico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (896, '\"Sólo es capaz de realizar los sueños el que, cuando llega la hora, sabe estar despierto\".', 'Leon Daudi(1905-1985); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (897, '\"El que no cree en la magia nunca la encontrará\".', 'Roald Dahl (1916-1990); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (898, '\"Una vez terminado el juego el rey y el peón vuelven a la misma caja\".', 'Proverbio italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (899, '\"Es especialmente duro predecir, sobre todo si se trata del futuro\".', 'Niels Henrik David Bohr (1885-1962); físico danés, premio Nobel.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (900, '\"Oír es precioso para el que escucha\".', 'Proverbio egipcio.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (901, '\"Considera las contrariedades como un ejercicio\".', 'Lucio Anneo Séneca (2 a.C.-65 d.C); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (902, '\"La naturaleza obra sin maestros\".', 'Hipócrates (460-377 a. de C.); médico griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (903, '\"No hay duda que todo conocimiento empieza con la experiencia\".', 'Inmanuel Kant (1724-1804); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (904, '\"De hombres es equivocarse; de locos persistir en el error\".', 'Marco Tulio Cicerón (106 a.C.-43 a.C.); escritor y político romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (905, '\"La verdadera ciencia enseña, sobre todo, a dudar y a ser ignorante\".', 'Ernest Rutherford (1871-1937); físico neozelandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (906, '\"La Historia Universal es la de un solo hombre\".', 'Jorge Luis Borges (1899-1986); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (907, '\"La imaginación es más importante que el conocimiento\".', 'Albert Einstein (1879-1955); físico y matemático.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (908, '\"Háblame para que yo te vea\".', 'Lucio Anneo Séneca (2 a.C.-65 d.C.); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (909, '\"Una tonelada de ciencia no vale más que una gota de sabiduría\".', 'Pitágoras (570-500 a. C.); filósofo y matemático griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (910, '\"No existen más que dos reglas para escribir: tener algo que decir y decirlo\".', 'Oscar Wilde (1854-1900); dramaturgo y novelista irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (911, '\"Pensar y obrar, obrar y pensar es la suma de toda sabiduría\".', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (912, '\"Quien daña el saber, homicida es de sí mismo\".', 'Pedro Calderón de la Barca (1600-1681); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (913, '\"Un problema deja de serlo si no tiene solución\".', 'Eduardo Mendoza (1943 - ); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (914, '\"Saber es saber que no sabes nada, ése es el significado de la verdadera sabiduría\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (915, '\"Todo gran avance en la Ciencia es el resultado de una nueva audacia de la imaginación\".', 'John Dewey (1859-1952); filósofo y educador estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (916, '\"Los imposibles de hoy serán posibles mañana\".', 'Konstantin Tsiolkovsky (1857-1935); inventor y científico ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (917, '\"Busca dentro de ti la solución de todos los problemas,\nhasta aquellos que creas más exteriores y materiales\".', 'Amado Nervo (1870-1919); escritor mexicano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (918, '\"Si estudio, no es por saber más, sino por ignorar menos\".', 'Anónimo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (919, '\"Solamente aquel que construye el futuro tiene derecho a juzgar el pasado\".', 'Friedrich Nietzsche (1844-1900); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (920, '\"No olvidemos jamás que lo bueno no se alcanza nunca sino por medio de lo mejor\".', 'Víctor Hugo (1802-1885); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (921, '\"Vale más actuar exponiéndose a arrepentirse de ello,  que arrepentirse de no haber hecho nada\".', 'Giovanni Boccaccio (1313-1375); escritor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (922, '\"Nunca se logra ningún beneficio sin perjudicar a otro\".', 'Michel Eyquem de la Montaigne (1533-1592); escritor y filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (923, '\"La casualidad favorece a las mentes entrenadas\".', 'William Thomson (1824-1907); físico y matemático británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (924, '¿Qué es nuestra imaginación comparada con la de un niño\nque intenta hacer un ferrocarril con espárragos?', 'Jules Renard (1864-1910); escritor y dramaturgo francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (925, '\"Cada frase que pronuncio no puede considerarse una afirmación sino una pregunta\".', 'Niels Bohr (1885-1962); físico danés, premio Nobel.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (926, '\"El agua es la mirada de la tierra, su aparato para contemplar el tiempo\".', 'George Menager (1868-1955); poeta y dramaturgo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (927, '\"No es en la ciencia que encontramos la felicidad, sino en su adquisición\".', 'Edgar Allan Poe (1809-1849); escritor, poeta y crítico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (928, '\"Un peligro previsto está medio abolido\".', 'William Shakespeare (1564-1616); dramaturgo británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (929, '\"El asunto es el problema; la forma la solución\".', 'Friedrich Hebbel (1813-1863); escritor alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (930, '\"Toda idea nueva pasa inevitablemente por tres fases: primero es ridícula,\ndespués es peligrosa, y después... ¡todos la sabían!\".', 'Henry George (1839-1897); economista estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (931, '\"Lo mucho se vuelve poco con sólo desear otro poco más\".', 'Francisco de Quevedo y Villegas (1580-1645). Escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (932, '\"No me digáis que este problema es difícil. Si no fuese difícil, no sería un problema\".', 'Ferdinand Foch (1851-1929); mariscal francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (933, '\"La experiencia es la enfermedad que ofrece el menor peligro de contagio\".', 'Oliverio Girondo 1891-1967); poeta argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (934, '\"Un hombre que comete un error y no lo corrige\nes propicio a cometer nuevamente el mismo error\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (935, '\"El arte es la firma de la civilización\".', 'Beverly Sills (1929 - ); cantante de ópera estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (936, '¿Para qué es oro el tiempo más que para verlo pasar acariciándolo?', 'Camilo José Cela (1916-2002); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (937, '\"Hay cuatro cosas que no pueden ser escondidas durante mucho tiempo:\nla ciencia, la estupidez, la riqueza y la pobreza\".', 'Averroes (1126-1198); filósofo y médico hispanoárabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (938, '\"Los niños hallan el todo en la nada; los hombres, la nada en el todo\".', 'Giacomo Leopardi(1798-1837); poeta italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (939, '\"El comercio mezcla a los hombres, pero no los une\".', 'Anónimo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (940, '\"La fe no es creer lo que no vimos, sino creer lo que no vemos\".', 'Miguel de Unamuno (1864-1936); filósofo y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (941, '\"La ciencia humana consiste más en destruir errores que en descubrir verdades\".', 'Sócrates (470 - 399 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (942, '\"Saber es acordarse\".', 'Aristóteles (384 a.C.-322 a.C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (943, '\"Los imposibles de hoy serán posibles mañana\".', 'Konstantin Tsiolkovsky (1857-1935); científico ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (944, '\"Tres clases hay de ignorancia: no saber lo que debiera saberse,\nsaber mal lo que se sabe, y saber lo que no debiera saberse\".', 'François de la Rochefoucauld (1613-1680); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (945, '\"Cuida de los pequeños gastos; un pequeño agujero hunde un barco\".', 'Benjamín Franklin (1706-1790); estadista y científico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (946, '\"El mal no está en tener faltas, sino en no tratar de enmendarlas\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (947, '\"Exagerar la fuerza es descubrir la debilidad\".', 'Madame de Girardin (1806-1881); poetisa francesa.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (948, '\"Si viéramos realmente el Universo, tal vez lo entenderíamos\".', 'Jorge Luis Borges (1899-1986); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (949, '\"Es intentando lo imposible como se realiza lo posible\".', 'Henri Barbusse (1873-1935); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (950, '\"El pasado siempre está presente\".', 'Maurice Maeterlinck (1862-1949); escritor belga.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (951, '\"Sorprenderse, extrañarse, es comenzar a entender\".', 'José Ortega y Gasset (1883-1955); filósofo y ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (952, '\"Razonar: sopesar probabilidades en la balanza del deseo\".', 'Ambrose Bierce (1842-1914); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (953, '\"El ejemplo es una lección que todos los hombres pueden leer\".', 'Morris West (1916-1999); escritor australiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (954, '\"No existe una mejor prueba del progreso de una civilización\nque la del progreso de la cooperación\".', 'John Stuart Mill (1806-1873); filósofo y economista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (955, '\"El sentido común es el instinto de la verdad\".', 'Max Jacobs (1876-1944); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (956, '\"La historia es la ciencia de lo que nunca sucede dos veces\".', 'Paul Ambroise Valéry (1871-1945); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (957, '\"No puedes enseñárselo todo: sólo puedes ayudarle a encontrarlo por sí mismo\".', 'Galileo Galilei (1564-1642); astrónomo y físico italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (958, '\"Lo peor que hacen los malos es obligarnos a dudar de los buenos\".', 'Jacinto Benavente (1866-1954); dramaturgo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (959, '\"Para la mayoría de los hombres, la experiencia es como las luces de\npopa de un barco, que iluminan sólo el camino que queda a la espalda\".', 'Samuel Taylor Coleridge (1772-1834); poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (960, '¿Qué puede haber imprevisto para el que nada ha previsto?', 'Paul Ambroise Valéry (1871-1945); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (961, '\"Incluso el pasado puede modificarse; los historiadores no paran de demostrarlo\".', 'Jean Paul Sartre (1905-1980); filósofo y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (962, '\"El mundo ha sido creado para ser recreado\".', 'Georges Duhamel (1884-1966); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (963, '\"Una cabeza sin memoria es como una fortaleza sin guarnición\".', 'Napoleón Bonaparte (1769-1821); emperador de Francia.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (964, '\"Escuchad el consejo del que mucho sabe; pero, sobre todo,\nescuchad el consejo de quien mucho os ama\".', 'Arturo Graf (1848-1913); escritor y poeta italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (965, '\"Comprender es el principio de aprobar\".', 'Baruch Benedict Spinoza (1632-1677); filósofo holandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (966, '\"Visión es el arte de ver las cosas invisibles\".', 'Jonathan Swift (1667-1745); político y escritor irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (967, '\"La realización conlleva la idea de que lo que sé es definitivo\".', 'Pierre Bonnard (1867-1947); pintor y artista gráfico francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (968, '\"El tiempo descubre la verdad\".', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo hispanolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (969, '\"La mitad de la alegría reside en hablar de ella\".', 'Proverbio persa.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (970, '\"El tiempo saca a luz todo lo que está oculto y encubre\ny esconde lo que ahora brilla con el más grande esplendor\".', 'Quinto Horacio Flaco (65 AC-8 AC); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (971, '\"El sabio sabe que ignora\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (972, '\"Los grandes conocimientos engendran las grandes dudas\".', 'Aristóteles (384 AC-322 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (973, '\"En el círculo se confunden el principio y el fin\".', 'Heráclito de Efeso (540 AC-470 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (974, '\"Lo mejor de la vida es el pasado, el presente y el futuro\".', 'Pier Paolo Pasolini (1922-1975); escritor y director de cine italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (975, '\"Quien no comprende una mirada tampoco comprenderá una larga explicación\".', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (976, '\"Nada perece en el universo; cuanto acontece en él no pasa de meras transformaciones\".', 'Pitágoras (570-500 a. C.); filósofo y matemático griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (977, '\"Saber para prever, a fin de poder\".', 'Auguste Comte (1798-1857); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (978, '\"El lenguaje es el vestido de los pensamientos\".', 'Samuel Johnson (1709-1784); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (979, '\"El pasado tiene sus códigos y costumbres\".', 'Sócrates (470 - 399 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (980, '\"Nada es constante en este mundo sino la inconstancia\".', 'Jonathan Swift (1667-1745); político y escritor irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (981, '\"No hay nada nuevo bajo el sol,\npero cuantas cosas viejas hay que no conocemos\".', 'Ambrose Bierce (1842-1914); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (982, '\"Las ciencias aplicadas no existen, sólo las aplicaciones de la ciencia\".', 'Louis Pasteur (1822-1895); químico y microbiólogo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (983, '\"El destino se ríe de las probabilidades\".', 'Edward George Bulwer-Lytton (1803-1873); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (984, '\"El mundo no fue hecho en el tiempo, sino con el tiempo\".', 'San Agustín (354-439); obispo y filósofo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (985, '\"Mientras haya libros no existe el pasado\".', 'Edward George Bulwer-Lytton (1803-1873); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (986, '\"Nuestro conocimiento es necesariamente finito,\nmientras que nuestra ignorancia es necesariamente infinita\".', 'Karl Raimund Popper (1902-1994); filósofo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (987, '\"Ciencia es todo aquello sobre lo cual siempre cabe discusión\".', 'José Ortega y Gasset (1883-1955); filósofo y ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (988, '\"Ver es creer, pero sentir es estar seguro\".', 'John Ray (1627-1705); naturalista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (989, '\"Jamás el esfuerzo desayuda la fortuna\".', 'Fernando de Rojas (1468-1542); autor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (990, '\"La conclusión es que sabemos muy poco\ny sin embargo es asombroso lo mucho que conocemos\".', 'Bertrand Russell (1872-1970); filósofo y matemático inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (991, '\"No perdamos nada del pasado. Sólo con el pasado se forma el porvenir\".', 'Anatole France (1844-1924); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (992, '\"Para saber hablar es preciso saber escuchar\".', 'Plutarco (50-125); escritor griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (993, '\"El mundo es la suma total de nuestras posibilidades vitales\".', 'José Ortega y Gasset (1883-1955); filósofo y ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (994, '\"Nuestra recompensa se encuentra en el esfuerzo y no en el resultado.\nUn esfuerzo total es una victoria completa\".', 'Mahatma Gandhi (1869-1948); político y pensador indio.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (995, '\"El cielo, el sol, los elementos, los hombres, han sido siempre los mismos\".', 'Nicolás Maquiavelo (1469-1527); político e historiador italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (996, '\"La ciencia es la progresiva aproximación del hombre al mundo real\".', 'Max Planck (1858-1947); físico alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (997, '\"El saber es la única propiedad que no puede perderse\".', 'Bías de Priene (siglo VI a. C.); uno de los siete sabios de Grecia.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (998, '\"Cuanto más se dividen los obstáculos son más fáciles de vencer\".', 'Concepción Arenal (1820-1893); escritora española.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (999, '\"El único error real es aquel del que no aprendemos nada\".', 'John Powell (1834-1902); geólogo y etnólogo estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1000, '\"Los conflictos existen siempre; no tratéis sólo de evitarlos, sino de entenderlos\".', 'Lin Yutang (1895-1976); escritora estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1001, '\"Cuanto más grande es el caos, más próxima está la solución\".', 'Mao Tse-Tung (1893-1976); político y estadista chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1002, '\"El pasado me ha revelado la estructura del futuro\".', 'Pierre Teilhard de Chardin (1881-1955); filósofo y teólogo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1003, '\"Es mucho mejor conocer algo acerca de todo, que acerca de una sola cosa.\nLo universal es siempre mejor\".', 'Blaise Pascal (1623-1662); científico y filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1004, '\"La respuesta más rápida es la acción\".', 'Proverbio americano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1005, '\"La perseverancia es convertir lo imposible en posible\".', 'Anónimo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1006, '\"En teoría, no existe diferencia entre teoría y práctica; en la práctica sí la hay\".', 'Jan L.A. van de Snepscheut; físico y matemático alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1007, '\"La verdad es hija del tiempo\".', 'Aulo Gelio (a. C. 130 - a. C. 200); historiador romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1008, '\"Así decía el hierro al imán: te odio porque me atraes\nsin que poseas fuerza suficiente para unirme a ti\".', 'Friedrich Nietzsche (1844-1900); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1009, '\"El universo está hecho de historias, no de átomos\".', 'Muriel Rukeyser (1913-1980); poetisa norteamericana.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1010, '\"Nuestra memoria no es más que una imagen de la realidad,\npor lo que nuestra realidad es sólo nuestra imaginación\".', 'Michael Ende (1929-1995); escritor alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1011, '\"La elocuencia es la pintura del pensamiento\".', 'Blaise Pascal (1623-1662); científico y filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1012, '\"La gran sabiduría, que mira lo lejano y lo cercano,\nno juzga poco lo pequeño, ni mucho lo grande\".', 'Lin Yutang (1895-1976); escritora estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1013, '\"Las ideas son capitales que sólo ganan intereses entre las manos del talento\".', 'Antoine Rivarol (1753-1810); literato y político francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1014, '\"El mejor consejo lo da siempre la experiencia, pero siempre llega demasiado tarde\".', 'Nicolas Amelot de la Houssaye (1634-1706); historiador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1015, '\"La verdad es eterna; el conocimiento, cambiante. Confundirlos resulta desastroso\".', 'Madeleine L\'Engle (1918- ); escritora estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1016, '\"No hay espejo que mejor refleje la imagen del hombre que sus palabras\".', 'Juan Luis Vives (1492-1540); humanista y filósofo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1017, '\"Los deseos de nuestra vida forman una cadena, cuyos eslabones son las esperanzas\".', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1018, '\"Los errores son inevitables. Lo que cuenta es cómo respondemos a ellos\".', 'Nikki Giovanni (1943- ); poetisa estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1019, 'Un experto es un hombre que ha cometido todos los errores posibles\nen un campo muy pequeño', 'Niels Bohr (1885-1962), científico danés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1020, '\"Es difícil decir que es imposible,\nporque el sueño de ayer es la esperanza de hoy y la realidad de mañana\".', 'Robert H. Goddard (1882-1945); físico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1021, 'Hay cuerdas en el corazón humano que es mejor no hacer vibrar', 'Charles Dickens (1812-1870), escirtor inglés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1022, '\"Prefiero que mi mente se abra movida por la curiosidad\na que se cierre movida por la convicción\".', 'Gerry Spence; abogado estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1023, '\"Prefiero los errores del entusiasmo a la indiferencia de la sabiduría\".', 'Anatole France (1844-1924); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1024, '\"Lo que se ignora, se desprecia\".', 'Antonio Machado (1875-1939); poeta y prosista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1025, '\"La naturaleza ha puesto en nuestras mentes un insaciable deseo de ver la verdad\".', 'Marco Tulio Cicerón (106 a.C. - 43 a.C.); escritor y político romano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1026, '\"Es extraña la ligereza con que los malvados creen que todo les saldrá bien\".', 'Victor Hugo (1802-1885); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1027, '\"Hay dos maneras de llegar al desastre: una, pedir lo imposible; otra, retrasar lo inevitable\".', 'Francisco Cambó (1876-1947); político y estadista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1028, '\"Los errores ajenos proporcionan los medios para descubrir la verdad\".', 'John Selden (1584-1654); político, jurista y orientalista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1029, '\"Todo es posible para aquel que lo considera tal\".', 'William Ellery Channing (1780-1842); teólogo estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1030, '\"Lo esperado no sucede, es lo inesperado lo que acontece\".', 'Eurípides (480-406 a. C.); poeta trágico griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1031, '\"No progresas mejorando lo que ya esta hecho,\nsino esforzándote por lograr lo que aún queda por hacer\".', 'Khalil Gibran (1883-1931); ensayista, novelista y poeta libanés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1032, '\"La memoria es el centinela del cerebro\".', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1033, '\"Si no te ha sorprendido nada extraño durante el día, es que no ha habido día\".', 'John Archibald; físico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1034, '\"Nada parece tan verdadero que no pueda parecer falso\".', 'Michel Eyquem de Montaigne (1533-1592); pensador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1035, '\"Lo importante no es escuchar lo que se dice, sino averiguar lo que se piensa\".', 'Juan Donoso Cortés (1809-1853); ensayista y diplomático español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1036, '\"Sólo se reconoce el error cuando todo el mundo lo comparte\".', 'Jean Giraudoux (1882-1944); dramaturgo y diplomático francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1037, '\"Después de la verdad nada hay tan bello como la ficción\".', 'Antonio Machado (1875-1939); poeta y prosista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1038, '\"Conversar es entrar en el surco que ha trazado el otro,\ny proseguir en el trazo y perfección de aquel surco\".', 'Massimo Bontempelli (1878-1960); escritor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1039, '\"La fantasía no es otra cosa que un modo de memoria emancipado del orden del tiempo\".', 'Samuel Taylor Coleridge (1772-1834); poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1040, '\"El pensamiento es la única cosa del Universo\nde la que no se puede negar su existencia: negar es pensar\".', 'José Ortega y Gasset (1883-1955); filósofo y ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1041, '\"Cree a aquellos que buscan la verdad, duda de los que la han encontrado\".', 'André Gide (1859-1951); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1042, '\"El cultivo de la memoria es tan necesario como el alimento para el cuerpo\".', 'Marco Tulio Cicerón (106 AC-43 a.C.); escritor y político romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1043, '\"No conocemos lo verdadero si ignoramos la causa\".', 'Aristóteles (384 AC-322 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1044, '\"No hay nada mas espantoso que la ignorancia activa\".', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1045, '\"La suerte es la sonrisa de lo desconocido\".', 'Etienne Rey (1727 - 1794); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1046, '\"La imaginación no es más que el aprovechamiento de lo que se tiene en la memoria\".', 'Pierre Bonnard (1867-1947); pintor y artista gráfico francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1047, '\"Cuando creíamos que teníamos todas las respuestas, de pronto, cambiaron todas las preguntas\".', 'Mario Benedetti (1920); escritor uruguayo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1048, '\"La única verdad es la realidad\".', 'Aristóteles (384 AC-322 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1049, '\"No hay oscuridad; sólo ignorancia\".', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1050, '\"El porvenir es un lugar cómodo para colocar los sueños\".', 'Anatole France (1844-1924); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1051, '\"La sabiduría, después de todo, no es otra cosa que la experiencia\".', 'Marun Abbud (1886-1962); crítico, literato y filósofo libanés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1052, '\"Es mucho mejor conocer algo acerca de todo, que acerca de una sola cosa.\nLo universal es siempre mejor\".', 'Blaise Pascal (1623-1662); científico y filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1053, '\"La historia es un incesante volver a empezar\".', 'Tucídides (c.471-395 a. C.); historiador griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1054, '\"Son los problemas sin resolver, no los resueltos, los que mantienen activa la mente\".', 'Erwin Guido Kolbenheyer (1878-1962); escritor alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1055, '\"La verdad en un tiempo es error en otro\".', 'Charles-L. de Secondat Montesquieu (1689-1755); escritor y filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1056, '\"Conocer es recordar\".', 'Platón (c.428 - c.347 a. C.), filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1057, '\"Haríamos muchas más cosas si creyéramos que son muchas menos las imposibles\".', 'Guillaume de Lamoignan de Malesherbes (1721-1794); político francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1058, '\"Estar preparado es importante, saber esperar lo es aún más,\npero aprovechar el momento adecuado es la clave de la vida\".', 'Arthur Schnitzler (1862-1931); dramaturgo austríaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1059, '\"Antes las distancias eran mayores porque el espacio se mide por el tiempo\".', 'Jorge Luis Borges (1899-1986); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1060, '\"La experiencia no consiste en lo que se ha vivido, sino en lo que se ha reflexionado\".', 'José María de Pereda (1833-1906); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1061, '\"El sabio consigue más ventajas por sus enemigos que el necio por sus amigos\".', 'Benjamín Franklin (1706-1790); estadista y científico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1062, '\"La ciencia y la sabiduría, lejos de ser una misma cosa,\nno tienen entre sí a menudo conexión alguna\".', 'William Cowper (1731-1800); poeta británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1063, '\"Puedes acariciar a la gente con palabras\".', 'Francis Scott Fitzgerald (1896-1940); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1064, '\"Si no esperas lo inesperado no lo reconocerás cuando llegue\".', 'Heráclito de Efeso (540 AC-470 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1065, '\"La verdadera ciencia enseña, por encima de todo, a dudar y a ser ignorante\".', 'Miguel de Unamuno (1864-1936); filósofo y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1066, '\"Pensar contra la corriente del tiempo es heroico; decirlo, una locura\".', 'Eugene Ionesco (1912-1994); dramaturgo francés de origen rumano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1067, '\"Por los defectos de los demás el sabio corrige los propios\".', 'Publio Siro (Siglo I a. C.); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1068, '\"Los males previstos resultan menores\".', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1069, '\"He ofendido a Dios y a la humanidad porque mi trabajo\nno tuvo la calidad que debía haber tenido\".', 'Leonardo Da Vinci (1452-1519); pintor, escultor e inventor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1070, '\"En los muros del tiempo trabajamos todos\ncomo arquitectos de nuestro propio destino\".', 'Orison Swett Marden (1853-1924); escritor y moralista estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1071, '\"Mil cosas avanzan. Novecientas noventa y nueve retroceden. Esto es el progreso\".', 'Henri Frédéric Amiel (1821-1881); escritor y profesor suizo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1072, '\"De todos los peligros, el mayor es subestimar al enemigo\".', 'Pearl S. Buck (1892-1973), novelista estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1073, '\"Si al pleno acierto aspiras, une la utilidad con el deleite\".', 'Tomás de Iriarte (1750-1791); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1074, '\"En la prosperidad modérate; en la adversidad resígnate y sé siempre prudente\".', 'Periandro de Corinto (s. VII-VI a.C.); uno de los Siete Sabios de Grecia.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1075, '\"Todas las cosas son en sí contradictorias\".', 'Georg Wilhelm Friedrich Hegel (1770-1831); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1076, '\"El papel de la ciencia es producir economía de pensamiento,\ncomo la máquina ahorra economía de fuerza\".', 'Henri Poincaré (1854-1912); matemático francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1077, '\"Los historiadores son personas que se interesan por el futuro cuando éste ya es pasado\".', 'Graham Greene (1904-1991); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1078, '\"Para prevenidos no hay acasos\".', 'Baltasar Gracián (1601-1658); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1079, '\"El cambio es la única cosa inmutable\".', 'Arthur Schopenhauer (1788-1860); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1080, '\"Una experiencia nunca es un fracaso, pues siempre viene a demostrar algo\".', 'Thomas Alva Edison (1847-1931); físico e inventor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1081, '\"Lo inevitable rara vez sucede, es lo inesperado lo que suele ocurrir\".', 'John Maynard Keynes (1883-1946); economista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1082, '\"Creer posible algo es hacerlo cierto\".', 'Christian Friedrich Hebbel (1813-1863); poeta y autor dramático alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1083, '\"El hombre es la suma de sus fantasías\".', 'Henry James (1843-1916); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1084, '\"No hay daño tan grande como el del tiempo perdido\".', 'Miguel Ángel Buonarroti(1475-1564); arquitecto, escultor y pintor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1085, '\"Cuanto más se lee, menos se imita\".', 'Jules Renard (1864-1910); escritor y dramaturgo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1086, '\"La evolución no es una fuerza, sino un progreso; no una causa, sino una ley\".', 'Vizconde de Blackburn, John Morley (1838-1923); estadista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1087, '\"El error es una hoja garabateada que primero hay que borrar\".', 'Charles Caleb Colton (1780-1832); poeta y ensayista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1088, '\"El grado sumo del saber es contemplar el por qué\".', 'Sócrates (470 - 399 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1089, '\"Donde una puerta se cierra, otra se abre\".', 'Miguel de Cervantes (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1090, '\"Si conociéramos el verdadero fondo de todo tendríamos\ncompasión hasta de las estrellas\".', 'Graham Greene (1904-1991); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1091, '\"Lo que hace falta es someter a las circunstancias, no someterse a ellas\".', 'Quinto Horacio Flaco (65 a.c.- 8 a.c.); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1092, '\"No encuentres la falta, encuentra el remedio\".', 'Henry Ford (1863-1947); industrial estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1093, '\"Cuando me dicen que soy demasiado viejo para hacer una cosa,\nprocuro hacerla enseguida\".', 'Pablo Picasso (1881-1973); pintor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1094, '\"La historia es una filosofía en ejemplos\".', 'Dionisio de Halicarnaso (60 a. C.-10 d. C.); historiador griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1095, '\"La ventaja se la lleva aquel que aprovecha el momento oportuno\".', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1096, '\"La habilidad y la constancia son las armas de la debilidad\".', 'Nicolás Maquiavelo (1469 - 1527); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1097, '\"Lo que no se parece a nada no existe\".', 'Paul Valéry (1871-1945); poeta y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1098, '\"En lo pasado está la historia del futuro\".', 'Juan Donoso Cortés (1809-1853); ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1099, '\"Todos los ríos van al mar, pero el mar no se desborda\".', 'Proverbio chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1100, '\"Lo peor que hacen los malos es obligarnos a dudar de los buenos\".', 'Jacinto Benavente (1866-1954); dramaturgo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1101, '\"El sabio puede sentarse en un hormiguero, pero sólo el necio se queda sentado en él\".', 'Proverbio chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1102, '\"Muchas cosas hay portentosas, pero ninguna como el hombre.\nTiene recursos para todo; sólo la muerte no ha conseguido evitar\".', 'Sófocles (495 a. C - 406 a. C.); poeta trágico griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1103, '\"Lo que no sé, tampoco creo saberlo\".', 'Platón (427-347 a.C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1104, '\"¿Qué sabe el pez del agua donde nada toda su vida?\".', 'Albert Einstein (1879-1955); físico y matemático.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1105, '\"Lo pasado ha huido, lo que esperas está ausente, pero el presente es tuyo\".', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1106, '\"El futuro está oculto detrás de los hombres que lo hacen\".', 'Anatole France (1844-1924); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1107, '\"La música es la aritmética de los sonidos, como la óptica es la geometría de la luz\".', 'Claude Debussy (1862-1918); compositor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1108, '\"La felicidad no está en la ciencia, sino en la adquisición de la ciencia\".', 'Edgar Allan Poe (1809-1849); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1109, '\"Oír o leer sin reflexionar es una ocupación inútil\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1110, '\"El conocimiento teórico es un tesoro cuya clave es la práctica\".', 'Thomas Fuller (1609-1661); clérigo y escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1111, '\"Imputar la revolución a los hombres es imputar la marea a las olas\".', 'Victor Hugo (1802-1885); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1112, '\"Un libro es como un jardín que se lleva en el bolsillo\".', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1113, '\"Generalizar siempre es equivocarse\".', 'Hermann A. Von Keyserling (1880-1946); filósofo y científico alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1114, '\"Yo no procuro conocer las preguntas; procuro conocer las respuestas\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1115, '\"Un ejército de ciervos dirigido por un león es mucho más temible\nque un ejército de leones mandado por un ciervo\".', 'Plutarco (50-125); escritor griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1116, '\"No sabe más el que más cosas sabe, sino el que sabe las que más importan\".', 'Bernardino Rebolledo (1597-1676); militar, poeta y diplomático español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1117, '\"La verdadera sabiduría está en reconocer la propia ignorancia\".', 'Sócrates (470 - 399 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1118, '\"La sorpresa es el móvil de cada descubrimiento\".', 'Cesare Pavese (1908-1950); poeta y novelista italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1119, '\"Sólo aquello que se ha ido es lo que nos pertenece\".', 'Jorge Luis Borges (1899-1986); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1120, '\"Con el conocimiento se acrecientan las dudas\".', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1121, '\"Excava el pozo antes de que tengas sed\".', 'Proverbio chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1122, '\"La ciencia consiste en sustituir el saber que parecía seguro\npor una teoría, o sea, por algo problemático\".', 'José Ortega y Gasset (1883-1955); filósofo y ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1123, '\"La totalidad esta presente incluso en las piezas rotas\".', 'Aldous Huxley (1894-1963); novelista, ensayista, crítico y poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1124, '\"Prefiero el bastón de la experiencia que el carro rápido de la fortuna.\nEl filósofo viaja a pie\".', 'Pitágoras de Samos (582 AC-497 AC); filósofo y matemático griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1125, '\"La fantasía, aislada de la razón, sólo produce monstruos imposibles.\nUnida a ella, en cambio, es la madre del arte y fuente de sus deseos\".', 'Francisco de Goya y Lucientes (1746- 1828); pintor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1126, '\"La verdad es hija del tiempo, no de la autoridad\".', 'Sir Francis Bacon (1561-1626); filósofo y estadista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1127, '\"La verdadera causa final reside en los seres inmóviles\".', 'Aristóteles (384 AC-322 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1128, '\"El cambio es la única cosa en el universo que no cambia\".', 'Helmuth Wilhem; científico alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1129, '\"Los problemas son oportunidades para demostrar lo que se sabe\".', 'Duke Ellington (1899-1974); compositor y músico de jazz estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1130, '\"Cuando no sopla el viento, incluso la veleta tiene carácter\".', 'Stanislaw Jerzy Lec (1909-1966); escritor polaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1131, '\"A los que corren en un laberinto, su misma velocidad los confunde\".', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1132, '\"Los conceptos están incluidos en las palabras\".', 'Henri Bergson (1859-1941); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1133, '\"Vivir en la Tierra es caro, pero incluye un viaje gratis alrededor del sol cada año\".', 'Anónimo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1134, '\"La contemplación es un lujo, mientras que la acción es una necesidad\".', 'Henri Bergson (1859-1941); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1135, '\"La ciencia se compone de errores, que a su vez, son los pasos hacia la verdad\".', 'Julio Verne (1828-1905); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1136, '\"No basta tener buen ingenio; lo principal es aplicarlo bien\".', 'René Descartes (1596-1650); filósofo y matemático francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1137, '\"Existe un lenguaje que va más allá de las palabras\".', 'Paulo Coelho (1947); escritor brasileño.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1138, '\"Es preciso elevarse con las alas del entusiasmo. Si se razona, no se volará jamás\".', 'Anatole France (1844-1924); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1139, '\"La escritura es la pintura de la voz\".', 'Voltaire -nacido François-Marie Arouet- (1694-1778); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1140, '\"El tiempo es una cierta parte de la eternidad\".', 'Marco Tulio Cicerón (106 AC - 43 AC); escritor, orador y político romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1141, '\"El mundo real es mucho más pequeño que el mundo de la imaginación\".', 'Friedrich Nietzsche (1844-1900); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1142, '\"No nos atrevemos a muchas cosas porque son difíciles,\npero son difíciles porque no nos atrevemos a hacerlas\".', 'Lucio Anneo Séneca (2 a.C - 65 d.C.); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1143, '\"Una vez terminado el juego, el rey y el peón vuelven a la misma caja\".', 'Proverbio italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1144, '\"Todos los asuntos tienen dos asas: por una son manejables, por la otra no\".', 'Epicteto de Frigia (50-135); filósofo grecolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1145, '\"La vida es fascinante: sólo hay que mirarla a través de las gafas correctas\".', 'Alejandro Dumas (1803-1870); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1146, '\"Componer no es difícil, lo complicado es dejar caer bajo la mesa las notas superfluas\".', 'Johannes Brahms(1833-1897); compositor alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1147, '\"La ocasión hay que crearla, no esperar a que llegue\".', 'Sir Francis Bacon (1561-1626); filósofo y estadista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1148, '\"Cada vez que cometo un error me parece descubrir una verdad que no conocía\".', 'Maurice Maeterlinck (1862-1949); escritor belga.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1149, '\"Cuando era más joven podía recordar todo, hubiera sucedido o no\".', 'Mark Twain (1835-1910); escritor y periodista estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1150, '\"En la naturaleza están todos los estilos futuros\".', 'Auguste Rodin (1840-1917); escultor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1151, '\"La música es la voz armoniosa de la creación; un eco del mundo invisible\".', 'Giuseppe Mazzini (1805-1872); político italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1152, '\"Un barco no debería navegar con una sola ancla, ni la vida con una sola esperanza\".', 'Epicteto de Frigia (50-135); filósofo grecolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1153, '\"Todo cambia, nada es\".', 'Heráclito (c.544-480 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1154, '\"Sírvete de lo aparente como indicio de lo inaparente\".', 'Solón de Atenas (640 a.C.-558 a.C.); legislador griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1155, '\"La creencia no es el principio, sino el fin de todo conocimiento\".', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1156, '\"Nueve décimas partes de la sabiduría provienen de ser juicioso a tiempo\".', 'Henry David Thoreau (1817-1862); escritor, poeta y pensador.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1157, '\"Planear: preocuparse por encontrar el mejor método para lograr un resultado accidental\".', 'Ambrose Bierce (1842-1914); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1158, '\"Vivimos bajo el mismo cielo, pero ninguno tenemos el mismo horizonte\".', 'Konrad Adenauer (1876-1967); político alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1159, '\"El único símbolo de superioridad que conozco es la bondad\".', 'Ludwig van Beethoven (1770-1827); compositor alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1160, '\"La pintura es mas fuerte que yo, siempre consigue que haga lo que ella quiere\".', 'Pablo Picasso (1881-1973); pintor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1161, '\"La finalidad del arte es dar cuerpo a la esencia secreta de las cosas, no el copiar su apariencia\".', 'Aristóteles (384 a.C.-322 a.C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1162, '\"La duda es uno de los nombres de la inteligencia\".', 'Jorge Luis Borges (1899-1986); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1163, '\"A fuerza de construir bien, se llega a buen arquitecto\".', 'Aristóteles (384 a.C.-322 a.C.); filósofo griego');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1164, '\"Los hombres sabios aprenden mucho de sus enemigos\".', 'Aristófanes (444 a.C.-385 a.C.); dramaturgo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1165, '\"El hombre se complace en enumerar sus pesares, pero no enumera sus alegrías\".', 'Fiodor M. Dostoiewsky (1821-1881); novelista ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1166, '\"A los hombres les encanta maravillarse. Esto es la semilla de la ciencia\".', 'Ralph Waldo Emerson (1803-1882); poeta estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1167, '\"El lenguaje es el vestido de los pensamientos\".', 'Samuel Johnson (1709-1784); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1168, '\"El gran libro de la naturaleza está escrito en símbolos matemáticos\".', 'Galileo Galilei (1564-1642); astrónomo italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1169, '\"Nada se sabe bien sino por medio de la experiencia\".', 'Sir Francis Bacon (1561-1626); filósofo y estadista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1170, '\"Absurdo sería pedir al cálculo lo que puede dar la abnegación\".', 'Concepción Arenal (1820-1893); escritora española.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1171, '\"La ignorancia afirma o niega rotundamente; la ciencia duda\".', 'Voltaire -nacido François-Marie Arouet- (1694-1778); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1172, '\"Agua pasada no mueve molinos\".', 'Refrán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1173, '\"Somos engañados por la apariencia de la verdad\".', 'Quinto Horacio Flaco (65 AC-8 AC); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1174, '\"No se desea lo que no se conoce\".', 'Publio Ovidio Nasón (43 AC-17 DC); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1175, '\"Actúa siempre con acierto. Esto tranquilizará a algunas personas y asombrará al resto\".', 'Mark Twain (1835-1910); escritor y periodista estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1176, '\"Nadie cambia si no siente la necesidad de hacerlo\".', 'Henry Ford (1863-1947); industrial estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1177, '\"La sabiduría es un tesoro que nunca causa entorpecimientos\".', 'Jean de la Fontaine (1621-1695); poeta y fabulista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1178, '\"El tiempo no es sino la corriente en la que estoy pescando\".', 'Henry David Thoreau (1817-1862); escritor, poeta y pensador.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1179, '\"El valor de un acto se juzga por su oportunidad\".', 'Lao-Tse (604 AC-531 AC); filósofo del Taoísmo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1180, '\"Ningún ejército puede detener la fuerza de una idea cuando llega a tiempo\".', 'Víctor Hugo (1802-1885); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1181, '\"El que no pueda guardar sus pensamientos, jamás sabrá analizar grandes cosas\".', 'Thomas Carlyle (1795-1881); historiador, pensador y ensayista escocés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1182, '\"Divide las dificultades que examinas en tantas partes\ncomo sea posible para su mejor solución\".', 'René Descartes (1596-1650); filósofo y matemático francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1183, '\"Ningún descubrimiento se haría ya si nos contentásemos con lo que sabemos\".', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1184, '\"Si viéramos realmente el Universo, tal vez lo entenderíamos\".', 'Jorge Luis Borges (1899-1986); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1185, '\"Terrible es el error cuando usurpa el nombre de la ciencia\".', 'Jaime Luciano Balmes (1810-1848); filósofo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1186, 'Nadie se ha perdido aún en un camino recto.', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1187, '\"El presente es la viviente suma total del pasado\".', 'Thomas Carlyle (1795-1881); historiador, pensador y ensayista escocés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1188, 'Libros, caminos y días dan al hombre sabiduría.', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1189, '\"La arena del desierto es para el viajero fatigado\nlo mismo que la conversación incesante para el amante del silencio\".', 'Proverbio persa.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1190, '\"Es más fácil negar las cosas que enterarse de ellas\".', 'Mariano Jose de Larra (1809-1837); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1191, '\"Mi memoria es magnífica para olvidar\".', 'Robert Louis Stevenson (1850-1894); escritor británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1192, '\"Para ver claro, basta con cambiar la dirección de la mirada\".', 'Antoine de Saint-Exupery (1900-1944); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1193, '\"Yo sólo sé que no sé nada\".', 'Sócrates (470 - 399 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1194, '\"Quien da primero, da dos veces\".', 'Refrán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1195, '\"Creo para comprender, y comprendo para creer mejor\".', 'San Agustín (354-439); obispo y filósofo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1196, '\"Con audacia se puede intentar todo, mas no conseguirlo todo\".', 'Napoleón Bonaparte (1769-1821); emperador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1197, '\"Un libro es como un jardín que se lleva en el bolsillo\".', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1198, '\"La patria del escritor es su lengua\".', 'Francisco Ayala (1906); narrador y crítico español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1199, '\"Si lo que vas a decir no es más bello que el silencio: no lo digas\".', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1200, '\"Lleva tiempo llegar a ser joven\".', 'Pablo Picasso (1881-1973); pintor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1201, '\"No basta con oír la música; además hay que verla\".', 'Igor Stravinski (1882-1971); compositor ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1202, '\"El que tiene imaginación sin instrucción tiene alas sin pies\".', 'Joseph Joubert (1754-1824); moralista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1203, '\"La ciencia es la estética de la inteligencia\".', 'Gastón Bachelard (1884-1962); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1204, '\"Cuando fuiste martillo no tuviste clemencia, ahora que eres yunque, ten paciencia\".', 'Refrán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1205, '\"Sorprenderse, extrañarse, es comenzar a entender\".', 'José Ortega y Gasset (1883-1955); filósofo y ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1206, '\"Puedo creer lo imposible pero no lo improbable\".', 'Gilbert Keith Chesterton (1874-1936); escritor británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1207, '\"Añorar el pasado es correr tras el viento\".', 'Proverbio ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1208, '\"Nunca creí que pudiéramos transformar el mundo,\npero creo que todos los días se pueden transformar las cosas\".', 'Françoise Giroud (1916-2003); periodista y escritora francesa.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1209, '\"Comprender es el principio de aprobar\".', 'Baruch Benedict Spinoza (1632-1677); filósofo holandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1210, '\"No hay ningún viento favorable para el que no sabe a qué puerto se dirige\".', 'Arthur Schopenhauer (1788-1860); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1211, '\"El tiempo es el ángel del hombre\".', 'Johann C. Friedrich von Schiller (1759-1805); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1212, '\"Inspiración y genio son casi la misma cosa\".', 'Víctor Hugo (1802-1885); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1213, '\"La única ventaja de jugar con fuego es que aprende uno a no quemarse\".', 'Oscar Wilde (1854-1900); dramaturgo y novelista irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1214, '\"Los años enseñan muchas cosas que los días jamás llegan a conocer\".', 'Ralph Waldo Emerson (1803-1882); poeta estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1215, '\"Culto es aquel que sabe dónde encontrar lo que no sabe\".', 'Georg Georg Simmel (1858-1918); sociólogo y filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1216, '\"La desconfianza es madre de la seguridad\".', 'Aristófanes (444 a.C.-385 a.C.); dramaturgo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1217, '\"El sol es nuevo cada día\".', 'Heráclito de Efeso (540 AC-470 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1218, '\"No es el tiempo lo que se os da, sino el instante.\nCon un instante dado, a nosotros nos corresponde hacer el tiempo\".', 'Georges Poulet (1902-1991); escritor belga.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1219, '\"La unidad es la variedad, y la variedad en la unidad es la ley suprema del universo\".', 'Isaac Newton (1643-1727); matemático inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1220, '\"La experiencia no consiste en lo que se ha vivido, sino en lo que se ha reflexionado\".', 'José María de Pereda (1833-1906); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1221, '\"Las grandes naciones escriben sus autobiografías en tres manuscritos:\nel libro de los hechos, el libro de las palabras y el libro del arte\".', 'John Ruskin (1819-1900); crítico y escritor británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1222, '\"Los conceptos y principios fundamentales de la ciencia\nson invenciones libres del espíritu humano\".', 'Albert Einstein (1879-1955); físico y matemático.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1223, '\"Lo que es creado por el espíritu es más vivo que la materia\".', 'Charles Baudelaire (1821-1867); poeta francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1224, '\"Procuremos más ser padres de nuestro porvenir que hijos de nuestro pasado\".', 'Miguel de Unamuno (1864-1936); filósofo y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1225, '\"La magia es un puente que te permite ir del mundo visible\nhacia el invisible. Y aprender las lecciones de ambos mundos\".', 'Paulo Coelho (1947); escritor brasileño.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1226, '\"Todas las cosas son imposibles, mientras lo parecen\".', 'Concepción Arenal (1820-1893); escritora y socióloga española.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1227, '\"El mundo ha sido creado para ser recreado\".', 'Georges Duhamel (1884-1966); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1228, '\"El asunto es el problema; la forma, la solución\".', 'Christian Friedrich Hebbel (1813-1863); poeta y autor dramático alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1229, '\"El sabio no dice todo lo que piensa, pero siempre piensa todo lo que dice\".', 'Aristóteles (384 AC-322 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1230, '\"La incertidumbre es una margarita cuyos pétalos no se terminan jamás de deshojar\".', 'Mario Vargas Llosa (1936); escritor peruano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1231, 'El tiempo es el ángel del hombre.', 'Johann Christoph F. von Schiller (1759-1805); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1232, '\"Buscando las cosas inciertas, perdemos las ciertas\".', 'Plauto (c. 254-184 a.C.); comediógrafo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1233, '\"La duda es la madre del descubrimiento\".', 'Ambrose Bierce (1842-1914); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1234, '\"Los ejemplos son diez veces más útiles que los preceptos\".', 'Charles James Fox (1749-1806); estadista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1235, '\"Hay que guardarse bien de un agua silenciosa,\nde un perro silencioso y de un enemigo silencioso\".', 'Proverbio judío.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1236, '\"En el punto donde se detiene la ciencia, empieza la imaginación\".', 'Jules de Gaultier (1811-1872); poeta, crítico y novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1237, '\"El pasado es un prólogo\".', 'William Shakespeare (1564-1616); escritor británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1238, '\"Para investigar la verdad es preciso dudar, en cuanto sea posible, de todas las cosas\".', 'René Descartes (1596-1650); filósofo y matemático francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1239, '\"El que confía sus secretos a otro hombre se hace esclavo de él\".', 'Baltasar Gracián (1601-1658); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1240, '\"Uno no es lo que es por lo que escribe, sino por lo que ha leído\".', 'Jorge Luis Borges (1899-1986); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1241, '\"Ningún hombre es una isla, algo completo en sí mismo;\ntodo hombre es un fragmento del continente, una parte de un conjunto\".', 'John Donne (1572-1631); poeta y prosista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1242, '\"Lo que sucede hoy acaeció otras veces; lo que se dice, sigue diciéndose\ny se dirá más adelante; lo que ha de ser, ya fue un día\".', 'Antonio Francesco Doni (1513-1574); escritor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1243, '\"La imaginación es el ojo del alma\".', 'Joseph Joubert (1754-1824); moralista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1244, '\"El espíritu humano avanza de continuo, pero siempre en espiral\".', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1245, '\"La diligencia en escuchar es el más breve camino hacia la ciencia\".', 'Juan Luis Vives (1492-1540); humanista y filósofo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1246, '\"El valor es hijo de la prudencia, no de la temeridad\".', 'Pedro Calderón de la Barca (1600-1681); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1247, '\"No hay ninguna cosa buena que no tenga su base en la razón\".', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1248, '\"La verdad es más importante que los hechos\".', 'Frank Lloyd Wright (1867-1959); arquitecto estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1249, '\"El arte es un compendio de la naturaleza formado por la imaginación\".', 'José María Eça de Queiroz (1845-1900); novelista portugués.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1250, '\"Hablar es el arte de sofocar e interrumpir el pensamiento\".', 'Thomas Carlyle (1795-1881); historiador, pensador y ensayista escocés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1251, '\"No hace falta conocer el peligro para tener miedo; de hecho,\nlos peligros desconocidos son los que inspiran más temor\".', 'Alejandro Dumas (1803-1870); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1252, '\"Largo es el camino de la enseñanza por medio de teorías;\nbreve y eficaz por medio de ejemplos\".', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1253, '\"El error es un arma que acaba siempre por dispararse contra el que la emplea\".', 'Concepción Arenal (1820-1893); escritora y socióloga española.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1254, '\"La soledad es muy hermosa... cuando se tiene alguien a quien decírselo\".', 'Gustavo Adolfo Bécquer (1836-1870); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1255, '\"La sabiduría suprema es tener sueños bastante grandes\npara no perderlos de vista mientras se persiguen\".', 'William Faulkner (1897-1962); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1256, '\"Todos desean saber, pero pocos pagar el trabajo que vale\".', 'Decimus Junius Juvenal (67-127); poeta satírico romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1257, '\"Un libro hermoso es una victoria ganada en todos los campos\nde batalla del pensamiento humano\".', 'Honoré de Balzac (1799-1850); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1258, '\"La inspiración es la ocasión del genio\".', 'Honoré de Balzac (1799-1850); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1259, '\"La primera obligación de la inteligencia es desconfiar de ella misma\".', 'Stanislaw Jerzy Lec (1909-1966); escritor polaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1260, '\"El instante es la continuidad del tiempo, pues une el tiempo pasado con el tiempo futuro\".', 'Aristóteles (384 a.C-322 a.C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1261, '\"No perdáis una hora, porque no estáis seguros de un minuto\".', 'Benjamin Franklin (1706-1790); político y científico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1262, '\"La vida es una extraña mezcla de azar, destino y carácter\".', 'Wilhelm Dilthey (1833-1911); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1263, '\"Vale más un testigo de vista que diez de oídas\".', 'Plauto (c. 254-184 a.C.); comediógrafo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1264, '\"Si de algo soy rico es de perplejidades y no de certezas\".', 'Jorge Luis Borges (1899-1986); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1265, '\"La historia cuenta lo que sucedió; la poesía lo que debía suceder\".', 'Aristóteles (384 AC-322 AC.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1266, '\"El genio convierte la excepción en regla\".', 'Eugeni Trias (1942); filósofo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1267, '\"Los años enseñan muchas cosas que los días jamás llegan a conocer\".', 'Ralph Waldo Emerson (1803-1882); poeta y pensador estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1268, '\"La verdad anda sobre la mentira como el aceite sobre el agua\".', 'Miguel de Cervantes Saavedra (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1269, '\"Es preciso considerar el pasado con respeto\ny el presente con desconfianza si se pretende asegurar el porvenir\".', 'Joseph Joubert (1754-1824); moralista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1270, '¡Confiamos demasiado en los sistemas, y muy poco en los hombres!', 'Benjamín Disraeli (1766-1848); estadista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1271, '\"Todo lo que se llama estudiar y aprender no es otra cosa que recordar\".', 'Platón (427-347 a.C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1272, '\"Nada se parece tanto a la ingenuidad como el atrevimiento\".', 'Oscar Wilde (1854-1900); dramaturgo y novelista irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1273, '\"Si dices la verdad, no tendrás que acordarte de nada\".', 'Mark Twain (1835-1910); escritor y periodista estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1274, '\"La cometa se eleva más alto en contra del viento, no a su favor\".', 'Winston Churchill (1874-1965); político británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1275, '\"La confianza es madre del descuido\".', 'Baltasar Gracián (1601-1658); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1276, '¿Quién capitulará más pronto: el que necesita las cosas\ndifíciles o quien se sirve de lo que buenamente pueda hallar?', 'Sócrates (470 a.C.-399 a.C); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1277, '\"Antes de iniciar la labor de cambiar el mundo, da tres vueltas por tu propia casa\".', 'Proverbio chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1278, '\"Discutir en el peligro es apretar el dogal\".', 'Napoleón Bonaparte (1769-1821); emperador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1279, '\"Existen en nosotros varias memorias.\nEl cuerpo y el espíritu tienen cada uno la suya\".', 'Honoré de Balzac (1799-1850); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1280, '\"No puedes bajar dos veces el mismo río, pues nuevas aguas corren sobre ti\".', 'Heráclito (c.544-480 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1281, '\"Sólo la inteligencia se examina a sí misma\".', 'Jaime Balmes (1810-1848); sacerdote y filósofo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1282, '\"El tiempo descubre la verdad\".', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo hispanolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1283, '\"Nada vale la pena de ser encontrado sino lo que jamás ha existido aún\".', 'Pierre Teilhard de Chardin (1881-1955); filósofo y paleontólogo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1284, '\"Reprender al que yerra no basta si no se le enseña el camino recto\".', 'Lucio Junio Moderado Columela (s. I d. C.); escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1285, '\"La verdadera elocuencia consiste en no decir más de lo que es preciso\".', 'François de la Rochefoucauld (1613-1680); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1286, '\"Si te parece que sabes mucho y entiendes muy bien,\nten por cierto que es mucho más lo que ignoras\".', 'Tomás de Kempis (1375-1471); escritor alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1287, '\"La historia es la ciencia de lo que nunca sucede dos veces\".', 'Paul Ambroise Valéry (1871-1945); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1288, '\"Por un clavo se perdió una herradura, por ésta un caballo,\ny por éste el jinete, que fue capturado y muerto por el enemigo\".', 'Benjamín Franklin (1706-1790); estadista y científico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1289, '\"Es un hecho que el hombre tiene que controlar la ciencia\ny chequear ocasionalmente el avance de la tecnología\".', 'Thomas Henry Huxley (1825-1895); zoólogo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1290, '\"La mitad está hecha cuando tienen buen principio las cosas\".', 'Fernando de Rojas (1468-1542); autor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1291, '\"Sin música la vida sería un error\".', 'Friedrich Nietzsche (1844-1900); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1292, '\"La reflexión es el ojo del alma\".', 'Jacques Bénigne Bossuet (1627-1704); orador y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1293, '\"En un minuto hay muchos días\".', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1294, '\"El camino arriba y abajo es uno y el mismo\".', 'Heráclito (c.544-480 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1295, '\"El tiempo es el mejor antologista, o el único, tal vez\".', 'Jorge Luis Borges (1899-1986); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1296, '\"Todo número es cero ante el infinito\".', 'Víctor Hugo (1802-1885); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1297, '\"En todas las cosas parece existir como ley un círculo\".', 'Publius Cornelius Tacitus Tácito (55-115); historiador romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1298, '\"Cuando llega el tiempo en que se podría, ha pasado en el que se pudo\".', 'Marie von Ebner Eschenbach (1830-1916); escritora austríaca.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1299, '\"No deseo copiar a la naturaleza.\nMe interesa más ponerme a la par de ella\".', 'Georges Braque (1882-1963); pintor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1300, '\"El hombre se descubre cuando se mide con un obstáculo\".', 'Antoine de Saint-Exupery (1900-1944); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1301, 'La ciencia que se aparta de la justicia, más que ciencia debe llamarse astucia.', 'Cicerón (106-43 a. C.); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1302, '\"Lo que los hombres realmente quieren no es el conocimiento sino la certidumbre\".', 'Bertrand Russell (1872-1970); filósofo y matemático inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1303, '\"Sólo se inventa mediante el recuerdo\".', 'Jean Baptiste Alphonse Karr (1808-1890); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1304, '\"La Historia Universal es la de un solo hombre\".', 'Jorge Luis Borges (1899-1986); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1305, '\"No puedes enseñárselo todo: sólo puedes ayudarle a encontrarlo por sí mismo\".', 'Galileo Galilei (1564-1642); astrónomo y físico italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1306, '\"Después de la tempestad viene la calma\".', 'Refrán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1307, '\"Es tan difícil verse a uno mismo como mirar para atrás sin volverse\".', 'Henry David Thoreau (1817-1862); escritor, poeta y pensador.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1308, '\"La acción no debe ser una reacción sino una creación\".', 'Mao Tse-Tung (1893-1976); estadista chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1309, '\"El tiempo es oro\".', 'Edward George Bulwer-Lytton (1803-1873); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1310, '\"El que busca la verdad corre el riesgo de encontrarla\".', 'Manuel Vicent (1936); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1311, '\"Quien daña el saber, homicida es de sí mismo\".', 'Pedro Calderón de la Barca (1600-1681); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1312, '\"La única técnica que merece la pena dominar es la que uno mismo inventa\".', 'Jean Cocteau (1889-1963); escritor, pintor y coreógrafo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1313, '\"El hombre no puede saltar fuera de su sombra\".', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1314, '\"El presente sólo se forma del pasado,\ny lo que se encuentra en el efecto estaba ya en la causa\".', 'Henri Bergson (1859-1941); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1315, '¡Como si se pudiera matar el tiempo sin insultar a la eternidad!', 'Henry David Thoreau (1817-1862); escritor, poeta y pensador.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1316, '\"El horizonte está en los ojos y no en la realidad\".', 'Angel Ganivet (1865-1898); novelista, ensayista y dramaturgo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1317, '\"Todo artista es tan múltiple que el crítico no puede dejar\nde encontrar en él lo que busca resueltamente y a priori\".', 'André Maurois (1885-1967); biógrafo, novelista y ensayista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1318, '\"Lo que embellece al desierto es que en alguna parte esconde un pozo de agua\".', 'Antoine de Saint-Exupéry (1900-1944); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1319, '\"Quizá la más grande lección de la historia\nes que nadie aprendió las lecciones de la historia\".', 'Aldous Huxley (1894-1963); novelista, ensayista, crítico y poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1320, '\"Los grandes conocimientos engendran las grandes dudas\".', 'Aristóteles (384 AC-322 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1321, '\"El verdadero significado de las cosas se encuentra\nal decir las mismas cosas con otras palabras\".', 'Charles Chaplin (1889-1977); actor y director británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1322, '\"Los imposibles de hoy serán posibles mañana\".', 'Konstantin Tsiolkovsky (1857-1935); científico ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1323, '\"La música constituye una revelación más alta que ninguna filosofía\".', 'Ludwig van Beethoven (1770-1827); compositor alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1324, '\"Cada cosa tiene su belleza, pero no todos pueden verla\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1325, '\"Seguir un sólo camino es retroceder\".', 'Igor Stravinski (1882-1971); compositor ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1326, 'La verdadera sabiduría está en reconocer la propia ignorancia\".', 'Sócrates (470 - 399 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1327, '¿Qué puede haber imprevisto para el que nada ha previsto?', 'Paul Ambroise Valéry (1871-1945); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1328, '\"Azar es una palabra vacía de sentido, nada puede existir sin causa\".', 'François Marie Arouet Voltaire (1694-1778); filósofo y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1329, '\"No perdamos nada del pasado. Sólo con el pasado se forma el porvenir\".', 'Anatole France (1844-1924); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1330, '\"Todos tenemos nuestra casa, que es el hogar privado;\ny la ciudad, que es el hogar público\".', 'Enrique Tierno Galván (1918-1986); sociólogo, político y ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1331, '\"Si buscas resultados distintos, no hagas siempre lo mismo\".', 'Albert Einstein (1879-1955); físico y matemático.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1332, '\"Estudia el pasado si quieres pronosticar el futuro\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1333, '\"La mucha luz es como la mucha sombra: no deja ver\".', 'Octavio Paz (1914); escritor mexicano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1334, '\"La palabra una vez hablada, vuela y no torna\".', 'Quinto Horacio Flaco (65 AC-8 AC); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1335, '\"Sólo la fantasía permanece siempre joven;\nlo que no ha ocurrido jamás no envejece nunca\".', 'Johann C. Friedrich von Schiller (1759-1805); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1336, '\"Las ideas se encienden unas con otras como las chispas eléctricas\".', 'Johann Jakob Engel (1741-1802); escritor alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1337, '\"La armonía total de este mundo está formada\npor una natural aglomeración de discordancias\".', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo hispanolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1338, '\"El hombre tiene mil planes para sí mismo. El azar, sólo uno para cada uno\".', 'Mencio o Meng Zi (372-289 a. C.); filósofo chino confuciano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1339, '\"Hay un pasado que se fue para siempre pero hay un futuro que todavía es nuestro\".', 'F. W. Robertson (1816-1853); predicador inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1340, '\"La música es la armonía del cielo y de la tierra\".', 'Yuel-Ji (s. II a. de C.); músico chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1341, '\"La historia del mundo es la suma de aquello que hubiera sido evitable\".', 'Bertrand Russell (1872-1970); filósofo y matemático inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1342, '\"Todos los asuntos tienen dos asas: por una son manejables, por la otra no\".', 'Epicteto de Frigia (50-135); filósofo grecolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1343, '\"Una palabra es suficiente para hacer o deshacer la fortuna de un hombre\".', 'Sófocles (495 a.C.-406 a.C.); poeta trágico griego');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1344, '\"Lo que sabemos es una gota de agua; lo que ignoramos es el océano\".', 'Isaac Newton (1643-1727); matemático inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1345, '\"Produce una inmensa tristeza pensar que la naturaleza\nhabla mientras el género humano no escucha\".', 'Víctor Hugo (1802-1885); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1346, '\"Si tu intención es describir la verdad, hazlo con sencillez\ny la elegancia déjasela al sastre\".', 'Albert Einstein (1879-1955), físico germano-estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1347, '\"La pluma es la lengua del alma\".', 'Miguel de Cervantes Saavedra (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1348, '\"No basta tener buen ingenio; lo principal es aplicarlo bien\".', 'René Descartes (1596-1650); filósofo y matemático francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1349, '\"Engarza en oro las alas del pájaro y nunca mas volará al cielo\".', 'Rabindranath Tagore (1861-1941); filósofo y escritor indio.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1350, '\"Lo que llamamos casualidad no es ni puede ser sino\nla causa ignorada de un efecto desconocido\".', 'Voltaire (1694-1778); filósofo y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1351, '\"En todas las cosas, naturales y humanas, el origen es lo más excelso\".', 'Platón (427 AC-347 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1352, '\"El jarrón da forma al vacío y la música al silencio\".', 'Georges Braque (1882-1963); pintor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1353, '\"La tinta más pobre de color vale más que la mejor memoria\".', 'Proverbio chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1354, '\"Es un hecho que el hombre tiene que controlar la ciencia\ny chequear ocasionalmente el avance de la tecnología\".', 'Thomas Henry Huxley (1825-1895); zoólogo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1355, '\"La sorpresa es el móvil de cada descubrimiento\".', 'Cesare Pavese (1908-1950); poeta y novelista italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1356, 'El leer sin pensar nos hace una mente desordenada.\nEl pensar sin leer nos hace desequilibrados.', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1357, '\"Incluso el pasado puede modificarse; los historiadores no paran de demostrarlo\".', 'Jean Paul Sartre (1905-1980); filósofo y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1358, '\"Los niños hallan el todo en la nada; los hombres, la nada en el todo\".', 'Giacomo Leopardi(1798-1837); poeta italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1359, '\"Saber mucho da ocasión de dudar más\".', 'Michel Eyquem de Montaigne (1533-1592); pensador francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1360, '\"Experiencia es el nombre que damos a nuestras equivocaciones\".', 'Óscar Wilde (1854-1900); escritor irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1361, '\"Es más fácil ser genial que tener sentido común\".', 'Jacinto Benavente (1866-1954); dramaturgo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1362, '\"La memoria es el centinela del cerebro\".', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1363, '\"La vida es como una leyenda: no importa que sea larga, sino que esté bien narrada\".', 'Lucio Anneo Séneca (2 AC-65); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1364, '\"El tiempo saca a la luz todo lo que está oculto y encubre\ny esconde lo que ahora brilla con el más grande esplendor\".', 'Quinto Horacio Flaco (65 AC-8 AC); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1365, '\"La música es el verdadero lenguaje universal\".', 'Carl Maria von Weber (1786-1826); compositor alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1366, '\"Se puede tener por compañera la fantasía, pero se debe tener como guía a la razón\".', 'Samuel Johnson (1709-1784); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1367, '\"El pensamiento es la única cosa del Universo\nde la que no se puede negar su existencia: negar es pensar\".', 'Ortega y Gasset, José (1883-1955); filósofo y ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1368, '\"Mi memoria es magnífica para olvidar\".', 'Robert Louis Stevenson (1850-1894); novelista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1369, '\"La reflexión calmada y tranquila desenreda todos los nudos\".', 'Harold MacMillan (1894-1986); político inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1370, '\"Si no quieres repetir el pasado, estúdialo\".', 'B. Benedict Spinoza (1632-1677); filósofo holandés, de origen judeoespañol.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1371, '\"La confidencia descubre quién era o no digno de ella\".', 'André Maurois (1885-1967); biógrafo, novelista y ensayista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1372, '\"Es más fácil negar las cosas que enterarse de ellas\".', 'Mariano José de Larra (1809-1837); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1373, '\"Dime y lo olvido, enséñame y lo recuerdo, involúcrame y lo aprendo\".', 'Confucio (551-479 a. C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1374, '\"Pensar y obrar, obrar y pensar es la suma de toda sabiduría\".', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1375, '\"Seguir un sólo camino es retroceder\".', 'Ígor Stravinski (1882-1971); compositor ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1376, '\"Las ideas son capitales que sólo ganan intereses entre las manos del talento\".', 'Conde de Rivarol (1801-1753); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1377, '\"La mucha luz es como la mucha sombra: no deja ver\".', 'Octavio Paz (1914); escritor mexicano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1378, '\"Sólo es capaz de realizar los sueños el que, cuando llega la hora, sabe estar despierto\".', 'León Daudet (1867-1942); periodista y novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1379, '\"Una palabra es suficiente para hacer o deshacer la fortuna de un hombre\".', 'Sófocles (495 a.C-406a.C.); poeta trágico griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1380, 'Existen en nosotros varias memorias. El cuerpo y el espíritu tienen cada uno la suya.', 'Honoré de Balzac (1799-1850), escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1381, '\"Todo cabe en lo breve. Pequeño es el niño y encierra al hombre\".', 'Alejandro Dumas (1802-1870), escritor Francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1382, 'Para protegerse de los bribones es mucho más eficaz intimar realmente\ncon personas honestas que desconfiar por principio de todo el mundo', 'Clive Staples Lewis (Reino Unido, 1898-1963), escritor y profesor británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1383, 'Nada nos engaña tanto como nuestro propio juicio.', 'Leonardo da Vinci (Italia, 1452 - Francia, 1519) Artista e inventor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1384, '\"Puedes engañar a todo el mundo algún tiempo.\nPuedes engañar a algunos todo el tiempo.\nPero no puedes engañar a todo el mundo todo el tiempo.\"\nAbraham Lincoln (Estados Unidos, 1809-1865),', 'Presidente de los Estados Unidos de América');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1385, 'La tradición no se hereda, se conquista', 'André Malraux (1901-1976), escritor y filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1386, '\"El que se pierde es el que encuentra las nuevas sendas\".', 'Nils Kjaer (1870-1924); escritor noruego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1387, '\"Las personas cambian y generalmente se olvidan\nde comunicar dicho cambio a los demás.', 'Lillian Hellman (1905-1984), dramaturgo estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1388, '\"La cordura y el genio son novios, pero jamás han podido casarse\".', 'Amado Nervo (1870-1919); poeta mexicano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1389, '\"La armonía total de este mundo está formada\npor una natural aglomeración de discordancias\".', 'Lucio Anneo Séneca (2a.C.-65 a.C); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1390, '\"Todos los hombres se parecen por sus palabras;\nsolamente las obras evidencian que no son iguales\".', 'Jean-Baptiste Poquelin Molière (1622-1673); comediógrafo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1391, 'Las sentencias cortas se derivan de una gran experiencia.', 'Miguel de Cervantes Saavedra (1547-1616), escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1392, 'Confía en el tiempo, que suele dar dulces salidas a muchas amargas dificultades', 'Miguel de Cervantes Saavedra (1547-1616). Escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1393, 'El amor es como Don Quijote, cuando recobra el juicio es que está para morir', 'Jacinto Benavente (1866-1954), escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1394, 'Dad crédito a las obras y no a las palabras', 'Miguel de Cervantes Saavedra (1547-1616), escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1395, 'Al bien hacer jamás le falta premio', 'Miguel de Cervantes Saavedra (1547-1616), escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1396, 'Cada hombre es el hijo de su propio trabajo', 'Miguel de Cervantes Saavedra (1547-1616). Escritor español');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1397, 'La falsedad tiene alas y vuela, y la verdad la sigue arrastrándose', 'Miguel de Cervantes Saavedra (1547-1616). Escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1398, '\"El presente sólo se forma del pasado, y lo que\nse encuentra en el efecto estaba ya en la causa\".', 'Henri Bergson (1859-1941); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1399, '\"El que no aplique nuevos remedios debe esperar nuevos males,\nporque el tiempo es el máximo innovador\".', 'Sir Francis Bacon (1561-1626), filósofo y estadista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1400, 'El que confía sus secretos a otro hombre se hace esclavo de él', 'Baltasar Gracián (1601-1658), escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1401, 'La razón humana es tan débil para edificar como formidable ariete para destruir', 'Jaime Luciano Balmes (1810 - 1848). Filósofo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1402, 'No guardes nunca en la cabeza aquello que te quepa en un bolsillo.', 'Albert Einstein (1879 - 1955) físico germano-estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1403, 'Los que emplean mal su tiempo son los primeros en quejarse de su brevedad.', 'Jean de la Bruyere (1645 - 1696), escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1404, 'Lo peor no es cometer un error, sino tratar de justificarlo en vez  de aprovecharlo\ncomo aviso providencial de nuestra ligereza o ignorancia.', 'Santiago Ramón y Cajal (1852-1934), médico español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1405, 'El arte es uno de los medios de comunicación entre los hombres.', 'Leon Tolstoi (1828-1910), escritor ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1406, 'Las conversaciones siempre son peligrosas si se quiere esconder alguna cosa', 'Agatha Christie (1890 - 1976), escritora británica.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1407, 'Una de las alegrías de la amistad es saber en quien confiar', 'Alessandro Manzoni (1785-1873), novelista, poeta y dramaturgo italiano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1408, 'Hacer versos malos depara más felicidad que leer los versos más bellos', 'Hermann Hesse (1877-1962), escritor suizo de origen alemán');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1409, 'Uno puede defenderse de los ataques; contra el elogio se está indefenso.', 'Sigmund Freud (1856 - 1939), médico austríaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1410, 'Para escribir un buen libro no considero imprescindible haber leído el Quijote.\nCervantes, cuando escribió el Quijote, aún no lo había leído', 'Miguel Delibes (1920), escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1411, 'Mi deseo es poner en aborrecimiento de los hombres\nlas fingidas y disparatadas historias de los libros de caballerías', 'Miguel de Cervantes Saavedra (1547-1616). Escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1412, 'En un lugar de la mancha, de cuyo nombre no quiero acordarme...', 'Miguel de Cervantes Saavedra (1547-1616). Escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1413, 'El ver mucho y leer mucho aviva los ingenios de los hombres', 'Miguel de Cervantes Saavedra (1547-1616). Escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1414, 'Los males que no tienen fuerza para acabar la vida,\nno han de tenerla para acabar la paciencia.', 'Miguel de Cervantes Saavedra (1547-1616). Escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1415, 'Mientras se gana algo no se pierde nada.', 'Miguel de Cervantes Saavedra (1547-1616). Escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1416, 'El mejor cimiento y zanja del mundo es el dinero', 'Miguel de Cervantes Saavedra (1547-1616). Escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1417, 'Más vale el buen nombre que las muchas riquezas', 'Miguel de Cervantes Saavedra (1547-1616). Escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1418, '\"Habla bajo, habla despacio, y no hables mucho\".', 'John Wayne (1907-1979), actor y director de cine estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1419, '\"Si no sabes donde vas, acabarás en otra parte\".', 'Laurence J. Peter (1919-1990), poeta canadiense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1420, '\"La vida es el arte de sacar conclusiones suficientes a partir de datos insuficientes\".', 'Samuel Butler (1835-1902), poeta británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1421, '\"Hazlo o no lo hagas. Pero no lo intentes\".\nYoda, en \"El Imperio contraataca\", según guión de', 'George Lucas (1944), director y guionista estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1422, '\"Los hombres están siempre dispuestos a curiosear y averiguar sobre las vidas ajenas,\npero les da pereza conocerse a sí mismos y corregir su propia vida.', 'San Agustín (354-439), Obispo, filósofo y Padre de la Iglesia Latina argelino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1423, 'Yo soy un hombre de gustos sencillos: siempre me conformo con lo mejor.', 'Oscar Wilde (1854-1900), dramaturgo y novelista irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1424, '\"La verdad no está de parte de quién grite más\".', 'Rabindranath Tagore (1861-1941), filósofo y escritor indio.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1425, '\"Es más fácil escribir diez volúmenes de principios filosóficos\nque poner en práctica uno solo de sus principios\".', 'Leon Tolstoi (1828-1910), escritor ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1426, '\"La calidad nunca es un accidente; siempre es el resultado de un esfuerzo de la inteligencia\".', 'John Ruskin (1819-1900), crítico y escritor británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1427, '\"Comprender es el principio de aprobar\".', 'Baruch Benedict Spinoza (1632-1677), filósofo holandés, de origen judeoespañol.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1428, '\"Todas las cosas ya fueron dichas, pero como nadie escucha es preciso comenzar de nuevo\".', 'André Gide (1859-1951), escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1429, 'Tres podrían guardar un secreto si dos de ellos hubieran muerto.', 'Benjamin Franklin (1706-1790), estadista y científico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1430, '\"No hay mayor placer que el de encontrar un viejo amigo, salvo el de hacer uno nuevo.', 'Rudyard Kipling (1865-1936), novelista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1431, 'La verdad siempre resplandece al final, cuando ya se ha ido todo el mundo.', 'Julio Cerón (1928), dimplomático español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1432, 'El primer paso para el conocimiento es saber que somos ignorantes.', 'Baltasar Gracián (1601-1658), escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1433, 'De nada sirve al hombre lamentarse de los tiempos en que vive.\nLo único bueno que puede hacer es intentar mejorarlos.', 'Thomas Carlyle (1795-1881), historiador, pensador y ensayista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1434, 'Hay grandes hombres que hacen a todos los demás sentirse pequeños.\nPero la verdadera grandeza consiste en hacer que todos se sientan grandes.', 'Charles Dickens, (1812-1870), novelista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1435, 'Poca observación y muchas teorías llevan al error.\nMucha observación y pocas teorías llevan a la verdad.', 'Alexis Carrel (1873-1944), biólogo y médico francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1436, 'Es un hecho que el hombre tiene que controlar la ciencia\ny chequear ocasionalmente el avance de la tecnología', 'Thomas Henry Huxley (1825-1895), zoólogo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1437, 'Decir adiós no significa nada. Lo que importa es\nel tiempo que pasamos juntos, no cómo se termina', 'Trey Parker (1969-) y Matt Stone (1971-), guionistas de televisión estadounidenses');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1438, 'Es más fácil perdonar a un enemigo que perdonar a un amigo.', 'William Blake (1757-1827), grabador, ilustrador y poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1439, '\"La voz del pueblo es la voz de Dios.\" (Vox Populi, Vox Dei)', 'Alcuin (732-804), matemático anglosajón');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1440, '\"Un héroe no es más valiente que un hombre normal,  pero es valiente cinco minutos más\".', 'Ralph Waldo Emerson, (1803-1882) ensayista y poeta estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1441, 'Un hombre débil tiene dudas antes de tomar una decisión,\nun hombre fuerte las tiene después', 'Karl Kraus (1874-1936), periodista y escritor australiano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1442, 'El periodismo consiste básicamente en decir \'Ha muerto Lord Jones\',\na gente que no sabía que Lord Jones estaba vivo', 'G. K. Chesterton (1874-1936), escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1443, 'La historia es la versión de los hechos pasados\nen los que las personas se han puesto de acuerdo', 'Napoleon Bonaparte (1769-1821), general y político francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1444, '\"El futuro, según algunos científicos, será exactamente igual\nque el pasado, solo que mucho más caro\".', 'John Sladek (1937-2000), escritor estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1445, '\"De todos los sonidos, la música es el menos desagradable\".', 'Samuel Johnson (1709-1784), escritor, crítico y lexicógrafo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1446, 'Es mejor confiar en un rey poderoso que en muchas princesitas', 'Jean de La Fontaine (1621-1695), poeta francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1447, 'Las puertas de la sabiduría nunca están cerradas.', 'Benjamin Franklin (1706-1790); estadista y científico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1448, '\"Un hombre que no confía en sí mismo nunca podrá confiar en nadie más\".', 'Paul de Gondi (1613-1679), cardenal de Retz, Francia.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1449, 'El miedo a un nombre aumenta el miedo a la cosa que se nombra', 'J. K. Rowling (1965), novelista británica.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1450, '\"Lo bueno de los estándares es que hay muchos entre los que elegir\".\nAndrew S. Tanenbaum (1944) profesor de Informática', 'en la Universidad de Vrije, Holanda.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1451, '\"El resumen más triste de una vida contiene tres descripciones:\n\'podía haber\', \'pudo haber\', y \'debería haber\'\".', 'Louis E. Boone (1941-2005), autor académico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1452, '\"Una persona que valora más sus privilegios que\nsus principios, pronto acabará perdiendo ambos\".', 'Dwight D. Eisenhower (1890-1969) general y político estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1453, 'Lanza primero tu corazón y tu caballo saltará el obstáculo', 'Noel Claraso (1905-1985), escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1454, '\"Quienes creen que el dinero lo hace todo, terminan haciendo todo por dinero\".', 'Voltaire (1694-1778), filósofo y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1455, '\"Una experiencia nunca es un fracaso, pues siempre viene a demostrar algo\".', 'Thomas Alva Edison (1847-1931), físico e inventor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1456, '\"Cuando leemos demasiado deprisa o demasiado despacio, no entendemos nada\".\nBlaise Pascal (1623-1662), científico, filósofo', 'y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1457, 'El hombre sabio evita el mal anticipándose a él', 'Publilius Syrus (~100 A. C.), escritor latino');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1458, 'Deja tu brazo roto dentro de la manga', 'Proverbio chino');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1459, 'La verdad es más extraña que la ficción', 'Mark Twain (1835-1910), escritor estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1460, '\"No necesito amigos que cambian cuando yo cambio, y asienten\ncuando yo asiento. Mi sombra lo hace mucho mejor\".', 'Plutarco (46-120); historiador griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1461, 'Una habitación sin libros es como un cuerpo sin alma', 'G. K. Chesterton (1874 - 1936), escritor inglés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1462, '\"Al final no recordaremos las palabras de nuestros enemigos,\nsino el silencio de nuestros amigos\"\nMartin Luther King Jr. (1929-1968), luchador por los derechos civiles', 'y clérigo estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1463, 'Yo respeto la fe, pero dudar es lo que te proporciona educación', 'Wilson Mizner (1876 - 1933), guionista estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1464, '\"Hacer felices a otros hombres: no hay nada mejor ni más bello\".', 'Ludwig van Beethoven (1770-1827); músico y compositor alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1465, '\"Saber que se sabe lo que se sabe y que no se sabe\nlo que no se sabe; he aquí el verdadero saber\".', 'Confucio (551 a.C.- 478 a.C); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1466, '\"Nadie se baña en el río dos veces porque todo\ncambia en el río y en el que se baña\".', 'Heráclito de Efeso (540 a.C.-470 a.C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1467, '\"El hallazgo afortunado de un buen libro puede cambiar el destino de un alma\".', 'Marcel Prévost (1862-1941); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1468, 'Una vida pasada cometiendo errores no es solo honorable,\nsino que es más útil que una vida pasada sin hacer nada', 'George Bernard Shaw (1856-1950), dramaturgo irlandés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1469, 'La vida es una cosa demasiado importante como para hablar en serio de ella.', 'Oscar Wilde (1854-1900), dramaturgo, novelista y poeta irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1470, '\"La alegría de ver y entender es el más perfecto don de la naturaleza\".', 'Albert Einstein (1879-1955); físico y matemático.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1471, '\"Un barco no debería navegar con una sola ancla, ni la vida con una sola esperanza\".', 'Epicteto de Frigia (50-135); filósofo grecolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1472, '\"Los años enseñan muchas cosas que los días jamás llegan a conocer\".', 'Ralph Waldo Emerson (1.803-1.882); poeta y pensador estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1473, '\"En el estudio no existe la saciedad\".', 'Erasmo de Rotterdam (1466-1536); erudito y escritor holandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1474, '\"La sabiduría es hija de la experiencia\".', 'Leonardo Da Vinci (1452-1519); pintor, escultor e inventor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1475, '\"Todo lo que realmente nos pertenece es el tiempo;  incluso el que no tiene nada más, lo posee\".', 'Baltasar Gracián (1601-1658); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1476, '\"Las palabras son enanos, los ejemplos son gigantes\".', 'Proverbio suizo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1477, '\"En circunstancias especiales, el hecho debe ser más rápido que el pensamiento\".', 'Hernán Cortés (1485-1547); conquistador español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1478, '\"Quien se empeña en pegarle una pedrada a la luna no lo conseguirá,\npero terminará sabiendo manejar la honda\".', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1479, 'Es fácil ser valiente desde una distancia segura', 'Esopo (620 AC-560 AC), escritor clásico griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1480, '\"No sabemos ni un cienmillonésimo de nada\".', 'Thomas Alva Edison (1847-1931); físico e inventor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1481, '\"No dispares la flecha que puede volverse contra ti\".', 'Proverbio kurdo');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1482, '\"Vengándose, uno se iguala a su enemigo; perdonándolo, se muestra superior a él\".', 'Sir Francis Bacon (1561-1626); filósofo y estadista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1483, '\"Las ideas son capitales que sólo ganan intereses entre las manos del talento\".', 'Conde de Rivarol (1753-1801); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1484, '\"Considera las contrariedades como un ejercicio\".', 'Lucio Anneo Séneca (2 AC-65 DC); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1485, '\"A cada día le bastan sus temores, y no hay por qué anticipar los de mañana\".', 'Charles Péguy (1873-1914); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1486, '\"El que no considera lo que tiene como la riqueza más grande,\nes desdichado, aunque sea dueño del mundo\".', 'Epicuro de Samos (341 AC-270 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1487, 'Sólo es digno de libertad quien sabe conquistarla cada día', 'Johann Wolfgang von Goethe (1749-1832), poeta alemán');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1488, '\"Manejar el silencio es más difícil que manejar la palabra\".', 'Georges Benjamin Clemenceau (1841-1929); político y periodista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1489, '\"No existen más que dos reglas para escribir: tener algo que decir y decirlo\".', 'Oscar Wilde (1854-1900); dramaturgo y novelista irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1490, '\"Sírvete de lo aparente como indicio de lo inaparente\".', 'Solón de Atenas (638-559 a.C.); legislador griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1491, '\"Cada fracaso le enseña al hombre algo que necesitaba aprender\".', 'Charles Dickens (1812-1870); novelista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1492, '\"Pensar es como vivir dos veces\".', 'Marco Tulio Cicerón (106-43 a. C); escritor, orador y político romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1493, '\"La vida sólo puede ser comprendida mirando hacia atrás,\npero ha de ser vivida mirando hacia delante\".', 'Sören Aabye Kierkegaard (1813-1855); literato y filósofo danés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1494, '\"La vida cobra sentido cuando se hace de ella una aspiración a no renunciar a nada\".', 'José Ortega y Gasset (1883-1955); filósofo y ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1495, '\"Entre dos explicaciones, elige la más clara; entre dos formas,\nla más elemental; entre dos expresiones, la más breve\".', 'Eugeni d\' Ors (1881-1954); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1496, 'La fuerza de la necesidad es irresistible.', 'Esquilo de Eleusis (525 - 456 a. C.); poeta trágico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1497, '\"La ignorancia está menos lejos de la verdad que el prejuicio\".', 'Denis Diderot (1713-1784); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1498, 'El hombre nada puede aprender sino en virtud de lo que ya sabe.', 'Aristóteles (384-322 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1499, '\"El futuro nos tortura y el pasado nos encadena. He ahí por qué se nos escapa el presente\".', 'Gustave Flaubert (1821-1880); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1500, '\"El idealismo aumenta en proporción directa de la distancia que nos separa del problema\".', 'John Galsworthy (1867-1933); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1501, '\"Que siempre por señales o razones se suelen descubrir las intenciones\".', 'Alonso de Ercilla y Zúñiga (1533-1594); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1502, '\"Cuando se puede evitar un mal es necedad aceptarlo\".', 'Publio Terencio Afer (195-159 a.C.); autor cómico latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1503, '\"No hay viento favorable para el que no sabe donde va\".', 'Séneca, Lucius Annaeus (c.5 a. C.-65 d. C.); filósofo hispanolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1504, '\"Todo lo difícil debe intentarse mientras es fácil\".', 'Lao-tsé (570 a.C.-490 a.C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1505, '\"El destino es el que baraja las cartas, pero nosotros somos los que jugamos\".', 'William Shakespeare (1564-1616); poeta y dramaturgo inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1506, '\"¡Como si se pudiera matar el tiempo sin insultar a la eternidad!\".', 'Henry David Thoreau (1817-1862); escritor, poeta y pensador.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1507, '\"Donde menos se piensa, salta la liebre\".', 'Refrán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1508, '\"Actuar es fácil, pensar es difícil; actuar según se piensa es aún más difícil\".', 'Johann Wolfgang von Goethe (1749-1832); poeta y dramaturgo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1509, '\"El sabio no dice todo lo que piensa, pero siempre piensa todo lo que dice\".', 'Aristóteles (384 AC-322 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1510, '\"La historia del mundo es la suma de aquello que hubiera sido evitable\".', 'Bertrand Russell (1872-1970); filósofo, matemático y escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1511, '\"La contemplación es un lujo, mientras que la acción es una necesidad\".', 'Henri Bergson (1859-1941); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1512, '\"Nunca la naturaleza dice una cosa y la sabiduría otra\".', 'Decimus Junius Juvenal (67-127); poeta satírico romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1513, '\"No hay tiempo que no se acabe ni tiento que no se corte\".', 'José Hernández (1834-1886); poeta argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1514, '\"El valor de un acto se juzga por su oportunidad\".', 'Lao-tsé (570 a.C.-490 a.C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1515, '\"El genio es un uno por ciento de inspiración\ny un noventa y nueve por ciento de sudor\".', 'Thomas Alva Edison (1847-1931); físico e inventor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1516, '\"La vida es un arco iris que incluye el negro\".', 'Yevgeny Yevtushenko (1933-1992); poeta ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1517, '\"Quien volviendo a hacer el camino viejo aprende el nuevo,\npuede considerarse un maestro\".', 'Confucio (551 a.C.- 478 a.C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1518, 'La cuestión más importante es no dejar de preguntar', 'Albert Einstein (1879-1955), físico estadounidense de origen alemán');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1519, '\"Elimina la diplomacia de una guerra y el problema se desinflará en una semana\".', 'Will Rogers (1879-1935), humorista estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1520, '\"Las palabras son como los rayos de sol:\ncuanto más concentradas están, más profundamente queman\".', 'Robert Southey (1774-1843), poeta británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1521, '\"No hay nada nuevo bajo el sol, pero cuantas cosas viejas hay que no conocemos\".', 'Ambrose Bierce (1842-1914); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1522, '\"No puedes enseñárselo todo: sólo puedes ayudarle a encontrarlo por sí mismo\".', 'Galileo Galilei (1564-1642); astrónomo y físico italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1523, '\"Hacer lo imposible es una forma de diversión\".', 'Walt Disney (1901-1966); dibujante y productor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1524, '\"Nunca se alcanza la verdad total, ni nunca se está totalmente alejado de ella\".', 'Aristóteles (384 AC-322 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1525, '\"La ausencia de prueba no es prueba de ausencia\".', 'Carl Sagan (1934-1996); Astrónomo estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1526, '\"La necesidad es un obstáculo indestructible;\ntodo lo que sobre ella se lanza se estrella\".', 'Gustave Flaubert (1821-1880); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1527, '\"El único deber que tenemos con la historia es rescribirla\".', 'Oscar Wilde (1854-1900); dramaturgo y novelista irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1528, '\"La diferencia entre el pasado, el presente y el futuro es sólo una ilusión persistente\".', 'Albert Einstein (1879-1955); físico y matemático.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1529, '\"La unidad es la variedad, y la variedad en la unidad es la ley suprema del universo\".', 'Isaac Newton (1643-1727); matemático inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1530, '\"Ver es creer, pero sentir es estar seguro\".', 'John Ray (1627-1705); naturalista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1531, '\"El saber y la razón hablan; la ignorancia y el error gritan\".', 'Arturo Graf (1848-1913); escritor y poeta italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1532, '\"La sorpresa es el móvil de cada descubrimiento\".', 'Cesare Pavese (1908-1950); poeta y novelista italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1533, '\"La prudencia es el más excelso de todos los bienes\".', 'Epicteto de Frigia (55-135); filósofo grecolatino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1534, '\"Una cosa sobre todo hace sugestivo el pensamiento humano: es la inquietud\".', 'Anatole France (1844-1924); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1535, '\"No hay ninguna cosa seria que no pueda decirse con una sonrisa\".', 'Alejandro Casona (1.903-1.965); dramaturgo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1536, '\"Visión es el arte de ver las cosas invisibles\".', 'Jonathan Swift (1667-1745); político y escritor irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1537, '\"Cada cosa tiene su belleza, pero no todos pueden verla\".', 'Confucio (551 a.C.- 478 a.C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1538, '\"Voy despacio, pero jamás desandando lo andado\".', 'Abraham Lincoln (1808-1865); político estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1539, '\"Sólo hay una máxima absoluta y es que no hay nada absoluto\".', 'Auguste Comte (1798-1857); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1540, '\"Puedo creer lo imposible pero no lo improbable\".', 'Gilbert Keith Chesterton (1874-1936); escritor británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1541, '\"Me interesa el futuro porque es el sitio donde voy a pasar el resto de mi vida\".', 'Woody Allen (1935); actor, director y escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1542, '\"El hombre prudente sólo piensa en sus dificultades\ncuando ello tiene algún objeto. Cuando no, piensa en otra cosa\".', 'Bertrand Russell (1872-1970); filósofo, matemático y escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1543, 'No es bueno intentar que el conocimiento no siga hacia delante.\nLa ignorancia nunca es mejor que el conocimiento', 'Enrico Fermi (1901-1954) físico estadounidense de origen italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1544, '\"Hay quien cruza el bosque y sólo ve leña para el fuego\".', 'Leon Tolstoi (1828-1910); novelista ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1545, '\"La práctica debería ser producto de la reflexión, no al contrario\".', 'Hermann Hesse (1877-1962); escritor suizo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1546, '\"La naturaleza ha puesto en nuestras mentes un insaciable deseo de ver la verdad\".', 'Marco Tulio Cicerón (106 AC-43 AC.); escritor, orador y político romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1547, '\"Cuando llega el tiempo en que se podría, ha pasado el tiempo en que se pudo\".', 'Marie von Ebner-Eschenbach (1830-1916); novelista austríaca.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1548, '\"El mundo ha sido creado para ser recreado\".', 'Georges Duhamel (1884-1966); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1549, '\"Nada vale la pena de ser encontrado sino lo que jamás ha existido aún\".', 'Pierre Teilhard de Chardin (1881-1955); filósofo y teólogo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1550, '\"Hay un libro abierto siempre para todos los ojos: la naturaleza\".', 'Jean Jacques Rousseau (1712-1778); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1551, 'Que no te de tanto miedo equivocarte que rechaces probar cosas nuevas', 'Louis E. Boone (1941), escritor estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1552, 'Demostrar gratitud con moderación es un signo de mediocridad', 'Roberto Benigni (1952), actor, cómico y director italiano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1553, '\"Las máquinas me sorporenden con mucha frecuencia\"\nAlan Turing (1912 - 1954), matemático inglés', 'y uno de los padres de la informática moderna');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1554, 'La moda es una forma de fealdad tan intolerable\nque tenemos que cambiarla cada 6 meses', 'Oscar Wilde (1854-1900), dramaturgo, novelista y poeta irlandés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1555, 'América había sido descubierta antes de Colón, pero siempre se había silenciado', 'Oscar Wilde (1854-1900), dramaturgo, novelista y poeta irlandés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1556, 'La honestidad es la mejor imagen', 'Tom Wilson (1931), dibujante de cómic estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1557, '\"Alégrate de la vida porque ella te da la oportunidad\nde amar, de trabajar, de jugar y de mirar a las estrellas\".', 'Henry Van Dyke (1852-1933); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1558, '\"Acepto el caos, pero no estoy seguro de que el caos me acepte a mí\".', 'Bob Dylan (1941); cantante estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1559, '\"Existe al menos un rincón del universo que con\ntoda seguridad puedes mejorar, y eres tú mismo\".', 'Aldous Huxley (1894-1963); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1560, '\"He aprendido que una vida no vale nada, pero también que nada vale una vida\".', 'Andre Malraux (1901-1976); aventurero y novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1561, 'No busques en la tecnología soluciones a los problemas físicos de seguridad', 'Anónimo');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1562, 'Una persona que da más valor a sus privilegios\nque a sus principios, pronto perderá ambos.', 'Dwight D. Eisenhower (1890-1969), general y político estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1563, '\"Lo que embellece al desierto es que en alguna parte esconde un pozo de agua\".', 'Antoine de Saint-Exupery (1900-1944); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1564, '\"Quien de verdad sabe de qué habla, no encuentra razones para levantar la voz\".', 'Leonardo Da Vinci (1452-1519). Pintor, escultor e inventor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1565, '\"Puedo creer lo imposible pero no lo improbable\".', 'Gilbert Keith Chesterton (1874-1936); escritor británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1566, '\"La imaginación es el ojo del alma\".', 'Joseph Joubert (1754-1824); moralista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1567, '\"Los cautos rara vez se equivocan\".', 'Confucio (551 a.C.- 478 a.C.); filósofo chino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1568, '\"Mientras haya libros no existe el pasado\".', 'Edward George Bulwer-Lytton (1803-1873); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1569, '\"Lo que los hombres realmente quieren no es el conocimiento sino la certidumbre\".', 'Bertrand Russell (1872-1970); filósofo y matemático inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1570, '\"A menudo encontramos nuestro destino por los caminos que tomamos para evitarlo\".', 'Jean de La Fontaine (1621-1695); poeta francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1571, '\"Ninguna ciencia, en cuanto a ciencia, engaña; el engaño está en quien no la sabe\".', 'Miguel de Cervantes Saavedra (1547-1616); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1572, '\"El arte es el hombre añadido a la naturaleza\".', 'Vincent Van Gogh (1.853-1.890); pintor holandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1573, '\"Hemos modificado tan radicalmente nuestro entorno que ahora debemos\nmodificarnos a nosotros mismos para poder existir dentro de él\".', 'Norbert Wiener (1894-1964); matemático estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1574, '¿Dónde es más débil la naturaleza humana sino en una librería?', 'Henry Ward Beecher (1813-1887) abolicionista y clérigo estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1575, '\"El temor y la esperanza nacen juntos y juntos mueren\".', 'Pietro Metastasio (1698-1782); poeta italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1576, '\"Nunca es igual saber la verdad por uno mismo que tener que escucharla por otro\".', 'Aldous Huxley (1894-1963); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1577, '\"Antes de negar con la cabeza, asegúrate de que la tienes\".', 'Truman Capote (1924-1984); escritor estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1578, '\"Quien tiene la voluntad tiene la fuerza\".', 'Menandro de Atenas (342 - 292 a. C.); dramaturgo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1579, '\"El sigilo frente a la luz nació con los hombres\".', 'Gonzalo Santonja (1955); poeta español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1580, '\"Sobre las cosas que no se conocen siempre se tiene mejor opinión\".', 'G. Wilhelm Leibniz (1646-1716); filósofo, físico y matemático alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1581, '\"El que no aplique nuevos remedios debe esperar nuevos males,\nporque el tiempo es el máximo innovador\".', 'Sir Francis Bacon (1561-1626); filósofo y estadista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1582, '\"El mayor artista es aquel que en la suma de sus obras\nha incorporado el mayor número de sus mejores ideas\".', 'John Ruskin (1819-1900); crítico y escritor británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1583, '\"Un diccionario es un universo en orden alfabético\".', 'Anatole France (1844-1924); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1584, '\"Saber es acordarse\".', 'Aristóteles (384 a.C.-322 a.C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1585, '\"Lo verdadero es siempre sencillo,\npero solemos llegar a ello por el camino más complicado\".', 'George Sand (1804-1876); novelista francesa del movimiento romántico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1586, '\"La belleza se define como la manifestación sensible de la idea\".', 'Georg Wilhelm Friedrich Hegel (1770-1831); filósofo alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1587, '\"El ignorante tiene valor; el sabio miedo\".', 'Alberto Moravia (1907-1990); escritor italiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1588, '\"Una palabra bien elegida puede economizar no sólo cien palabras\nsino cien pensamientos\".', 'Henri Poincaré (1854-1912); matemático francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1589, '\"Sólo hay una verdad absoluta: que la verdad es relativa\".', 'André Maurois (1885-1967); biógrafo, novelista y ensayista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1590, '\"El futuro pertenece a quienes creen en la belleza de sus sueños\".', 'Eleanor Roosevelt (1884- 1962); escritora y política estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1591, '\"Las ciencias aplicadas no existen, sólo las aplicaciones de la ciencia\".', 'Louis Pasteur (1822-1895); químico y microbiólogo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1592, '\"Los conceptos están incluidos en las palabras\".', 'Henri Bergson (1859-1941); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1593, '\"Lo importante es no dejar de hacerse preguntas\".', 'Albert Einstein (1879-1955); físico y matemático.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1594, '\"El mundo no ha cambiado por la política, sino por la técnica\".', 'Friedrich Dürrenmatt (1921); escritor y dramaturgo suizo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1595, '\"Sabio es aquel que constantemente se maravilla\".', 'André Gide (1859-1951); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1596, '\"El que quiera ser líder debe ser puente\".', 'Proverbio galés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1597, '\"Cuando no sopla el viento, incluso la veleta tiene carácter\".', 'Stanislaw Jerzy Lec (1909-1966); escritor polaco.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1598, '\"El tiempo es la imagen de la eternidad en movimiento\".', 'Platón (427 -347 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1599, '\"La palabra se ha dado al hombre para que pueda encubrir su pensamiento\".', 'Charles-Maurice Talleyrand Périgord (1754-1838); diplomático y estadista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1600, '\"La suerte es una flecha lanzada que hace blanco en el que menos la espera\".', 'Konrad Adenauer (1876-1967); político alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1601, '\"Cuando Neptuno quiere calmar las tempestades no se dirige a las olas, sino a los vientos\".', 'Antoine Rivarol (1753-1801); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1602, '\"Nada resiste tanto como lo provisional\".', 'André Maurois (1885-1967); biógrafo, novelista y ensayista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1603, 'No te preocupes por si el mundo se acabará hoy. Ya es mañana en Australia.', 'Charles M. Schulz (1922-2000), dibujante estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1604, '\"La realización conlleva la idea de que lo que sé es definitivo\".', 'Pierre Bonnard (1867-1947); pintor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1605, '\"Las ideas no son responsables de lo que los hombres hacen de ellas\".', 'Werner Karl Heisenberg (1901-1976); filósofo y físico alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1606, '\"No se puede olvidar el tiempo más que sirviéndose de él\".', 'Charles Baudelaire (1821- 1867); escritor y poeta francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1607, '\"El ejemplo es una lección que todos los hombres pueden leer\".', 'Morris West (1916-1999); escritor australiano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1608, '\"Casi todo lo que realice será insignificante, pero es muy importante que lo haga\".', 'Mahatma Gandhi (1869-1948); político hindú.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1609, '\"El progreso consiste en el cambio\".', 'Miguel de Unamuno (1864-1936); filósofo y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1610, '\"La ciencia es la estética de la inteligencia\".', 'Gaston Bachelard (1884-1962); filósofo y ensayista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1611, '\"El hombre no puede saltar fuera de su sombra\".', 'Proverbio árabe.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1612, '\"La voluntad es la que da valor a las cosas pequeñas\".', 'Lucio Anneo Séneca (2 AC-65); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1613, '\"La antigüedad del tiempo es la juventud del mundo\".', 'Sir Francis Bacon (1561-1626); filósofo y estadista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1614, '\"Lo que llamamos casualidad no es ni puede ser\nsino la causa ignorada de un efecto desconocido\".', 'Voltaire (1694-1778); filósofo y escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1615, '\"La retentiva es el sello de la capacidad\".', 'Baltasar Gracián (1601-1658); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1616, '\"Si tuviese mi mano cerrada llena de verdades, me guardaría muy bien de abrirla\".', 'Bernard Le Bouvier de Fontenelle (1657-1757); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1617, '\"Los débiles tienen un arma: los errores de los que se creen fuertes\".', 'Georges Bidault (1899-1983); político francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1618, '\"Evitemos suplantar con nuestro mundo el de los demás\".', 'José Ortega y Gasset (1883-1955); filósofo y ensayista español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1619, '\"Dejamos de temer aquello que se ha aprendido a entender\".', 'Marie Curie (1867-1934); física francesa.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1620, '\"No hay cosas sin interés. Tan sólo personas incapaces de interesarse\".', 'Gilbert Keith Chesterton (1874-1936); escritor británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1621, '\"Los ejemplos son diez veces más útiles que los preceptos\".', 'Charles James Fox (1749-1806); estadista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1622, '\"Enseñar no es una función vital, porque no tiene el fin en sí misma;\nla función vital es aprender\".', 'Aristóteles (384 AC-322 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1623, '\"Lo poco que he aprendido carece de valor,\ncomparado con lo que ignoro y no desespero en aprender\".', 'René Descartes (1596-1650); filósofo y matemático francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1624, '\"Nuestro corazón tiene la edad de aquello que ama\".', 'Marcel Prévost (1862-1941); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1625, '\"La ciencia y la sabiduría, lejos de ser una misma cosa,\nno tienen entre sí a menudo conexión alguna\".', 'William Cowper (1731-1800); poeta británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1626, '\"Nada es constante en este mundo sino la inconstancia\".', 'Jonathan Swift (1667-1745); político y escritor irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1627, '\"Apresúrate lentamente\".', 'Suetonio (75-150 d. C.); historiador latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1628, '\"Tiempo es la medida del movimiento entre dos instantes\".', 'Aristóteles (384 AC-322 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1629, 'Mil cosas avanzan. Novecientas noventa y nueve retroceden.\nEsto es el progreso.', 'Henri Frédéric Amiel (1821-1881); escritor y profesor suizo.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1630, '\"En todas las cosas parece existir como ley un círculo\".', 'Publius Cornelius Tacitus (55-115); historiador romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1631, '\"El destino se ríe de las probabilidades\".', 'Edward George Bulwer-Lytton (1803-1873); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1632, 'La contemplación es un lujo, mientras que la acción es una necesidad.', 'Henri Bergson (1859-1941); filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1633, 'Las máquinas me sorprenden con mucha frecuencia', 'Alan Turing (1912-1954), lógico y matemático británico');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1634, '\"La verdadera sabiduría está en reconocer la propia ignorancia\".', 'Sócrates (470 AC-399 AC); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1635, '\"Procuremos más ser padres de nuestro porvenir que hijos de nuestro pasado\".', 'Miguel de Unamuno (1864-1936); filósofo y escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1636, '\"Nueve décimas partes de la sabiduría provienen de ser juicioso a tiempo\".', 'Henry David Thoreau (1817-1862); escritor, poeta y pensador.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1637, 'No te pongas en el lado malo de un argumento\nsimplemente porque tu oponente se ha puesto en el lado correcto', 'Baltasar Gracián, (1601-1658); escritor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1638, '\"Lo peor que hacen los malos es obligarnos a dudar de los buenos\".', 'Jacinto Benavente (1866-1954); dramaturgo español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1639, '\"Dime y lo olvido, enséñame y lo recuerdo, involúcrame y lo aprendo\".', 'Benjamin Franklin (1706-1790); estadista y científico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1640, '\"Por muy larga que sea la tormenta, el sol siempre vuelve a brillar entre las nubes\".', 'Khalil Gibran, (1883-1931); Ensayista, novelista y poeta libanés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1641, '\"El conocimiento viene, la sabiduría se queda\".', 'Alfred Tennyson (1809-1892); poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1642, '\"El corazón es un niño: espera lo que desea\".', 'Proverbio ruso.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1643, '\"En tres tiempos se divide la vida: en presente, pasado y futuro.\nDe éstos, el presente es brevísimo; el futuro, dudoso; el pasado, cierto\".', 'Lucio Anneo Séneca (2 AC-65 DC); filósofo latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1644, '\"Es preciso considerar el pasado con respeto y el presente con desconfianza\nsi se pretende asegurar el porvenir\".', 'Petrus Jacobus Joubert (1831 - 1900); militar bóer.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1645, '\"No pienses con palabras, es mejor que procures ver la imagen\".', 'Jack Kerouac (1922-69); escritor norteamericano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1646, '\"La historia cuenta lo que sucedió; la poesía lo que debió suceder\".', 'Aristóteles (384-322 a. C.); filósofo griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1647, '\"El que quiere interesar a los demás tiene que provocarlos\".', 'Salvador Dalí (1904-1989); pintor y escultor español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1648, '\"La ciencia se puede aprender de memoria, pero la sabiduría no\".', 'Laurence Sterne (1713-1768); novelista y humorista inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1649, '\"El tiempo es una cierta parte de la eternidad\".', 'Marco Tulio Cicerón (106-43 a. C); escritor, orador y político romano.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1650, '\"El escultor piensa en mármol\".', 'Oscar Wilde (1854-1900); dramaturgo, novelista y poeta irlandés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1651, 'El motivo no existe siempre para ser alcanzado,\nsino para servir de punto de mira.', 'Joseph Joubert (1754-1824); moralista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1652, '\"La habilidad y la constancia son las armas de la debilidad\".', 'Maquiavelo, Nicolás (1469 - 1527); político y escritor latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1653, '\"Inspiración y genio son casi la misma cosa\".', 'Víctor Hugo (1802-1885); novelista francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1654, '\"Somos nuestra memoria, somos ese quimérico museo\nde formas inconstantes, ese montón de espejos rotos\".', 'Jorge Luis Borges (1899-1986); escritor argentino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1655, '\"El tiempo saca a luz todo lo que está oculto y encubre\ny esconde lo que ahora brilla con el más grande esplendor\".', 'Horacio Flaco, Quinto (65 a. C. -8 a. C.); poeta latino.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1656, 'Las verdades que revela la ciencia superan siempre a los sueños que destruye.', 'Joseph Ernest Renan (1823-1892); historiador y filósofo francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1657, '\"El sigilo frente a la luz nació con los hombres\".', 'Gonzalo Santonja (1955); poeta español.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1658, '\"Cuida de los pequeños gastos; un pequeño agujero hunde un barco\".', 'Benjamín Franklin (1706-1790); estadista y científico estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1659, '\"La vida es fascinante: sólo hay que mirarla\na través de las gafas correctas\".', 'Alejandro Dumas (1802-1870); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1660, '\"El principio es la mitad del todo\".', 'Pitágoras (570-500 a. C.); filósofo y matemático griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1661, 'La vida sería imposible si todo se recordase.\nEl secreto está en saber elegir lo que debe olvidarse.', 'Roger Martin du Gard (1881-1958); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1662, '\"Los espejos se emplean para verse la cara; el arte para verse el alma\".', 'George Bernard Shaw (1856-1950); escritor irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1663, '\"Todas la cosas ya fueron dichas, pero como nadie escucha es preciso comenzar de nuevo\".', 'André Gide (1859-1951); escritor francés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1664, '\"Generalizar siempre es equivocarse\".', 'Hermann A. Von Keyserling (1880-1946); filósofo y científico alemán.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1665, '\"Cuando las deudas no se pagan porque no se puede, lo mejor es no hablar de ellas y barajar\".\nCamilo José Cela (1916-2002); escritor español.\n\"Nunca es igual saber la verdad por uno mismo que tener que escucharla por otro\".', 'Aldous Huxley (1894-1963); novelista, ensayista y poeta inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1666, '\"Para hacer una tarta de manzana primero tienes que crear un universo\".', 'Carl Sagan (1934-1996); astrónomo estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1667, '\"Ser consciente de la propia ignorancia es un gran paso hacia el saber\".', 'Benjamin Disraeli (1804-1881); estadista británico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1668, '\"El destino se ríe de las probabilidades\".', 'Edward George Bulwer-Lytton (1803-1873); escritor inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1669, 'Es mejor saber algunas de las preguntas que todas las respuestas', 'James Thurber (1894-1961), humorista y dibujante estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1670, 'Al final, todo es un chiste', 'Charles Chaplin (1889-1977); actor, director y guionista bitánico.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1671, 'La manera más rápida de finalizar una guerra es perderla', 'George Orwell (1903-1950), ensayista y novelista británico');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1672, 'Para mejorar nuestro conocimiento debemos aprender menos y contemplar más', 'Rene Descartes (1596-1650), matemático y filósofo francés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1673, 'Un tropezón puede prevenir una caída', 'Proverbio inglés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1674, 'La historia es una filosofía en ejemplos.', 'Dionisio de Halicarnaso (60 a. C.-10 d. C.); historiador griego.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1675, 'En la bandera de la Libertad bordé el amor más grande de mi vida.', 'Federico García Lorca (1898-1936), poeta español');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1676, 'Yo apunté al corazón del público, y por accidente les di en el estómago', 'Upton Sinclair (1878-1968), novelista y político estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1677, 'There are many things that we would throw away\nif we were not afraid that others might pick them up.', 'Oscar Wilde (1854-1900), Irish dramatist, novelist, & poet');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1678, 'El secreto de un buen sermón es tener un buen principio\ny un buen final, y después juntarlos lo más posible', 'George Burns (1896-1996), actor y cómico estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1679, 'La vida es lo que ocurre mientras estamos ocupados haciendo planes', 'John Lennon (1940-1980), cantante y compositor británico');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1680, 'La experiencia enseña lentamente y a base de errores', 'James A. Froude (1818-1894), historiador británico');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1681, 'Nunca te fíes del consejo de un hombre con problemas.', 'Esopo (620 AC-560 AC), esclavo y fabulista griego');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1682, 'Liberaos de vuestra esclavitud mental,\nsolamente nosotros podemos liberar nuestras mentes', 'Bob Marley (1945-1981), Jamaican reggae musician & singer');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1683, 'La edad adulta es cuando te has encontrado con tanta gente\nque cada nueva persona te recuerda a otra', 'Ogden Nash (1902-1971), poeta y humorista estadounidense.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1684, 'La risa es la distancia más corta entre dos personas', 'Victor Borge (1909-2000), comediante y pianista estadounidense de origen danés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1685, 'Empieza cada día con una sonrisa y mantenla todo el dia.', 'W. C. Fields (1880-1946), actor estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1686, 'El universo no es solo más extraño de lo que imaginamos,\nsino que es más extraño de lo que podemos imaginar', 'Sir Arthur Eddington (1882-1944), astrónomo británico');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1687, 'Que algo no funcione como tú esperabas no quiere decir que sea inútil.', 'Thomas A. Edison (1847-1931), inventor estadounidense');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1688, 'Los zorros usan muchos trucos. Los erizos, solo uno. Pero es el mejor de todos.', 'Desiderius Erasmus (1466-1536), filósofo holandés');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1689, 'Quizá este mundo es el infierno de otro planeta.', 'Aldous Huxley (1894-1963), crítico y novelista británico');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1690, 'El habla es el espejo de la mente', 'Séneca (5 AC-65 DC), dramaturgo, filósofo y político Romano');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1691, 'Si te dan un papel pautado, escribe por detrás', 'Juan Ramón Jiménez (1881-1958), escritor español');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1692, 'El dinero no puede comprar amigos, pero puede proporcionarte mejores enemigos', 'Spike Milligan (1918-2002), cómico y músico irlandés de origen indio');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1693, 'Para proteger realmente a los usuarios, no basta con que nosotros sepamos de seguridad;\ndebemos compartir lo que sabemos con los demás.', 'Mikel Urizarbarrena (1961), presidente y fundador de Panda Software');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1694, 'Cuando algo es divertido, busca ahí una verdad escondida', 'George Bernard Shaw (1856-1950), dramaturgo irlandés.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1695, 'La discreción en el habla es más que la elocuencia', 'Sir Francis Bacon (1561-1626), English philosopher');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1696, 'El trabajo que nunca se empieza es el que tarda más en finalizarse', 'J. R. R. Tolkien (1892-1973), erudito y escritor británico');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1697, 'Yo me he construido mi propio mundo, y es mucho mejor que el que nunca haya visto', 'Louise Nevelson (1900-1988), escultor estadounidense de origen ruso');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1698, 'Lo mejor es decir siempre la verdad, a no ser que seas un estupendo mentiroso', 'Jerome K. Jerome (1859 - 1927), escritor humorístico británico');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1699, 'Solo la mano que borra puede escribir la verdad.', 'Eckhart de Hochheim (1260-1328), teólogo y filósofo alemán');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1700, 'La naturaleza señala a los soldados de la vida el lugar en donde han de luchar por ella', 'Blas Infante (1885-1936), poeta y político español');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1701, '\"Por cada persona que quiere enseñar, hay, aproximadamente,\ntreinta personas que no quieren aprender\"\nWalter C. Sellar (1898-1951), humorista británico', '(El 4 de abril de 1887, Anne Sullivan enseñó \"agua\" a Helen Keller)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1702, '\"Cada momento es de oro para los que lo saben ver como tal\"\nHenry Miller (1891-1980), escritor estadounidense', '(4 de abril de 1896, anuncio del oro en Yukon)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1703, '\"Siempre hay un momento en la infancia en el que\nse abre una puerta y deja entrar al futuro.\"\nGraham Greene, (1904-1991) novelista británico', '(Graham Greene murió el 3 de abril de 1991)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1704, '\"Algunas personas no están acostumbradas a un entorno en el que se espera la excelencia\"\nSteve Jobs (1955), informático estadounidense', '(El 1 de abril de 1976, Wozniak y Jobs fundaron Apple Computer)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1705, '\"Si quieres hacer una tarta de manzana partiendo de cero,  primero tienes que crear el universo.\"\nCarl Sagan (1934-1996), astrónomo estadounidense.', '(El 31 de marzo de 1997, la nave Pioneer 10 finalizó su misión)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1706, '\"Todo artista baña su cepillo en su propia alma y pinta su propia naturaleza en sus cuadros\"\nHenry Ward Beecher, ministro presbiteriano (1813-1887)', '(El 30 de marzo de 1853, nació Vincent van Gogh)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1707, '\"La Guerra es una cosa muy seria para confiársela a los militares\"\nGeorges Clemenceau (1841-1929), periodista y estadista francés', '(29 de marzo de 1994, alto el fuego entre Serbios y Croatas)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1708, '\"Tanto dolor se agrupa en mi costado que por doler me duele hasta el aliento\"\nMiguel Hernández (1910-1942), poeta español', '(Miguel Hernández murió el 28 de marzo de 1942)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1709, '\"La vida es como una caja registradora, en la que cada cuenta,\ncada pensamiento, cada acto, como cada venta, se registra y almacena.\"\nFulton J. Sheen (1895-1979), predicador estadounidense', '(27 de marzo de 1914, primera transfusión de sangre con éxito)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1710, '\"Lo que tengo en mi corazón debe salir fuera, esa es la razón por la que compongo\"\nLudwig van Beethoven (1770-1827), compositor alemán', '(El 26 de marzo de 1827 murió Ludwig van Beethoven)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1711, '\"Lo importante no es ganar, sino participar\"\nPierre de Coubertin (1863-1937), fundador de los Juegos Olímpicos modernos.', '(El 23 de marzo de 1896, empezaron los Juegos Olímpicos modernos en Atenas)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1712, '\"La capacidad del hombre para la justicia hace posible la democracia,\npero su inclinación hacia la injusticia la hace necesaria\".\nReinhold Niebuhr (1892-1971), teólogo estadounidense.', '(El 24 de marzo de 1937, Canadá otorga a los negros su derecho al voto)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1713, '\"Me he dado cuenta de que si tuviera que elegir, preferiría tener pájaros a aviones\".\nCharles Lindbergh (1902-1974), aviador estadounidense', '(El 23 de marzo de 1903, los hermanos Wright obtuvieron la patente del avión)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1714, '\"La Biblia dice que amemos a nuestros vecinos y a nuestros enemigos;\nprobablemente porque generalmente son las mismas personas\"\nG. K. Chesterton (1874-1936), escritor británico', '(El 22 de marzo de 1457, la Biblia de Gutemberg se convirtió en el primer libro impreso)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1715, '\"Si no tuviéramos invierno, la primavera no sería tan placentera\"\nAnne Bradstreet (1612-1672), escritora estadounidense', '(La primavera empieza hoy, 20 de marzo a las 18:36 GMT)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1716, '\"Escribo para escaparme... Para escaparme de la pobreza.\"\nEdgar Rice Burroughs (1875-1950), escritor estadounidense', '(Edgar Rice Burroughs murió el 19 de marzo de 1950)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1717, '\"Sin héroes, todos somos gente normal y no sabríamos lo lejos que podemos llegar\"\nBernard Malamud (1914-1986), escritor estadounidense', '(Bernard Malamud murió el 18 de marzo de 1986)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1718, '\"¿Cómo puede haber una conversación si uno de los participantes está sordo?\"\nRudolf Nureyev (1938-1993), bailarín ruso.', '(Rudolf Nureyev nació el 17 de marzo de 1938)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1719, '\"Soy difícil de oír, pero no para los que me quieren escuchar\"\nTiberio Claudio Nerón (14-37), emperador de Roma', '(Tiberio Claudio Nerón murió el 16 de marzo de 37)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1720, '\"Mejor tengáis solo un rey que quinientos\"\nCarlos II, (1630-1685), rey de Inglaterra', '(El 15 de marzo de 1672, Carlos II promulgó la \"Declaración de Indulgencia\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1721, '\"Aquel que tiene una opinión de sí mismo,\npero depende de la opinión y los gustos de los demás, es un esclavo\"\nFriedrich Gottlieb Klopstock (1724-1803), poeta alemán', '(El 14 de marzo de 1803 murió Gottlieb Klopstock)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1722, '\"No podemos resolver una duda sin crear otras nuevas\"\nJoseph Priestly (1733-1804), clérigo y científico británico', '(El 13 de marzo de 1733 nació Joseph Priestly, descubridor del Oxígeno)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1723, '\"Ya no queda casi nadie de los de antes... y los que hay, han cambiado\".\nJesús Cifuentes (1966), letrista y compositor español', '(El 20 de abril de 1893, nació Joan Miró)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1724, '\"Para un buen matrimonio hay que enamorarse muchas veces, siempre de la misma persona.\"\nMignon McLaughlin (1913-1983), periodista estadounidense', '(El 19 de abril de 1956 Grace Kelly se casó con el Príncipe Rainiero)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1725, '\"El mundo está cambiando. Ya no es un mundo sólo para chicos y hombres\"\nAlice Walker (1944), escritora estadounidense', '(El 18 de abril de 1983, Alice Walker Pulitzer por \"El color púrpura\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1726, '\"Te aseguro que debajo de ese insulso exterior hay una absoluta falta de carácter”\nDe Un americano en París (1951).\nAlan Jay Lerner (1918-1986), libretista y compositor estadounidense', '(El 17 de abril de 1924 se formaron los estudios Metro-Goldwyn-Mayer)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1727, '\"Imagínate a tí mismo en una barca en un río,\ncon árboles con mandarinas y cielos de mermelada\"\nDe Lucy in the sky with diamonds,\nde John Lennon (1940-1980), compositor y cantante británico', '(El 16 de abril de 1943, Albert Hofmann descubre los efectos del LSD)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1728, '\"El sentido común es el que juzga las cosas que le dan los otros sentidos\"\nLeonardo da Vinci (1452-1519),  artista italiano', '(Leonardo da Vinci nació el 15 de abril de 1452)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1729, '\"Hay tres maneras de arruinarse: las mujeres, el juego y los técnicos.\nLa más placentera, las mujeres. La más rápida, el juego.\nPero la más segura, los técnicos.\"\nGeorge Pompidou (1911-1974), Presidente de Francia', '(El 14 de abril de 1962, Pompidou fue nombrado Presidente de Francia)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1730, '\"No hay nada mas duro que la suavidad de la indiferencia\"\nJuan Montalvo (1832-1889), ensayista y escritor político ecuatoriano', '(El 13 de abril de 1889 murió Juan Montalvo)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1731, '\"Los vídeos destruyeron la vitalidad del rock and roll.\nAntes, la música decía \'escúchame\'. Ahora dice \'mírame\'.\"\nBilly Joel, cantante y compositor estadounidense', '(El 12 de abril de 1954, Bill Haley grabó \'Rock Around the Clock\')');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1732, '\"El infierno está lleno de músicos aficionados\"\nGeorge Bernard Shaw (1856-1950), dramaturgo irlandés', '(El 11 de abril de 1888 se ignauguró el \"Concertgebouw\", Amsterdam)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1733, '\"Media calamidad es mejor que una entera\"\nT. E. Lawrence (1888-1935), Oficial del ejército británico', '(El 10 de abril de 1932 nació Omar Shariff)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1734, '\"El silencio es la virtud de los locos\"\nFrancis Bacon (1561-1626), filósofo británico', '(El 9 de abril de 1626 murió Francis Bacon)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1735, '\"Los ricos tienen más dinero, y los pobres, más niños\".\nF. Scott Fitzgerald (1896-1940), novelista irlandés', '(8 de abril de 1925, primera edición de \"El gran Gatsby\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1736, '\"Si me ofrecieran rodar mi vida en una película, lo rechazaría\"\nKirk Douglas (1916), actor estadounidense', '(6 de abril de 1925, 1ª película en un avión, B. Airways)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1737, '\"Las matemáticas no mienten, lo que hay son muchos matemáticos mentirosos\"\nHenry David Thoreau (1817-1862) Escritor, poeta y pensador', '(El 18 de mayo de 1872 Nace el matemático y filósofo Bertrand Russell.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1738, '\"La pintura es más fuerte que yo, siempre consigue que haga lo que ella quiere\".\nPablo Picasso (1881-1973) Pintor español.', '(El 17 de mayo de 1510 Muere el pintor Sandro Botticelli).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1739, '\"Para mi, el cine no es un trozo de la vida, sino un trozo de pastel\".\nAlfred Hitchcock (1899-1980); director de cine británico.', '(El 16 de mayo de 1929 se realiza la primera entrega de los Oscars).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1740, '\"Hacer del juego un negocio no puede compararse con el negocio del juego.\"\nAmbrose Bierce (1842-1914), escritor estadounidense', '(El 15 de mayo de 1905 se fundó la ciudad de Las Vegas, Nevada)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1741, '\"La fortuna juega en favor de una mente preparada\".\nLouis Pasteur (1822-1895); químico y microbiólogo francés.', '(El 14 de mayo de 1796 Edward Jenner descubre la vacuna contra la viruela.)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1742, '\"Un banco es un sitio que te prestará dinero si les demuestras que no lo necesitas.\"\nBob Hope (1903-2003), actor estadounidense de origen británico.', '(El 13 de mayo de 1950, primera tarjeta de crédito de Diner\'s Club).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1743, '\"La dictadura es un aria, y nunca llega a ser ópera\"\nEmilia Pardo Bazan (1851-1921), escritora española', '(El 12 de mayo de 1921 murió Emilia Pardo Bazán)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1744, '\"La arquitectura es el arte de desperdiciar espacio\"\nPhilip Johnson (1906-2005), arquitecto estadounidense', '(El 11 de mayo de 1976 murió Alvar Aalto)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1745, '\"Nada viaja más rápido que la luz, excepto las malas noticias\"\nDouglas Adams (1952-2001), humorista británico', '(El 10 de mayo de 1990, el tren francés TGV alcanzó 510,6 km/h)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1746, '\"Cuando Salomón dijo que había un tiempo y un lugar para cada cosa,\nno tenía problemas para aparcar su automóvil.\"\nBob Edwards (1947), periodista estadounidense', '(El 9 de mayo de 1837, nació Adam Opel)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1747, '\"El lío amoroso perfecto es el que puede mantenerse completamente por correo\"\nGeorge Bernard Shaw (1856-1950), dramaturgo irlandés', '(El 5 de mayo de 1794 se estbleció el \"US Post Office\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1748, '\"Una fotografía es un secerto sobre un secreto. Cuanto más te dice, menos sabes.\"\nDiane Arbus, (1923-1971), fotógrafa estadounidense', '(El 7 de mayo de 1888, George Eastman patentó la \"Kodak box camera\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1749, '\"Freud es el padre del psicoanálisis. Y el psicoanálisis no tiene madre.\"\nGermaine Greer (1939), escritora australiana', '(On May 6, 1856, Sigmund Freud was born)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1750, 'La razón siempre ha existido, pero no siempre en una forma razonable', 'Karl Marx (1818-1883), economista y filósofo político alemán');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1751, '\"La música... puede dar nombre a lo innombrable y comunicar lo desconocido\"\nLeonard Bernstein (1918-1990), compositor estadounidense', '(El 4 de mayo de 1976, Kiss ofrece su primer concierto)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1752, '\"El olor es un potente sabio que te transporta a miles de millas y a través de toda tu vida\"\nHelen Keller (1880-1968), educadora de sordomudos estadounidense.', '(El 3 de mayo de 1830, primer servicio regular de trenes de vapor)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1753, '\"El arte es un plagio o una revolución\"\nPaul Gauguin (1848-1903), pintor francés.\n(El 2 de mayo de 1808 se produjo en Madrid un', 'levantamiento popular contra la ocupación francesa).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1754, '\"Es correcto odiar el pecado, pero no odiar al pecador\"\nGiovanni Guareschi (1908-1968) periodista, dibujante y humorista italiano', '(El 1 de mayo de 1908 nació Giovanni Guareschi)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1755, '\"La televisión es un invento que permite que seas entretenido\nen tu salón por gente que nunca tendrías en casa\"\nDavid Frost (1939) Presentedor de TV británico.', '(El 30 de abril de 1939 se hizo la primera demostración pública de TV)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1756, '\"Siempre imaginé que el Paraíso sería algún tipo de biblioteca.\"\nJorge Luis Borges (1899-1986), novelista y poeta argentino.\n(El 29 de abril de 1986, 800.000 libros se destruyeron', 'por el fuego en la biblioteca central de Los Ángeles)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1757, '\"Están locos estos romanos\".\nObelix; guerrero galo ficticio creado por René Goscinny y Albert Uderzo.', '(El 28 de abril de 1927 nace el dibujante Albert Uderzo).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1758, '\"La libre comunicación de los pensamientos y las opiniones\nes uno de los derechos más preciados por el hombre\".\nFrançois de la Rochefoucauld (1613-1680); escritor francés.', '(El 27 de abril de 1791 nace el inventor Samuel Morse).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1759, '\"La esperanza hace que agite el naufrago sus brazos en medio\nde las aguas, aún cuando no vea tierra por ningún lado\".\nOvidio (43 AC-17); poeta latino.', '(El 26 de abril de 1731 muere el escritor Daniel Defoe)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1760, '\"La prueba para saber si puedes hacer un trabajo o no,\nno debería depender de la organización de tus cromosomas\".\nBella Abzug (1920), política estadounidense', '(El 25 de abril de 1953, científicos identifican el ADN)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1761, '\"La innovación es lo que distingue a un líder de los demás\"\nSteve Jobs (1955), informático estadounidense', '(El 24 de abril de 1981 se presentó el IBM-PC)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1762, '\"La literatura es el arte de escribir algo que se lee dos veces;\nel periodismo, el de escribir algo que se lee una vez\"\nCyril Connolly (1903-1974), escritor británico', '(El 23 de abril de 1616 murieron William Shakespeare y Miguel de Cervantes)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1763, '\"Ser es hacer\"\nImmanuel Kant (1724-1804), filósofo alemán', '(El 22 de abril de 1724 nació Immanuel Kant)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1764, '\"No se puede decir que la civilización no avance,\nen cada guerra pueden matarte de una manera distinta\"\nWill Rogers (1879-1935), humorista estadounidense', '(El 21 de abril de 1918, Manfred von Richtofen, \"barón Rojo\", es abatido)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1765, '\"Sí, hay dos caminos por los que puedes ir, pero en el largo\nsiempre hay tiempo de cambiar de carretera\"\nRobert Plant (1948), cantante británico, Led Zeppelin', '(El 31 de mayo de 2003, último vuelo de un Concorde de Air France)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1766, '\"Lo que natura no da, Salamanca no lo presta\"\nLema de la Universidad de Salamanca, fundada en 1218', '(El 30 de Mayo de 1965, primer graduado negro Universidad de Alabama)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1767, '\"No es la montaña lo que se conquista, sino a nosotros mismos.\"\nEdmund P. Hillary (1919), montañero neozelandés', '(El 29 de mayo de 1953, Edmund Hillary alcanzó la cima del Everest)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1768, '\"No hay ninguna razón para que cada persona tenga una computadora en su casa.\"\nKen Olsen (1926), presidente de Digital Equipment en 1977', '(El 28 de mayo de 1936, A. Turing envía \"On Computable Numbers\" para publicar)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1769, '\"Averguénzate de morir hasta que no hayas conseguido una victoria para la humanidad\"\nHorace Mann (1796-1859), educador estadounidense', '(El 27 de mayo de 1923 finalizaron las primeras 24 horas de Le Mans)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1770, '\"Es la segunda vez que me alcanzas con un disparo. No vuelvas a hacerlo\"\nSheriff John T. Chance en \"Rio Bravo\",\nsegún guión de Jules Furthman (1888-1966), guionista estadounidense.', '(El 26 de mayo de 1907 nació John Wayne)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1771, '\"La poesía es la lava de la imaginación, cuya erupción previene un terremoto\"\nLord Byron (1788-1824), poeta británico\n(El 25 de mayo de 1812, un terremoto destruye Caracas, Venezuela)\n\"¿Cuántos años tienen que existir algunas personas para que se les permita ser libres?\"\nBob Dylan (1941), cantautor estadounidense', '(El 24 de mayo de 1941 nació Bob Dylan)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1772, '\"¿Qué sabe el pez del agua donde nada toda su vida?\".\nAlbert Einstein (1879-1955); científico estadounidense de origen alemán.', '(El 23 de mayo de 1707 nace el naturalista Carl von Linneo).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1773, '\"Es un error capital teorizar antes de poseer datos. Uno comienza a alterar los\nhechos para encajarlos en las teorías, en lugar de encajar las teorías en los hechos\"\nSherlock Holmes, detective creado por Sir Arthur Conan Doyle.', '(El 22 de mayo de 1859 nació Sir Arthur Conan Doyle).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1774, '\"La pintura es poesía silenciosa, y la poesía es pintar con el regalo de la palabra\"\nSimónides (556 AC-468 AC), poeta griego', '(El 21 de mayo de 1471 nació Alberto Durero)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1775, '\"Detrás de cada gran fortuna hay un delito\"\nHonore de Balzac (1799-1850), escritor francés', '(El 20 de mayo de 1799 nació Honore de Balzac)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1776, '\"Los hombres son como las estrellas, unos lucen por sí mismos\ny otros reflejan el brillo que reciben\"\nJose Martí (1853-1895), escritor cubano-español', '(El 19 de mayo de 1895, murió José Martí)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1777, '\"Voy a hacer un pronóstico: puede pasar cualquier cosa\"\nRoy Atkinson, (1939), jugador de fútbol británico', '(El 19 de junio de 1912 se estableció la jornada de 8 horas en EEUU)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1778, '\"La única posibilidad de descubrir los límites de lo posible es\naventurarse un poco más allá de ellos, hacia lo imposible\".\nArthur C. Clarke (1917); Escritor inglés de ciencia ficción.', 'El 18 de junio de 1925 Roald Amundsen regresa de su expedición al Polo Norte.');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1779, '\"Hemos aprendido a volar como los pájaros, a nadar como los peces;\npero no hemos aprendido el sencillo arte de vivir como hermanos\".\nMartin Luther King (1929-1968) Religioso estadounidense.', '(El 17 de junio de 1991 desaparece oficialmente el apartheid de Sudáfrica).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1780, '\"La lectura es placer, conocimiento, emoción, enajenación\".\nFernando Trueba (1955); director de cine español.', '(El 16 de junio de 1901 nace el escritor Jacques Prévost).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1781, '\"La felicidad no está en la ciencia, sino en la adquisición de la ciencia\".\nEdgar Allan Poe (1809-1849); escritor estadounidense.', '(El 15 de junio de 1752 Benjamin Franklin demuestra que los relámpagos son electricidad).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1782, '\"Algunos dirán que en fútbol sólo interesa ganar, y otros pensamos que también importa gustar.\"\nJorge Alberto Valdano (1955), jugador de fútbol argentino.', '(El 14 de junio de 1907, Noruega instaura el sufragio femenino)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1783, 'Un país habrá llegado al máximo de su civismo cuando\nen él se puedan celebrar los partidos de fútbol sin árbitros.', 'José Luis Coll (1931), humorista español  (El 13 de junio de 1970, \"The Long and Winding Road\" último nº 1 de \"The Beatles\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1784, '\"El problema con los árbitros es que conocen las reglas, pero no conocen el juego\"\nBill Shankly (1913-1981), manager de fútbol', '(El 12 de junio de 1942, Anne Frank recibe un diario por su cumpleaños)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1785, '\"Un equipo de fútbol es como un buen reloj: si se pierde una pieza\ntodavía es bonito, pero ya no funciona igual.\"\nRuud Gullit (1962), jugador de futbol holandés.', '(El 11 de junio de 1910 nació Jacques-Yves Cousteau)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1786, '\"¿Un rival sin interés atacante?\nEs como intentar hacer el amor con un árbol.\"\nJorge Alberto Valdano (1955), jugador de fútbol argentino', '(El 10 de junio de 1967 finalizó la \"Guerra de los seis dias\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1787, '\"Mucha gente piensa que el fútbol es un juego a vida o muerte,\npero es mucho más importante que eso\".\nWilliam Shankly, (1913-1981), manager del Liverpool', '(Hoy empieza la Copa del Mundo de la FIFA)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1788, '\"Un cleptómano es una persona que se ayuda a sí mismo\nporque no puede ayudarse a sí mismo\"\nHenry Morgan, bucanero británico (1635-1688)', '(El 8 de junio de 1896 tuvo lugar el robo del primer coche)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1789, '\"Una pantalla grande sólo hace el doble de mala a una mala película\".\nSamuel Goldwyn (1882-1974); productor estadounidense.', '(El 7 de junio de 1948 muere el padre del cinematógrafo, Louis Lumière)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1790, '\"El hombre tiene que establecer un final para la guerra.\nSino, ésta establecerá un fin para la humanidad\".\nJohn Fitzgerald Kennedy (1917-1963); político estadounidense.', '(El 6 de junio de 1944 los aliados desembarcan en Normandía)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1791, '\"Muchas veces la gente no sabe lo que quiere hasta que se lo enseñas\"\nSteve Jobs (1955), informático estadounidense', '(El 5 de junio de 1977 empezó a venderse el Apple II)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1792, '\"Puedes estar llamando siempre a la puerta de un hombre sordo\"\nAlexis Zorba, en la novela \"Zorba el griego\" de\nNikos Kazantzakis (1883-1957), escritor griego', '(El 3 de junio de 2001, murió Anthony Quinn)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1793, '\"La historia no es más que una lista de crímenes y desgracias\"\nVoltaire (1694-1778), filósofo francés', '(El 2 de junio de 455, los vándalos saquean Roma)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1794, '\"Se pueden tener hechos sin pensar, pero no podemos pensar sin hechos\"\nJohn Dewey (1859-1952), filósofo estadounidense', '(El 1 de junio de 1952 murió John Dewey)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1795, '\"Ganar sin riesgo es un triunfo sin gloria\"\nPierre Corneille (1606-1684), dramaturgo francés', '(El 28 de junio de 1964, Malcom X crea la \"Afro-American Unity\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1796, '\"¡Si Dios me hiciera una clara señal!\ncomo hacer un gran depósito a mi nombre en un banco suizo.\"\nWoody Allen (1935), actor y director estadounidense', '(El 27 de junio de 1867 el banco de California abre sus puertas)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1797, '\"El cielo es ese viejo pergamino en el que el sol y la luna escriben su diario\"\nAlfred Kreymborg (1883-1966), poeta americano', '(El 26 de junio de 1936 tuvo lugar el vuelo del helicóptero FW61)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1798, '\"El que tiene imaginación, con qué facilidad saca de la nada un mundo\".\nGustavo Adolfo Bécquer (1836-1870); poeta español.', '(El 25 de junio de 1852 nace Antonio Gaudí).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1799, '\"Cuanto mayor es la dificultad, mayor es la gloria\".\nMarco Tulio Cicerón (106 AC-43 AC); escritor, orador y político romano.', '(El 24 de junio de 79 muere el emperador Vespasiano).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1800, '\"Todo progreso está basado en el deseo universal e innato por parte de\ncada organismo de vivir por encima de sus posibilidades\".\nSamuel Butler (1612-1680); poeta inglés.', '(El 23 de junio de 1931 el piloto Willy Post da la primera vuelta al mundo en avión).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1801, '\"En el reino de los ciegos, el tuerto es el rey, pero sigue siendo tuerto\".\nJohan Cruyff (1947), jugador y entrenador de fútbol holandés.', '(El 22 de junio de 1986 Maradona marcó el \"Gol del Siglo\" según la FIFA)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1802, '\"Una clara señal del verano es que la silla se levanta cuando tú lo haces\"\nWalter Winchell (1897-1972), columnista estadounidense.', '( )');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1803, '\"Todo cuanto sé con mayor certeza sobre la moral y las\nobligaciones de los hombres, se lo debo al fútbol\".\nAlbert Camus, (1913-1960), escritor y filósofo francés', '(El 20 de junio de 1963 se establece el \"teléfono rojo\" entre URSS y EEUU)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1804, '\"La máquina deshace al hombre. Ahora que la\nmáquina es tan perfecta, el ingeniero no es nadie\"\nRalph Waldo Emerson (1803-1882), escritor estadounidense', '(El 30 de julio de 1863 nació Henry Ford)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1805, '\"No es oro todo lo que reluce, ni todo lo que anda errante está perdido\".\nGandalf, en el libro \"La comunidad del anillo\", de\nJohn Ronald Reuel Tolkien (1892-1973), escritor británico', '(El 29 de julio de 1954 de publicó \"La comunidad del anillo\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1806, '\"¡Libertad! en sus costas se oyó, La indolencia de esclavo sacude\"\nDel himno nacional de Perú', '(El 28 de julio, Perú celebra el día de la independencia)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1807, '\"La falta de dinero no es un obstáculo. La falta de ideas es un obstáculo.\"\nKen Hakuta (1950), presentador de TV estadounidense.\n(El 27 de julio de 1967 se instaló en el Reino Unido', 'el primer cajero automático del mundo)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1808, '\"La vida de un hombre es como montar en bicicleta: si se para, se cae\".\nWilliam Golding (1911-1993), novelista británico', '(El 25 de julio de 1819 se patentó la bicicleta)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1809, '\"La moda es una forma de fealdad tan intolerable\nque tiene que ser cambiada cada seis meses\"\nBernard Shaw (1856-1950), escritor irlandés', 'El 25 de julio de 1946 se exhibe el primer bikini en el Paris Fashion Show');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1810, '\"Nuestras vidas no están en manos de los dioses, sino en manos de nuestros cocineros\".\nLin Yutang (1895-1976), escritor y filólogo chino', 'El 24 de julio de 1938 se inventó el café instantáneo');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1811, '\"¿Qué es en el fondo actuar, sino mentir?\n¿Y qué es actuar bien, sino mentir convenciendo?\".\nSir Laurence Olivier (1907-1989); actor, director y productor británico.', '(El 23 de julio de 1966 muere el actor Montgomery Clift).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1812, '\"Probablemente se ha hecho más daño a la Tierra en el siglo XX\nque en toda la historia anterior de la humanidad\".\nJacques-Yves Cousteau (1910-1997); marino e investigador francés.', '(El 22 de julio de 1822 nace el monje y naturalista Gregor Mendel).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1813, '\"La obra clásica es un libro que todo el mundo admira, pero que nadie lee\".\nErnest Hemingway (1899-1961) Escritor estadounidense.', '(El 21 de julio de 1899, nace Ernest M. Hemingway).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1814, '\"Un pequeño paso para un hombre, pero un gran salto para la humanidad\".\nNeil Armstrong (1930); astronauta estadounidense.', '(El 20 de julio de 1969, el Hombre llega a la Luna).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1815, '\"El principal enemigo de la creatividad es el buen gusto.\"\nPablo Picasso (1881-1973); pintor español.', '(El 19 de julio de 1834, nació Edgar Degas).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1816, '\"Necesitas mucha pasión, porque todo lo que haces con placer lo haces bien\"\nJuan Manuel Fangio (1911-1995), piloto de carreras argentino', '(El 17 de julio de 1995, murió Juan Manuel Fangio)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1817, '\"Adelante, hijos de la patria, el día de gloria ha llegado\"\nDel himno nacional francés', '(El 14 de julio Francia celebra su fiesta nacional)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1818, '\"El verdadero poema es la mente del poeta\"\nRalph Waldo Emerson (1803-1882), poeta norteamericano.', '(El 13 de julio de 1885 fallece Rosalía de Castro).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1819, '\"Amor, cuántos caminos hasta llegar a un beso, ¡qué soledad errante hasta tu compañía!\"\nPablo Neruda (1904-1973), poeta chileno', '(El 12 de julio de 1904 nació Pablo Neruda)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1820, '\"La experiencia es algo que no consigues hasta justo depués de necesitarla\"\nLaurence Olivier (1907-1989), actor británico', '(El 11 de julio de 1989 murió Laurence Olivier)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1821, '\"La gente generalmente confunde lo que leen en los periódicos con las noticias\"\nAbbott Liebling (1904-1963), periodista estadounidense', '(El 10 de julio de 1925 se crea la agencia de noticias soviética TASS)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1822, '\"Si no fuera duro, todo el mundo lo haría. Es la dureza lo que lo hace grande.\"\nTom Hanks (1956), actor estadounidense', '(El 9 de julio de 1956 nació Tom Hanks)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1823, '\"La fuerza lo conquista todo, pero sus victorias son breves\"\nAbraham Lincoln (1809-1865), presidente estadounidense', '(El 8 de julio de 1099 comenzó la primera cruzada)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1824, '\"La televisión es un nuevo medio. Se le llama medio porque no está terminado del todo.\"\nFred Allen (1894-1956), cómico estadounidense', '(El 7 de julio de 1954, se emitió el primer disco de Elvis Presley)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1825, '\"Que tus hijos saquen fuerzas del pasado,\nque tus niños solamente sigan el camino de la virtud\"\nDel himno nacional de Lituania', '(El 6 de julio Lituania celebra su fiesta nacional)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1826, '\"Muera la opresión, compatriotas fieles: la fuerza es la unión\"\nDel himno nacional de Venezuela', '(El 5 de Julio, Venezuela celebra su fiesta nacional)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1827, '\"Dime si esa bandera de estrellas brillantes todavía ondea\nsobre la tierra de la libertad y el hogar de los valientes\"\nDel himno nacional estadounidense', '(El 4 de julio, Estados Unidos de América celebra su fiesta nacional)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1828, '\"La segregación es el resultado de un encuentro ilícito entre la injusticia y la inmoralidad\"\nMartin Luther King Jr. (1929-1968), clérigo estadounidense.', '(El 3 de julio de 1964, el pres. Johnson firma la Ley de Derechos Civiles)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1829, '\"Si Dios hubiera querido que voláramos, debería habernos dado los billetes\"\nMel Brooks (1926), actor y director estadounidense', '(El 2 de julio de 1900, primer vuelo del Zeppelin, en el lago Constanza)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1830, '\"Su valor, de Fe impregnado, protegerá a nuestros hogares y derechos\".\nDel himno nacional de Canadá', '(El 1 de Julio se celebra el Día Nacional de Canadá)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1831, '\"Es un milagro que la curiosidad sobreviva a la educación reglada\"\nAlbert Einstein (1879-1955), físico estadounidense de origen alemán', '(El 30 de junio de 1905, Albert Einstein presentó la relatividad especial)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1832, '\"La fantasía, aislada de la razón, sólo produce monstruos imposibles.\nUnida a ella, en cambio, es la madre del arte y fuente de sus deseos\".\nFrancisco de Goya (1746-1828); pintor español.', '(El 21 de agosto de 1890 nace H.P. Lovecraft, escritor estadounidense).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1833, '\"Si viéramos realmente el Universo, tal vez lo entenderíamos\".\nJorge Luis Borges (1899-1986); escritor argentino.', '(El 20 de agosto de 1975 se lanzó el Viking I para tomar imágenes de la superficie de Marte).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1834, '\"Es propio de hombres de cabezas medianas embestir contra\ntodo aquello que no les cabe en la cabeza\".\nAntonio Machado (1875-1939); poeta y prosista español.', '(El 19 de agosto de 1936, el poeta Federico García Lorca es fusilado).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1835, '\"La resignación es un suicidio cotidiano\".\nHonoré de Balzac (1799-1850); escritor francés.', '(El 18 de agosto de 1850 muere el novelista Honoré de Balzac).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1836, '\"Cuando muera, simplemente sigue poniendo los discos\".\nJimi Hendrix (1942-1970); músico de rock estadounidense.', '(El 16 de agosto de 1977 muere el cantante de rock Elvis Presley).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1837, '\"Sólo hay una guerra que puede permitirse el ser humano: la guerra contra su extinción\".\nIsaac Asimov (1920-1992) Escritor y bioquímico estadounidense.', '(El 15 de agosto de 1945 se firma el armisticio que acabó la Segunda Guerra Mundial).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1838, '\"El autor que ha alcanzado fama, corre el riesgo de verla disminuir,\ntanto si sigue escribiendo como si deja de hacerlo.\nSamuel Johnson (1709-1784) Escritor inglés.', '(El 14 de agosto de 1591 fallece el escritor español Fray Luis de León).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1839, '\"La civilización es una carrera entre la educación y la catástrofe\".\nHerbert George Wells (1866-1946); novelista inglés.', '(El 13 de agosto de 1946 muere el escritor H.G. Wells).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1840, '\"Estos son mis principios. Si no le gustan tengo otros\".\nGroucho Marx (1890-1977); actor estadounidense.', '(El 12 de agosto de 1881 nace el cineasta Cecil B. de Mille)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1841, '\"La belleza perece en la vida, pero es inmortal en el arte\".\nLeonardo Da Vinci (1452-1519); pintor, escultor e inventor italiano.', '(El 11 de agosto de 1793 se inaugura el Museo del Louvre en París).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1842, '\"A veces creo que hay vida en otros planetas, y a veces creo que no.\nEn cualquiera de los dos casos la conclusión es asombrosa\".\nCarl Sagan (1934-1996); astrónomo estadounidense.', '(El 10 de agosto de 1675 se funda el Observatorio de Greenwich).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1843, '\"No sé con qué armas se luchara en la tercera Guerra Mundial, pero sí sé\ncon cuáles lo harán en la cuarta Guerra Mundial: palos y mazas.”\nAlbert Einstein (1879-1955) Científico estadounidense de origen alemán.', '(El 9 de agosto de 1945, una bomba atómica destruye Nagasaki, Japón).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1844, '\"Abogado: uno que nos protege del robo llevándose la tentación\".\nH. L. Mencken (1880-1956); editor estadounidense.', '(El 8 de agosto de 1963, \"Gran Robo del Tren\" en Inglaterra).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1845, '\"Las imágenes llegaron y te rompieron el corazón, échale la culpa al vídeo\".\nTrevor Charles Horn (1949), letrista pop Británico.', '(El 7 de agosto de 1955, se vendió la primera radio transistorizada)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1846, '\"Morir antes que ver humillado de la Patria el augusto pendón\"\nDel hinmo nacional de Bolivia', '(El 6 de agosto Bolivia celebra el día de la independencia)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1847, '\"Marilyn Monroe hace a un hombre orgulloso de ser un hombre\"\nClark Gable (1901-1960), actor estadounidense', '(El 5 de agosto de 1962 murió Marilyn Monroe)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1848, '\"Hollywood es un sitio en el que las estrellas brillan hasta que les salen arrugas\"\nVictor Mature (1913-1999), actor estadounidense', '(El 4 de agosto de 1999 murió Victor Mature)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1849, '\"Si Cristóbal Colón hubiera tenido un comité de consejeros,\nprobablemente seguiría todavía en el puerto\"\nArthur Goldberg (1908-1990), abogado estadounidense', '(El 3 de Agosto de 1492, Colón inicia su travesía desde España)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1850, '\"Un pájaro no canta porque tenga una respuesta. Canta porque tiene una canción\".\nProverbio chino', '(El 2 de agosto de 1921 murió el tenor Enrico Caruso)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1851, '\"Traspasa la oscuridad que nos cubre con Su brillo de sol clarificador,\nsentiremos y entenderemos que Dios mora en esta tierra\"\nDel himno nacional suizo', '(El 1 de agosto, Suiza celebra su fiesta nacional)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1852, '\"El amor no es solo mirar al otro, es mirar en la misma dirección\".\nAntoine de Saint-Exupery (1900-1944), piloto y escritor francés.', '(El 31 de julio de 1944 murió Antoine de Saint-Exupery)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1853, '\"No hay nada peor que una imagen enfocada de un concepto difuso\"\nAnsel Adams (1902-1984), fotógrafo estadounidense', '(El 4 de septiembre de 1888, George Eastman registró la marca Kodak)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1854, '\"El silencio del pueblo es un aviso para el rey\"\nProverbio francés', '(El 3 de septiembre de 1189 se coronó a Ricardo \"Corazón de León\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1855, '\"Si ves un deporte, es divertido. Si lo practicas, es entretenido.\nSi trabajas en él, es golf\".\nBob Hope (1903-2003), actor estadounidense de origen británico.', '(El 2 de septiembre de 1937 murió Pierre de Coubertin)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1856, '\"Nuestra Eslovaquia estaba profundamente dormida hasta ahora,\npero la luz de los rayos la agitan para revivirla\"\nDel himno nacional Eslovaco', '(El 1 de septiembre, Eslovaquia celebra su fiesta nacional)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1857, '\"El propósito de la educación es cambiar\nuna mente vacía por una abierta\"\nMalcolm Forbes (1919-1990), editor estadounidense', '(El 31 de agosto de 1870, nació la educadora Maria Montessori)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1858, '\"Haz la suspensión ajustable y la ajustarán mal\"\nSir Colin Chapman (1928-1982), británico, fundador de la compañía de coches Lotus.', '(El 30 de Agosto de 1937, nació el piloto Bruce McLaren)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1859, '\"No preguntes por quién doblan las campanas, doblan por ti\"\nJohn Donne (1572-1631), poeta británico', '(El 29 de agosto de 1982 murió Ingrid Bergman)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1860, '\"¡Triste época la nuestra! Es más fácil desintegrar un átomo que un prejuicio\".\nAlbert Einstein (1879-1955); científico estadounidense de origen alemán.', '(El 28 de agosto de 1833 se reconoce en USA el derecho a voto de la mujer).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1861, '\"Presiento que este es el comienzo de una gran amistad\".\nDe \"Casablanca\", del director de cine Michael Curtiz (1886-1962)', '(El 27 de agosto de 1910 Thomas A. Edison presenta el kinetófono o cinematógrafo con sonido).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1862, '\"Encuentro la televisión muy educativa. Cada vez que alguien la enciende,\nme retiro a otra habitación y leo un libro\".\nGroucho Marx (1890-1977); actor estadounidense.', '(El 26 de agosto de 1936, la BBC realiza la primera transmisión mundial de televisión).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1863, '\"La ciencia es la progresiva aproximación del hombre al mundo real\".\nMax Planck (1858-1947); físico alemán.', '(El 25 de agosto de 1867 muere el físico y químico Michael Faraday).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1864, '\"La muerte es dulce; pero su antesala, cruel\".\nCamilo José Cela (1916-2002); escritor español.', '(El 24 de agosto de 79 Pompeya y Herculano son sepultadas por la lava del Vesubio).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1865, '\"Dios no ha creado fronteras. Mi objetivo es la amistad con el mundo entero\".\nMahatma Gandhi (1869-1948); político y pensador indio.', '(El 25 de agosto de 1961 se prohíbe a los ciudadanos de Berlín occidental entrar en Berlín Este).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1866, '\"Hay cosas peores que quemar libros, una de ellas es no leerlos\".\nRay Bradbury (1920); escritor estadounidense.', '(El 22 de agosto de 1920 nace Ray Bradbury).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1867, '\"Los débiles nunca pueden perdonar. El perdón es el atributo de los fuertes\"\nMahatma Gandhi (1869-1948), líder nacionalista de India', '(El 11 de septiembre de 1906 Gandhi inicia la no-violencia)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1868, '\"En Hollywood, un acuerdo de divorcio equitativo significa\nque cada parte obtiene un cincuenta por ciento de publicidad\".\nLauren Bacall (1924); actriz norteamericana.', '(El 10 de septiembre de 1924 nace Lauren Bacall).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1869, '\"Hice un curso de lectura rápida y leí \'Guerra y paz\' en veinte minutos. Trata sobre Rusia.\"\nWoody Allen (1935), director estadounidense.', '(El 9 de septiembre de 1828 nació Leo Tolstoy)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1870, '\"La voz humana es el más bello instrumento, pero es el más difícil de tocar\"\nRichard Strauss (1864-1949), compositor alemán', '(El 9 de septiembre de 1949 murió Richard Strauss)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1871, '\"Es bello, es fuerte, impávido coloso. En tu futuro se refleja esa grandeza\"\nDel himno nacional de Brasil', '(El 7 de septiembre Brasil celebra su fiesta nacional)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1872, '\"En un mundo loco, solo los locos están cuerdos\"\nAkira Kurosawa (1910-1998), director japonés', '(El 6 de septiembre de 1998 murió Akira Kurosawa)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1873, '\"La ausencia extingue las pequeñas pasiones y hace crecer las grandes,\nigual que el viento apaga una vela y aviva un fuego\"\nFrançois de La Rochefoucauld, (1613-1680), escritor francés', '(El 5 de septiembre de 1666 finalizó el gran incendio de Londres)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1874, '\"Un hobby debe hacer pasar el tiempo, no llenarlo\"\nNorman Bates en \"Psicosis\" (1960), según la novela de\nRobert Bloch (1917-1994), escritor estadounidense', '(El 12 de septiembre de 1992 murió Anthony Perkins, actor)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1875, '\"Los hombres tardan más en reconocer las bendiciones que las desgracias\"\nTitus Livius (59 AC-17 DC), autor e historiador romano', '(El 13 de septiembre de 1985, Nintendo lanza Super Mario Bros)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1876, '\"Mis dos dedos en la máquina de escribir nunca han\nconectado con mi cerebro. Mi mano en un lápiz lo hace\"\nGraham Greene (1904-1991), novelista británico', '(El 14 de septiembre de 1886 se patentó la cinta de máquina de escribir)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1877, '\"Si quieres tener paz, no hables con tus amigos. Habla con tus enemigos\"\nMoshe Dayan (1915-1981) general y político israelí.', '(El 17 de septiembre de 1978, se firmaron los acuerdos de Camp David)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1878, '\"Ciña oh patria! tus sienes de oliva de la Paz el arcángel divino\"\nDel himno nacional de Mexico', '(El 16 de septiembre México delebra su día de la independencia)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1879, '\"La libertad es el derecho a vivir como queramos\"\nEpictetus (55-135), filósofo griego\n(El 15 de septiember, Costa Rica, El Salvador, Guatemala,', 'Honduras y Nicaragua celebran su día de la independencia)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1880, '\"¡Viajar es la ruina de la felicidad! No es posible\nmirar a un edificio después de ver Italia.\"\nFanny Burney (1752-1840), novelista británica', '(El 20 de septiembre de 1870 se completó la unificación de Italia)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1881, '\"Un libro clásico es el que nunca deja de decir lo que tiene que decir\"\nItalo Calvino (1923-1985), escritor italiano', '(El 19 de septiembre de 1985 murió Italo Calvino)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1882, '\"Que o la tumba serás de los libres O el asilo contra la opresión.\"\nDel himno nacional de Chile', '(El 18 de septiembre, Chile celebra su fiesta nacional)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1883, '\"Prefiero vivir en un mundo en el que mi vida está rodeada por el\nmisterio que vivir en un mundo tan pequeño que lo pudiera comprender\"\nHarry Emerson Fosdick (1878-1969), clérigo estadounidense', '(El 27 de septiembre de 1822 se descifra la piedra de Rosetta)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1884, '\"Me gustaría haber inventado los pantalones vaqueros.\nTienen expresividad, modestia, \'sex appeal\' y  simplicidad\"\nYves Saint Laurent (1940), diseñador de moda francés', '(El 26 de septiembre de 1902 murió Levi Strauss)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1885, '\"Cuánto hemos perdido al dejar de escribir cartas.\nNo puedes releer una llamada de teléfono\".\nLiz Carpenter (1920), escritora feminista estadounidense', '(El 25 de septiembre de 1956, primer cable telefónico transoceánico)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1886, '\"Sólo existen tres deportes: el toreo, las carreras de coches\ny el montañismo. El resto son simples juegos\"\nErnest Hemingway (1899-1961), novelista estadounidense', '(El 24 de septiembre de 1948 se fundó Honda Motor Company)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1887, '\"El otoño es una segunda primavera, donde cada hoja es una flor.\"\nAlbert Camus (1913-1960), escritor y filósofo francés', '(Hoy, 23 de septiembre, empieza el otoño a las 04:03 UTC)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1888, '\"La paz no es la ausencia de guerra, es una virtud, un estado de la\nmente, una disposición a la benevolencia, la confianza y la justicia.\"\nBaruch Spinoza (1632-1677), filósofo holandés', '(El 21 de septiembre es el Día Internacional de la Paz)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1889, '\"El derecho a ser dejado en paz es, sin duda, el principio de todas las libertades\"\nWilliam O. Douglas (1898-1980), juez del tribunal supremo de EEUU', '(El 16 de octubre de 1898 nació William O. Douglas)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1890, '\"Libertad sigfnifica tener la oportunidad de ser\nlo que nunca pensamos que podríamos ser\"\nDaniel J. Boorstin (1914-2004), educador estadounidense', '(El 15 de octubre de 1940 se estrenó la película \"El gran dictador\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1891, '\"El dolor llega al corazón a la velocidad de la luz,\npero la verdad se mueve hacia él tan lenta como un glaciar\"\nBarbara Kingsolver (1955), escritora y activista estadounidense', '(On October 14, 1947, Chuck Yeager flew faster than the speed of sound)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1892, '\"Ningún hombre sensible mira a sus pies sobre el suelo.\nMira adelante para ver qué tipo de suelo va a pisar después.\"\nErnest Haycox (1899-1950), escritor estadounidense', '(El 13 de octubre de 1950 murió Ernest Haycox)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1893, '\"La riqueza no hace al hombre rico, simplemente, le hace más ocupado\"\nCristobal Colón (1451 - 1506), Navegante italiano', '(El 12 de Octubre, Cristobal Colón descubrío América)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1894, '\"Tras la muerte de un escritor, leer su diario es como recibir una larga carta\"\nJean Cocteau (1889-1963), escritor y director francés', '(El 11 de octubre de 1963, murió Jean Cocteau)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1895, '\"Si quieres un final feliz, depende de cuándo acabas la historia\"\nOrson Welles (1915-1985), director y actor estadounidense', '(El 10 de octubre de 1985 murió Orson Welles)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1896, '\"Yo no soy un libertador, los libertadores no existen.\nLa gente se libera a sí misma\".\nErnesto \"Che\" Guevara (1928-1967), revolucionario argentino', '(El 9 de Octubre de 1967 murió Ernesto Guevara).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1897, '\"Cada uno es una luna, y tiene una cara oculta que nunca enseña a nadie \"\nMark Twain (1835-1910), escritor estadounidense', '(El 7 de octubre de 1959 se vio la cara oculta de la luna)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1898, '\"Intenta lo imposible para mejorar tu trabajo\"\nBette Davis (1908-1989), actriz estadounidense', '(El 6 de octubre de 1989, murió Bette Davis)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1899, '\"La gente se dará cuenta de que el software no es un producto,\nse usa para conseguir un producto\"\nLinus Torvalds (1969), informático finlandés', '(El 5 de octubre de 1991 se publicó el primer kernel de Linux)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1900, '\"Hay más lagrimas derramadas sobre oraciones respondidas\nque sobre oraciones sin respuesta\"\nSta. Teresa de Ávila (1515-1582), monja, mística y escritora española', '(El 4 de octubre de 1582 murió Santa Teresa de Ávila)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1901, '\"La unión hace la fuerza\"\nEsopo (S. VI A. C.), autor clásico griego)', '(El 3 de octubre de 1990, Alemania se re-unificó)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1902, '\"Existen diferencias entre la filosofía y los adhesivos para el coche\"\nCharles M. Schulz (1922-2000), dibujante de cómics estadounidense', '(El 2 de octubre de 1950 se publicó el primer cómic de \"Peanuts\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1903, '\"Hay que sentir el pensamiento y pensar el sentimiento.\"\nMiguel de Unamuno (1864-1936), filósofo español.', '(El 29 de septiembre de 1864 nació Miguel de Unamuno)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1904, '\"No saben los cantores de agachadas, no callarán jamás de frente al crimen\"\nHoracio Guarany (1925), compositor y cantante argentino', '(El 28 de septiembre de 1932 nació el cantante chileno Victor Jara)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1905, '\"Valientemente avanzamos en los nuevos tiempos, libres y dedicados\"\n(Del himno nacional Austriaco)', '(El 26 de Octubre Austria celebra su Fiesta Nacional)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1906, '\"No quiero hacer nada elegante, quiero tener ideas antes de empezar una pieza\"\nGeorges Bizet (1838-1875), compositor francés', '(El 26 de octubre de 1838 nació George Bizet)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1907, '\"Unidos, nos mantendremos en pie; divididos, nos caeremos\"\nEsopo, (620 AC-560 AC), fabulista griego clásico', '(El 24 de octubre de 1945 se fundaron las Naciones Unidas)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1908, '\"Algunos políticos sostienen que la única manera de hacer seguro\na un revolucionario es darle un escaño en el parlamento\"\nC.S. Lewis (1898-1963), novelista británico.', '(El 23 de octubre de 1707, se reúne el primer parlamento británico)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1909, '\"Ser una mujer es una tarea terriblemente difícil,\nya que consiste principalmente en tratar con hombres\"\nJoseph Conrad (1857-1924), novelista británico', '(El 21 de octubre de 1945 las mujeres votan por primera vez en Francia)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1910, '\"En ciencias, se intenta decir a la gente algo que nadie\nsabía antes, pero la poesía es exactamente al contrario.\"\nPaul Dirac (1902-1984), físico y Premio Nobel británico', '(El 20 de octubre de 1984, murió Paul Dirac)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1911, '\"La salud es un estado del que la medicina no tiene nada que decir.\"\nWystan Hugh Auden (1907-1973), poeta británico', '(El 19 de octubre de 1943, se aísla la Estreptomicina)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1912, '\"Hacer radio es como cocinar. Pasas mucho tiempo preparándolo,\ny en el momento que está listo, se va\".\nDavia Nelson, productora de radio\n(El 18 de octubre de 1954, Texas Instruments anuncia', 'la primera radio de transistores)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1913, '\"La pobreza es la peor forma de violencia\"\nMahatma Gandhi (1869-1948), líder político y espiritual de India', '(Hoy, 17 de octubre, es el Día para la erradicación de la pobreza)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1914, '\"Una abuela es aquella persona que dice no saber quién eres en Halloween\"\nErma Bombeck (1927-1996), humorista estadounidense', '(Hoy, 31 de octubre, se celebra la fiesta de Halloween)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1915, '\"Si sigues pensando en qué quieres hacer o qué quieres que pase, ni lo harás, ni pasará.\"\nErasmo de Rotterdam (1466-15363), humanista holandés', '(El 27 de octubre de 1466 nació Erasmo de Rotterdam)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1916, '\"Mucha gente pasa por la Universidad, pero las Universidad no pasa por ellos\"\nAnónimo', '(El 28 de octubre de 1538 se fundó la primera Universidad en América)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1917, '\"Las matemáticas no solo son reales, sino que son la única realidad\"\nMartin Gardner (1914), matemático lúdico estadounidense', '(El 29 de octubre de 1675, primer uso del símbolo ? para integrales)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1918, '\"El valor está un paso por delante del miedo\"\nColeman Young, (1918-1997), político estadounidense\n(El 30 de octubre de 1938, se retransmite \"La guerra de los mundos\",', 'de Orson Welles causando el pánico en Estados Unidos)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1919, '\"Ciertamente, habría razones para volverse loco si no fuese por la música\"\nPeter Tchaikovsky (1840-1893), compositor ruso', '(El 6 de noviembre de 1893, murió Peter Tchaikovsky)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1920, '\"Año 50 AC. Toda la Galia está ocupada por los romanos... ¿Toda? !No!\"\nRené Goscinny, (1926-1977), escritor de cómic francés', '(El 5 de noviembre de 1977, murió René Goscinny)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1921, '\"Como a nadie se le puede forzar para que crea, a nadie se le puede forzar para que no crea\"\nSigmund Freud (1856-1939), neurólogo austriaco\n(El 4 de noviembre de 1899 se publicó', '\"La interpretación de los sueños\" de Freud)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1922, '\"Nunca seremos una civilización avanzada mientras que la lluvia\npueda retrasar el lanzamiento de una nave espacial\"\nGeorge Carlin (1937), cómico estadounidense', '(El 3 de noviembre de 1973, la nave Mariner 10 es lanzada a Mercurio)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1923, '\"Lo que creemos que son los motivos de nuestra conducta no son más que sus pretextos\".\nMiguel de Unamuno (1864-1936), escritor y filósofo español', '(El 2 de noviembre de 1988, R. Morris creó el primer gusano informático)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1924, '\"La luz de la unidad es tan potente que puede iluminar toda la tierra\"\nBaha\'u\'llah (1817-1892), teólogo y filósofo iraní', '(El 1 de noviembre de 1993, entró en vigor el tratado de Maastrich)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1925, '\"Al fin y al cabo no eres más que otro ladrillo en el muro\"\nGeorge Waters (1943), músico británico, miembro de Pink Floyd\n(El 9 de noviembre de 1989, los berlineses', 'empiezan a demoler el muro de Berlín)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1926, '\"El placer de leer es doble cuando se vive con otra persona con la que compartir los libros\"\nKatherine Mansfield (1888-1923), escritora neozelandesa\n(El 8 de noviembre de 1602, la biblioteca Bodleian de la', 'Universidad de Oxford se abrió al público)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1927, '\"La primera obligación de un periódico es ser preciso.\nSi se es preciso, el resto es bello\".\nHerbert B. Swope (1882-1958), periodista estadounidense', '(El 7 de noviembre de 1665, se publica \"The London Gazette\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1928, '\"No podemos resolver problemas pensando\nde la misma manera que cuando los creamos\"\nAlbert Einstein (1879-1955), físico estadounidense de origen alemán', '(El 21 de noviembre de 1905, se publicó la ecuación e=mc²)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1929, '\"El éxito es un pésimo profesor.\nLleva a la gente inteligente a pensar que no pueden perder\"\nBill Gates (1955), fundador de Microsoft', '(El 20 de noviembre de 1985, se lanzó Microsoft Windows 1.0)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1930, '\"Un buen diseño no venderá un mal producto, pero hará\nque un gran producto alcance su máximo potencial\"\nJohn Watson Sr. (1874-1956), fundador de IBM', '(El 19 de noviembre de 1970, se retira del mercado el IBM 1620)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1931, '\"Nuestras amadas hijas, cerca aparecen nuestros hijos, cantando que la fortuna, sonría aquí\"\nDel himno nacional letón', '(El 18 de noviembre, Letonia celebra el Día de la Independencia)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1932, '\"Si no se sabe a qué puerto se quiere navegar, ningún viento es favorable\"\nSeneca (4 AC-65 DC), filósofo romano', '(El 17 de noviembre de 1869, el Canal de Suez fue inaugurado)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1933, '\"Puedes hablar de la tiranía de Nerón y Tiberio,\npero la tiranía real es la del vecino de al lado\"\nWalter Bagehot (1826-1877), analista político británico', '(El 16 de noviembre de 42 AC, nació Tiberio, Emperador de Roma).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1934, '\"Los ordenadores hacen fáciles muchas cosas,\npero muchas de esas cosas no necesitan hacerse\"\nAndy Rooney (1919), periodista estadounidense', '(El 15 de noviembre de 1971 Intel lanzó el microprocesador 4004).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1935, '\"La pintura es la nieta de la naturaleza. Está relacionada con Dios\".\nRembrandt Harmenszoon van Rijn, (1606-1669), pintor holandés', '(El 14 de noviembre de 1840, nació Claude Monet)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1936, '\"Un hombre puede morir, las naciones pueden nacer y caer,\npero una idea siempre perdurará.\"\nJohn F. Kennedy (1917-1963), 35º Presidente de los Estados Unidos', '(El 22 de noviembre de 1963, JFK fue asesinado en Dallas, EE.UU.)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1937, '\"El deporte es un fenómeno internacional, como la ciencia o la música\"\nAvery Brundage (1887-1975) presidente del Comité Olímpico Internacional', '(El 30 de noviembre de 1872, se jugó el primer partido internacional de fútbol)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1938, '\"He fallado una y otra vez en mi vida, por eso he conseguido el éxito.\"\nMichael Jordan (1963), deportista estadounidense', '(El 28 de noviembre de 1899, el F.C. Barcelona fue fundado)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1939, '\"Un arquitecto prueba sus habilidades convirtiendo los defectos de un sitio en ventajas.\"\nGian Lorenzo Bernini (1598-1680), arquitecto y escultor italiano.', '(El 28 de noviembre de 1680 falleció Gian Lorenzo Bernini)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1940, '\"Si pudiera explicarlo a una persona normal, no me hubiera merecido un premio Nobel\"\nRichard Feynman (1918-1988), físico teórico estadounidense', '(El 27 de noviembre de 1895, se establecen los Premios Nobel)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1941, '\"Es tan corto el amor y tan largo el olvido\"\nPablo Neruda, poeta chileno (1904-1973)', '(El 23 de Noviembre de 1973 falleció Pablo Neruda)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1942, '\"Los premios acaban corrompiéndose, los amigos no acumulan polvo\"\nJesse Owens (1913-1980), atleta estadounidense', '(El 10 de diciembre de 1901, entrega de los primeros Premios Nobel)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1943, '\"En informática, pasar de lo obvio a lo útil\nes una auténtica definición de la palabra \'frustración\'.\"\nAlan Jay Perlis (1922-1990) informático estadounidense', '(El 9 de diciembre de 1888, H. Hollerith instala un \"computador\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1944, '\"Puedes salir cuando quieras, pero nunca podrás dejarnos\"\nDon Henley (1947), músico rock estadounidense', '(El 8 de diciembre de 1976, \"The Eagles\" publican el álbum \"Hotel California\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1945, '\"La ópera es el sitio en el que cuando se apuñala\na alguien por la espalda, en lugar de morirse, canta.\"\nRobert Charles Benchley (1889-1945) humorista estadounidense', '(El 7 de diciembre de 1732, abre \"The Royal Opera House\" en Londres)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1946, '\"Todos tienen derecho a la vida y a la integridad física y moral\"\nArticulo 15 de la Constitución Española', '(El 6 de diciembre de 1978 se aprobó la Constitución Española)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1947, '\"Si puedes soñarlo, puedes hacerlo\"\nWalter Disney (1901-1966), productor estadounidense', '(El 5 de diciembre de 1901 nació Walt Disney)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1948, '\"El arte es hacer algo de la nada y venderlo\"\nFrank Zappa (1940-1993), músico estadounidense', '(El 4 de diciembre de 1993 murió Frank Zappa)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1949, '\"Todos los seres humanos hechos a base de bien y mal\"\nRobert Louis Stevenson (1850-1894), escritor británico', '(El 3 de diciembre de 1894, murió Robert L. Stevenson)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1950, '\"Ya es suficientemente malo que la gente muera de SIDA,\ncomo para que nadie muera de ignorancia\"\nElizabeth \"Liz\" Taylor (1932), actriz británica', '(Hoy es el día mundial contra el SIDA 01/12/2006)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1951, '\"Los niños son el recurso más importante del mundo y la mejor esperanza para el futuro\"\nJohn Fitzgerald Kennedy (1917-1963), presidente estadounidense', '(El 11 de diciembre de 1946 se creó UNICEF)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1952, '\"La mejor venganza es un gran éxito\"\nFrank Sinatra, (1915-1998), cantante estadounidense', '(El 12 de diciembre de 1915, nació Frank Sinatra)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1953, '\"No lo consideres cierto solamente porque está escrito en un libro.\"\nMaimónides (1135-1204), rabino y filósofo español', '(El 13 de diciembre de 1204 murió Maimónides)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1954, '\"La pintura es poesía que se ve más que se siente,\nla poesía es pintura que se siente más que se ve.\"\nLeonardo da Vinci (1452-1519), artista italiano.', '(El 14 de diciembre de 1984 murió Vicente Aleixandre)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1955, '\"Los libros tenían repetición de las mejores jugadas\nmucho antes que los deportes en televisión\"\nBern Williams (1929), programador televisivo estadounidense', '(El 15 de diciembre de 1891, James Naismith presentó la primera versión del baloncesto)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1956, '\"La música expresa aquello que no puede decirse\ncon palabras pero no puede permanecer en silencio\"\nVictor Hugo (1802-1885), escritor francés', '(El 16 de diciembre de 1893, se estrenó la \"Sinfonía del nuevo mundo\" de Antonin Dvorák)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1957, '\"La respuesta a los problemas de la vida no está\nen el fondo de una botella, ¡está en la televisión!\"\nHomer Simpson (1955), trabajador de una central nuclear estadounidense', '(El 17 de diciembre de 1989, primer episodio de \"Los Simpson\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1958, '\"Debemos mantener viva la esperanza y luchar por hacerlo mejor\"\nKofi Atta Annan (1938), dimplomático ghanés\n(El 23 de diciembre de 1972, rescatados, dos meses tras el accidente,', 'los supervivientes del vuelo 571 de las fuerzas aéreas uruguayas)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1959, '\"por muchos ropajes que aquella sublevación adoptase no dejaría de ser otra cosa que la alianza tradicional entre curas y militares que luego acabarían creando un Estado al que llamarían Reino, que se empeño siempre en tenerse por un \"Estado de Derecho\", cristiano y tradicional, no siendo mas que una dictadura que negó siempre todos los derechos fundamentales\"\nManuel Azaña -presidente del Gobierno y de la República\n\"La primera tarea de la educación es agitar la vida, pero dejarla libre para que se desarrolle.\"\nMaria Montessori (1870–1952) educadora italiana', '(El 6 de enero de 1907, Montessori abre su primera escuela)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1960, '\"Cuando la televisión es buena, nada es mejor. Cuando es mala, nada es peor.\"\nNewton Norman Minow (1926), abogado estadounidense', '(El 30 de diciembre de 1953, se vendió el primer televisor en color)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1961, '\"Cristobal Colón fue, como todo el mundo sabe, la última persona en descubrir América\"\nJames Joyce (1882-1941), escritor irlandés', '(El 13 de enero de 1941 murió James Joyce)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1962, '\"El béisbol es como la iglesia. Muchos van pero pocos entienden\"\nWesley \"Wes\" Westrum (1922-2002) \"catcher\" estadounidense', '(El 20 de enero de 1892, primer partido oficial de béisbol)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1963, '\"Puedes tener el universo, mientras yo tenga a Italia\"\nGiuseppe Verdi (1813-1901), compositor italiano', '(El 27 de enero de 1901, murió Giuseppe Verdi)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1964, '\"El rock and roll se usaba para dar patadas, hoy se usa la política\"\nBilly Joel (1949), músico estadounidense\n(El 3 de febrero de 1959, murieron los músicos de rock', 'Buddy Holly, Ritchie Valens and \"The Big Bopper\")');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1965, '\"Para ser realmente grande, hay que estar con la gente, no por encima de ella\"\nCharles de Secondat, barón de Montesquieu (1689-1755), pensador político francés', '(El 10 de febrero de 1755, murió Charles de Montesquieu)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1966, '\"Cuando un dedo apunta a la luna, el imbécil mira al dedo\"\nProverbio Chino', '(Hoy, 3 de marzo de 2007, a las 23:20 UTC habrá un eclipse lunar)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1967, '\"Todos los ordenadores esperan a la misma velocidad\".\nAnónimo.', '(El 24 de febrero de 1955, nació Steve Jobs, estadounidense pionero de la informática).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1968, '\"Inteligencia es lo que usas cuando no sabes qué hacer\"\nJean Piaget (1896–1980) filósofo y psicólogo suizo\n(El 17 de febrero de 1996, Garry Kasparov ganó al supercomputador', '\"Deep Blue\" al ajedrez)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1969, '\"La gente usa el teléfono porque odian estar cerca pero temen estar solos\"\nChuck Palahniuk (1961), periodista estadounidense', '(El 10 de marzo de 1876, Graham Bell hizo la primera llamada telefónica)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1970, '\"Puedes matar a cientos, puedes acabar con una vida, no puedes matar una idea\"\nShimon Peres (1923), político Israelí', '(El 24 de marzo de 1980, el arzobispo Óscar Romero fue asesinado)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1971, '\"Toda una vida entrenando para solo diez segundos\"\nJames Cleveland \"Jesse\" Owens (1913–1980), atleta estadounidense', '(El 31 de marzo de 1980, murio Jesse Owens)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1972, '\"¿No sería bueno que nuestras vidas fueran como un vídeo,\ny pudiéramos avanzar rápido en los malos momentos?\"\nCharlie Brown, personaje de ficción de\nCharles Schulz (1922-2000), dibujante estadounidense\n(El 14 de abril de 1956 se hizo la primera', 'demostración de una cinta de vídeo)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1973, '\"Siempre estoy volviendo, pero nadie me dice de dónde\"\nEleanora Fagan \"Billie Holiday\" (1915-1959), cantante estadounidense', '(El 7 de abril de 1915, nació Billie Holiday)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1974, '\"La vida es como la música, debe componerse con el oído,\nel sentimiento y el instinto, no mediante reglas\"\nSamuel Butler (1835-1902), novelista británico', '(El 28 de abril de 2003, abre la tienda de música iTunes)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1975, '\"Votar es simplemente determinar qué lado es más fuerte\nsin tener que ponerlos a prueba peleándose.\"\nHenry Louis Mencken (1880-1956), periodista estadounidense', '(El 21 de abril de 1944, las mujeres en Francia consiguieron el derecho al voto)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1976, '\"El progreso social puede ser medido por la posición social del sexo femenino\"\nKarl Heinrich Marx (1818–1883), filósofo alemán', '(El 5 de mayo de 1818, nació Karl Marx)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1977, '\"La vida es dura. Después de todo, te mata.\"\nKatharine Houghton Hepburn (1907–2003), actriz estadounidense', '(El 12 de mayo de 1907, nació Katharine Hepburn)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1978, '\"Cuanto menos aporta un político, más ama a la bandera\"\nFrank McKinney \"Kin\" Hubbard (1868-1930), escritor estadounidense', '(El 26 de mayo de 1986, la Unión Europea adoptó su bandera)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1979, '\"Yo voy simplemente donde me lleva la guitarra\"\nAngus McKinnon Young (1955), guitarrista y compositor británico', '(El 9 de junio de 1915, nació Les Paul, guitarrista estadounidense)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1980, '\"El orden social a cambio de libertad es un mal trato\"\nDonatien Alphonse François, Marqués de Sade (1740–1814), escritor francés', '(El 2 de junio de 1740, nació el Marqués de Sade)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1981, '\"En algún sitio algo increíble espera ser descubierto\".\nCarl Sagan, astrónomo estadounidense.', '(El 16 de junio de 1983 se lanza al espacio el primer cohete Ariane).');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1982, '\"La mayor parte de la escritura se hace lejos de la máquina de escribir\"\nHenry Miller (1891-1980), escritor estadounidense', '(El 23 de junio de 1868, se patentó la máquina de escribir)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1983, '\"A Dios pongo por testigo que jamás volveré a pasar hambre.\"\nScarlett O\'Hara, personaje de \"Lo que el viento se llevó\", por\nMargaret Mitchell (1900-1949), escritora estadounidense', '(El 30 de junio de 1936, \"Lo que el viento se llevó\" fue publicado)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1984, '\"Podemos adquirir la libertad, pero nunca se recupera una vez que se pierde.\"\nJean-Jaques Rosseau (1712-1778), filósofo suizo', '(El 14 de julio de 1789 el pueblo de París toma la Bastilla)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1985, '\"Sí, hay dos caminos por los que puedes pasar, pero en el largo,\ntodavía hay tiempo para cambiar de carretera\"\nExtracto de \"Stairway to heaven\", de Led Zeppelin, 1971', '(El 7 de julio de 1980, Led Zeppelin ofreció su último concierto)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1986, '\"No escribo sobre mis experiencias, sino desde fuera de ellas\"\nJohn Ashbery, Poeta estadounidense', '(El 28 de julio de 1927, nació John Ashbery)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1987, '\"La mejor parte de la belleza es aquella que una imagen no puede expresar\"\nFrancis Bacon (1561-1626), filósofo británico', '(El 11 de agosto de 2006, expiró la última patente del formato GIF)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1988, '\"Creo que trabajaré toda mi vida. Cuando te diviertes, ¿por qué dejar de divertirse?\"\nHelen Thomas (1920) periodista estadounidense', '(El 4 de agosto de 1920, nació Helen Thomas)');
REPLACE INTO `quotes` (`id`, `phrase`, `author`) VALUES (1989, '\"Detrás de cada fortuna hay un crimen\"\r\nHonoré de Balzac (1799-1850) escritor francés.', 'El 18 de agosto de 1850 muere Honoré de Balzac');
